Modules.Fling = {
	State = {
		IsFlinging = false,
		OldPos = nil,
		WelcomeDone = false,
		FPDH = workspace.FallenPartsDestroyHeight,
	},
	Config = {
		Whitelist = { 20460194 },
		FlingWaitTime = 2,
		Power = 9e7,
	},
	Services = {
		Players = game:GetService("Players"),
		RunService = game:GetService("RunService"),
		StarterGui = game:GetService("StarterGui"),
	},
}
function Modules.Fling:Notify(title, text, duration)
	self.Services.StarterGui:SetCore("SendNotification", {
		Title = title,
		Text = text,
		Duration = duration or 5,
	})
end
function Modules.Fling:GetTarget(Name)
	local Players = self.Services.Players
	local LocalPlayer = Players.LocalPlayer
	Name = Name:lower()
	if Name == "all" or Name == "others" then
		local targets = {}
		for _, p in ipairs(Players:GetPlayers()) do
			if p ~= LocalPlayer then
				table.insert(targets, p)
			end
		end
		return targets
	elseif Name == "random" then
		local pList = Players:GetPlayers()
		table.remove(pList, table.find(pList, LocalPlayer))
		return { pList[math.random(#pList)] }
	else
		for _, p in ipairs(Players:GetPlayers()) do
			if p ~= LocalPlayer and (p.Name:lower():find(Name) or p.DisplayName:lower():find(Name)) then
				return { p }
			end
		end
	end
	return nil
end
function Modules.Fling:SkidFling(TargetPlayer)
	local Player = self.Services.Players.LocalPlayer
	local Character = Player.Character
	local Humanoid = Character and Character:FindFirstChildOfClass("Humanoid")
	local RootPart = Humanoid and Humanoid.RootPart
	local TCharacter = TargetPlayer.Character
	if not TCharacter or not TCharacter:FindFirstChildOfClass("Humanoid") then
		return
	end
	local THumanoid = TCharacter:FindFirstChildOfClass("Humanoid")
	local TRootPart = THumanoid.RootPart
	local THead = TCharacter:FindFirstChild("Head")
	if Character and Humanoid and RootPart then
		if RootPart.Velocity.Magnitude < 50 then
			self.State.OldPos = RootPart.CFrame
		end
		workspace.CurrentCamera.CameraSubject = THead or TRootPart or THumanoid
		local function FPos(BasePart, Pos, Ang)
			RootPart.CFrame = CFrame.new(BasePart.Position) * Pos * Ang
			Character:SetPrimaryPartCFrame(CFrame.new(BasePart.Position) * Pos * Ang)
			RootPart.Velocity = Vector3.new(self.Config.Power, self.Config.Power * 10, self.Config.Power)
			RootPart.RotVelocity = Vector3.new(self.Config.Power * 10, self.Config.Power * 10, self.Config.Power * 10)
		end
		local function SFBasePart(BasePart)
			local Time = tick()
			local Angle = 0
			repeat
				if RootPart and THumanoid then
					Angle = Angle + 100
					FPos(
						BasePart,
						CFrame.new(0, 1.5, 0) + THumanoid.MoveDirection * BasePart.Velocity.Magnitude / 1.25,
						CFrame.Angles(math.rad(Angle), 0, 0)
					)
					task.wait()
				else
					break
				end
			until BasePart.Velocity.Magnitude > 500 or tick() > Time + self.Config.FlingWaitTime
		end
		workspace.FallenPartsDestroyHeight = 0 / 0
		Humanoid:SetStateEnabled(Enum.HumanoidStateType.Seated, false)
		if TRootPart then
			SFBasePart(TRootPart)
		elseif THead then
			SFBasePart(THead)
		end
		Humanoid:SetStateEnabled(Enum.HumanoidStateType.Seated, true)
		workspace.CurrentCamera.CameraSubject = Humanoid
		repeat
			RootPart.CFrame = self.State.OldPos * CFrame.new(0, 0.5, 0)
			Character:SetPrimaryPartCFrame(self.State.OldPos * CFrame.new(0, 0.5, 0))
			Humanoid:ChangeState("GettingUp")
			for _, v in ipairs(Character:GetChildren()) do
				if v:IsA("BasePart") then
					v.Velocity, v.RotVelocity = Vector3.new(), Vector3.new()
				end
			end
			task.wait()
		until (RootPart.Position - self.State.OldPos.p).Magnitude < 10
		workspace.FallenPartsDestroyHeight = self.State.FPDH
	end
end
function Modules.Fling:Initialize()
	local module = self
	if not self.State.WelcomeDone then
		self:Notify("Flinger", "Working", 1)
		self.State.WelcomeDone = true
	end
	RegisterCommand({
		Name = "fling",
		Aliases = { "ff" },
		Description = "Flings a target player using physics manipulation.",
	}, function(args)
		local targetName = args[1] or ""
		local targets = module:GetTarget(targetName)
		if targets then
			for _, p in ipairs(targets) do
				if table.find(module.Config.Whitelist, p.UserId) then
					module:Notify("Error", p.Name .. " is whitelisted.", 5)
				else
					module:SkidFling(p)
				end
			end
		else
			module:Notify("Error", "Target not found.", 5)
		end
	end)
end
Modules.FlingProtection = {
	State = {
		IsEnabled = false,
		SteppedConnection = nil,
		PlayerConnections = {},
	},
	Config = {
		MAX_VELOCITY_MAGNITUDE = 200,
		LOCAL_PLAYER_GROUP = "LocalPlayerCollisionGroup",
		OTHER_PLAYERS_GROUP = "OtherPlayersCollisionGroup",
	},
}
function Modules.FlingProtection:_setCollisionGroupForCharacter(character, groupName)
	if not character then
		return
	end
	for _, part in ipairs(character:GetDescendants()) do
		if part:IsA("BasePart") then
			pcall(function()
				part.CollisionGroup = groupName
			end)
		end
	end
end
function Modules.FlingProtection:_setupPlayerCollisions()
	local PhysicsService = game:GetService("PhysicsService")
	pcall(function()
		PhysicsService:CreateCollisionGroup(self.Config.LOCAL_PLAYER_GROUP)
	end)
	pcall(function()
		PhysicsService:CreateCollisionGroup(self.Config.OTHER_PLAYERS_GROUP)
	end)
	PhysicsService:CollisionGroupSetCollidable(self.Config.LOCAL_PLAYER_GROUP, self.Config.OTHER_PLAYERS_GROUP, false)
	for _, player in ipairs(Players:GetPlayers()) do
		local group = (player == LocalPlayer) and self.Config.LOCAL_PLAYER_GROUP or self.Config.OTHER_PLAYERS_GROUP
		if player.Character then
			self:_setCollisionGroupForCharacter(player.Character, group)
		end
		local conn = player.CharacterAdded:Connect(function(character)
			self:_setCollisionGroupForCharacter(character, group)
		end)
		table.insert(self.State.PlayerConnections, conn)
	end
	local conn = Players.PlayerAdded:Connect(function(player)
		local group = self.Config.OTHER_PLAYERS_GROUP
		local charConn = player.CharacterAdded:Connect(function(character)
			self:_setCollisionGroupForCharacter(character, group)
		end)
		table.insert(self.State.PlayerConnections, charConn)
	end)
	table.insert(self.State.PlayerConnections, conn)
end
function Modules.FlingProtection:_revertPlayerCollisions()
	for _, conn in ipairs(self.State.PlayerConnections) do
		conn:Disconnect()
	end
	self.State.PlayerConnections = {}
	for _, player in ipairs(Players:GetPlayers()) do
		if player.Character then
			self:_setCollisionGroupForCharacter(player.Character, "Default")
		end
	end
end
function Modules.FlingProtection:_enforceStability()
	local hrp = LocalPlayer.Character and LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
	if not (hrp and not hrp.Anchored) then
		return
	end
	if hrp.AssemblyLinearVelocity.Magnitude > self.Config.MAX_VELOCITY_MAGNITUDE then
		hrp.AssemblyLinearVelocity = Vector3.zero
	end
end
function Modules.FlingProtection:Toggle()
	self.State.IsEnabled = not self.State.IsEnabled
	if self.State.IsEnabled then
		DoNotif("Fling & Player Collision Protection: ENABLED", 2)
		self:_setupPlayerCollisions()
		self.State.SteppedConnection = RunService.Stepped:Connect(function()
			self:_enforceStability()
		end)
	else
		DoNotif("Fling & Player Collision Protection: DISABLED", 2)
		self:_revertPlayerCollisions()
		if self.State.SteppedConnection then
			self.State.SteppedConnection:Disconnect()
			self.State.SteppedConnection = nil
		end
	end
end
do
	local ATTR_OG_SIZE = "Zuka_OriginalSize"
	local SEL_BOX_NAME = "Zuka_ReachSelectionBox"
	local TweenService = game:GetService("TweenService")
	local UserInputService = game:GetService("UserInputService")
	local activeTool: Tool? = nil
	local modifiedPart: BasePart? = nil
	local persistentToolName: string? = nil
	local persistentPartName: string? = nil
	local currentReachSize: number = 20
	local currentReachType: string = "directional"
	local function tween(obj, props, t, style, dir)
		style = style or Enum.EasingStyle.Quad
		dir = dir or Enum.EasingDirection.Out
		TweenService:Create(obj, TweenInfo.new(t or 0.15, style, dir), props):Play()
	end
	local function applyPart(part: BasePart, size: number?, reachType: string?)
		if not part or not part.Parent then
			return
		end
		if not size then
			local og = part:GetAttribute(ATTR_OG_SIZE)
			if og then
				part.Size = og
				part:SetAttribute(ATTR_OG_SIZE, nil)
			end
			local sb = part:FindFirstChild(SEL_BOX_NAME)
			if sb then
				sb:Destroy()
			end
			return
		end
		if not part:GetAttribute(ATTR_OG_SIZE) then
			part:SetAttribute(ATTR_OG_SIZE, part.Size)
		end
		local sb = part:FindFirstChild(SEL_BOX_NAME)
		if not sb then
			sb = Instance.new("SelectionBox")
			sb.Name = SEL_BOX_NAME
			sb.Adornee = part
			sb.LineThickness = 0.025
			sb.Parent = part
		end
		sb.Color3 = reachType == "box" and Color3.fromRGB(30, 140, 255) or Color3.fromRGB(255, 60, 60)
		if reachType == "box" then
			part.Size = Vector3.one * size
		else
			part.Size = Vector3.new(part.Size.X, part.Size.Y, size)
		end
		part.Massless = true
	end
	local function resetReach()
		if modifiedPart then
			applyPart(modifiedPart, nil, nil)
			modifiedPart = nil
		end
		persistentToolName, persistentPartName = nil, nil
	end
	local function makeConnManager()
		local m = { _c = {} }
		function m:add(key, conn)
			if self._c[key] then
				self._c[key]:Disconnect()
			end
			self._c[key] = conn
		end
		function m:disconnect(key)
			if self._c[key] then
				self._c[key]:Disconnect()
				self._c[key] = nil
			end
		end
		function m:clean()
			for _, c in pairs(self._c) do
				c:Disconnect()
			end
			table.clear(self._c)
		end
		return m
	end
	Modules.ReachController = {
		State = {
			IsEnabled = false,
			UI = nil,
		},
	}
	function Modules.ReachController:Enable()
		if self.State.IsEnabled then
			return
		end
		self.State.IsEnabled = true
		local conns = makeConnManager()
		self._conns = conns
		local ui = Instance.new("ScreenGui")
		ui.Name = "ReachController_Zuka"
		ui.ZIndexBehavior = Enum.ZIndexBehavior.Global
		ui.ResetOnSpawn = false
		self.State.UI = ui
		local W, H_FULL, H_MIN = 260, 340, 32
		local isCollapsed = false
		local frame = Instance.new("Frame", ui)
		frame.Size = UDim2.fromOffset(W, H_FULL)
		frame.Position = UDim2.fromScale(0, 0)
		frame.BackgroundColor3 = Color3.fromRGB(12, 12, 18)
		frame.BorderSizePixel = 0
		frame.ClipsDescendants = true
		Instance.new("UICorner", frame).CornerRadius = UDim.new(0, 8)
		local outerStroke = Instance.new("UIStroke", frame)
		outerStroke.Color = Color3.fromRGB(55, 55, 75)
		outerStroke.Thickness = 1
		local accent = Instance.new("Frame", frame)
		accent.Size = UDim2.new(1, 0, 0, 2)
		accent.BackgroundColor3 = Color3.fromRGB(60, 160, 255)
		accent.BorderSizePixel = 0
		local titleBar = Instance.new("Frame", frame)
		titleBar.Size = UDim2.new(1, 0, 0, H_MIN)
		titleBar.BackgroundColor3 = Color3.fromRGB(18, 18, 28)
		titleBar.BorderSizePixel = 0
		local titleLabel = Instance.new("TextLabel", titleBar)
		titleLabel.Size = UDim2.new(1, -40, 1, 0)
		titleLabel.Position = UDim2.fromOffset(10, 0)
		titleLabel.BackgroundTransparency = 1
		titleLabel.Font = Enum.Font.GothamBold
		titleLabel.Text = "REACH CONTROLLER"
		titleLabel.TextColor3 = Color3.fromRGB(180, 210, 255)
		titleLabel.TextSize = 11
		titleLabel.TextXAlignment = Enum.TextXAlignment.Left
		local collapseBtn = Instance.new("TextButton", titleBar)
		collapseBtn.Size = UDim2.fromOffset(22, 22)
		collapseBtn.Position = UDim2.new(1, -27, 0.5, 0)
		collapseBtn.AnchorPoint = Vector2.new(1, 0.5)
		collapseBtn.BackgroundColor3 = Color3.fromRGB(35, 35, 50)
		collapseBtn.Text = "—"
		collapseBtn.Font = Enum.Font.GothamBold
		collapseBtn.TextColor3 = Color3.fromRGB(160, 180, 255)
		collapseBtn.TextSize = 12
		Instance.new("UICorner", collapseBtn).CornerRadius = UDim.new(0, 4)
		local sep = Instance.new("Frame", frame)
		sep.Size = UDim2.new(1, -20, 0, 1)
		sep.Position = UDim2.fromOffset(10, H_MIN)
		sep.BackgroundColor3 = Color3.fromRGB(40, 40, 58)
		sep.BorderSizePixel = 0
		local content = Instance.new("Frame", frame)
		content.Name = "Content"
		content.Size = UDim2.new(1, 0, 1, -H_MIN - 1)
		content.Position = UDim2.fromOffset(0, H_MIN + 1)
		content.BackgroundTransparency = 1
		local PAD = 10
		local y = PAD
		local function sectionLabel(text, yOff)
			local lbl = Instance.new("TextLabel", content)
			lbl.Size = UDim2.new(1, -PAD * 2, 0, 16)
			lbl.Position = UDim2.fromOffset(PAD, yOff)
			lbl.BackgroundTransparency = 1
			lbl.Font = Enum.Font.GothamSemibold
			lbl.Text = text
			lbl.TextColor3 = Color3.fromRGB(110, 130, 170)
			lbl.TextSize = 10
			lbl.TextXAlignment = Enum.TextXAlignment.Left
			return lbl
		end
		local function makeBtn(parent, text, xOff, yOff, w, h, bgColor)
			local btn = Instance.new("TextButton", parent)
			btn.Size = UDim2.fromOffset(w, h)
			btn.Position = UDim2.fromOffset(xOff, yOff)
			btn.BackgroundColor3 = bgColor or Color3.fromRGB(40, 40, 58)
			btn.Font = Enum.Font.GothamSemibold
			btn.Text = text
			btn.TextColor3 = Color3.fromRGB(210, 220, 240)
			btn.TextSize = 12
			btn.BorderSizePixel = 0
			Instance.new("UICorner", btn).CornerRadius = UDim.new(0, 5)
			btn.MouseEnter:Connect(function()
				tween(btn, { BackgroundTransparency = 0.25 }, 0.1)
			end)
			btn.MouseLeave:Connect(function()
				tween(btn, { BackgroundTransparency = 0 }, 0.1)
			end)
			return btn
		end
		sectionLabel("REACH SIZE", y)
		y += 18
		local sizeBox = Instance.new("TextBox", content)
		sizeBox.Size = UDim2.new(1, -PAD * 2, 0, 30)
		sizeBox.Position = UDim2.fromOffset(PAD, y)
		sizeBox.BackgroundColor3 = Color3.fromRGB(22, 22, 34)
		sizeBox.Font = Enum.Font.Code
		sizeBox.Text = tostring(currentReachSize)
		sizeBox.TextColor3 = Color3.fromRGB(100, 210, 255)
		sizeBox.TextSize = 14
		sizeBox.BorderSizePixel = 0
		Instance.new("UICorner", sizeBox).CornerRadius = UDim.new(0, 5)
		local sizeStroke = Instance.new("UIStroke", sizeBox)
		sizeStroke.Color = Color3.fromRGB(50, 50, 72)
		local sizePad = Instance.new("UIPadding", sizeBox)
		sizePad.PaddingLeft = UDim.new(0, 8)
		y += 34
		sectionLabel("REACH TYPE", y)
		y += 18
		local BW = (W - PAD * 2 - 6) / 2
		local dirBtn = makeBtn(content, "Directional", PAD, y, BW, 28)
		local boxBtn = makeBtn(content, "Box", PAD + BW + 6, y, BW, 28)
		local function syncTypeButtons()
			if currentReachType == "directional" then
				dirBtn.BackgroundColor3 = Color3.fromRGB(40, 100, 200)
				dirBtn.TextColor3 = Color3.fromRGB(220, 235, 255)
				boxBtn.BackgroundColor3 = Color3.fromRGB(30, 30, 45)
				boxBtn.TextColor3 = Color3.fromRGB(130, 140, 160)
			else
				boxBtn.BackgroundColor3 = Color3.fromRGB(40, 100, 200)
				boxBtn.TextColor3 = Color3.fromRGB(220, 235, 255)
				dirBtn.BackgroundColor3 = Color3.fromRGB(30, 30, 45)
				dirBtn.TextColor3 = Color3.fromRGB(130, 140, 160)
			end
		end
		syncTypeButtons()
		y += 32
		local activeLabel = Instance.new("TextLabel", content)
		activeLabel.Size = UDim2.new(1, -PAD * 2, 0, 18)
		activeLabel.Position = UDim2.fromOffset(PAD, y)
		activeLabel.BackgroundTransparency = 1
		activeLabel.Font = Enum.Font.Gotham
		activeLabel.Text = "Active Part: none"
		activeLabel.TextColor3 = Color3.fromRGB(80, 90, 110)
		activeLabel.TextSize = 10
		activeLabel.TextXAlignment = Enum.TextXAlignment.Left
		activeLabel.TextTruncate = Enum.TextTruncate.AtEnd
		y += 22
		local function setActiveLabel(partName: string?)
			if partName then
				activeLabel.Text = "Active: " .. partName
				activeLabel.TextColor3 = Color3.fromRGB(80, 220, 120)
			else
				activeLabel.Text = "Active Part: none"
				activeLabel.TextColor3 = Color3.fromRGB(80, 90, 110)
			end
		end
		sectionLabel("TOOL PARTS", y)
		y += 18
		local listH = H_FULL - H_MIN - 1 - y - 44
		local scroll = Instance.new("ScrollingFrame", content)
		scroll.Size = UDim2.new(1, -PAD * 2, 0, listH)
		scroll.Position = UDim2.fromOffset(PAD, y)
		scroll.BackgroundColor3 = Color3.fromRGB(16, 16, 24)
		scroll.BorderSizePixel = 0
		scroll.ScrollBarThickness = 5
		scroll.ScrollBarImageColor3 = Color3.fromRGB(60, 100, 200)
		scroll.CanvasSize = UDim2.fromOffset(0, 0)
		scroll.AutomaticCanvasSize = Enum.AutomaticSize.Y
		Instance.new("UICorner", scroll).CornerRadius = UDim.new(0, 5)
		local listLayout = Instance.new("UIListLayout", scroll)
		listLayout.Padding = UDim.new(0, 4)
		listLayout.SortOrder = Enum.SortOrder.LayoutOrder
		local listPad = Instance.new("UIPadding", scroll)
		listPad.PaddingTop = UDim.new(0, 4)
		listPad.PaddingBottom = UDim.new(0, 4)
		listPad.PaddingLeft = UDim.new(0, 4)
		listPad.PaddingRight = UDim.new(0, 4)
		y += listH + 8
		local resetBtn = makeBtn(content, "↺  Reset Reach", PAD, y, W - PAD * 2, 28, Color3.fromRGB(160, 35, 35))
		resetBtn.TextColor3 = Color3.fromRGB(255, 200, 200)
		local function liveApply()
			if modifiedPart and modifiedPart.Parent then
				applyPart(modifiedPart, currentReachSize, currentReachType)
			end
		end
		local function populateParts()
			for _, child in ipairs(scroll:GetChildren()) do
				if child:IsA("TextButton") then
					child:Destroy()
				end
			end
			if not activeTool then
				return
			end
			local parts = {}
			for _, d in ipairs(activeTool:GetDescendants()) do
				if d:IsA("BasePart") then
					table.insert(parts, d)
				end
			end
			for i, part in ipairs(parts) do
				local btn = Instance.new("TextButton", scroll)
				btn.LayoutOrder = i
				btn.Size = UDim2.new(1, 0, 0, 28)
				btn.BackgroundColor3 = Color3.fromRGB(28, 28, 42)
				btn.Font = Enum.Font.Code
				btn.Text = part.Name
				btn.TextColor3 = Color3.fromRGB(190, 200, 220)
				btn.TextSize = 12
				btn.BorderSizePixel = 0
				btn.TextTruncate = Enum.TextTruncate.AtEnd
				Instance.new("UICorner", btn).CornerRadius = UDim.new(0, 4)
				local btnStroke = Instance.new("UIStroke", btn)
				btnStroke.Color = Color3.fromRGB(40, 40, 60)
				btnStroke.Thickness = 1
				local function refreshBtnHighlight()
					local isActive = modifiedPart == part
					btnStroke.Color = isActive and Color3.fromRGB(40, 100, 200) or Color3.fromRGB(40, 40, 60)
					btn.TextColor3 = isActive and Color3.fromRGB(120, 200, 255) or Color3.fromRGB(190, 200, 220)
				end
				refreshBtnHighlight()
				btn.MouseEnter:Connect(function()
					if modifiedPart ~= part then
						tween(btn, { BackgroundColor3 = Color3.fromRGB(38, 38, 56) }, 0.1)
					end
				end)
				btn.MouseLeave:Connect(function()
					if modifiedPart ~= part then
						tween(btn, { BackgroundColor3 = Color3.fromRGB(28, 28, 42) }, 0.1)
					end
				end)
				btn.MouseButton1Click:Connect(function()
					if not part or not part.Parent or not activeTool then
						warn("[ReachController] Part or tool is gone.")
						return
					end
					if modifiedPart and modifiedPart ~= part then
						applyPart(modifiedPart, nil, nil)
					end
					modifiedPart = part
					persistentToolName = activeTool.Name
					persistentPartName = part.Name
					applyPart(part, currentReachSize, currentReachType)
					setActiveLabel(part.Name)
					for _, child in ipairs(scroll:GetChildren()) do
						if child:IsA("TextButton") then
							local childPart = activeTool and activeTool:FindFirstChild(child.Text, true)
							local childIsActive = childPart == part
							child:FindFirstChildOfClass("UIStroke").Color = childIsActive
									and Color3.fromRGB(40, 100, 200)
								or Color3.fromRGB(40, 40, 60)
							child.TextColor3 = childIsActive and Color3.fromRGB(120, 200, 255)
								or Color3.fromRGB(190, 200, 220)
						end
					end
					print(string.format("[ReachController] Applied to '%s' on '%s'.", part.Name, activeTool.Name))
				end)
			end
		end
		local function onToolEquipped(tool: Tool)
			activeTool = tool
			populateParts()
			setActiveLabel(modifiedPart and modifiedPart.Name or nil)
			conns:disconnect("toolUnequipped")
			conns:add(
				"toolUnequipped",
				tool.Unequipped:Connect(function()
					activeTool = nil
					populateParts()
				end)
			)
		end
		local function onCharacterAdded(character: Model)
			conns:disconnect("charChildAdded")
			conns:disconnect("charReapply")
			if persistentToolName and persistentPartName then
				local function tryReapply(child)
					if child:IsA("Tool") and child.Name == persistentToolName then
						local part = child:WaitForChild(persistentPartName, 3)
						if part and part:IsA("BasePart") then
							modifiedPart = part
							applyPart(part, currentReachSize, currentReachType)
							setActiveLabel(part.Name)
						end
					end
				end
				local existing = character:FindFirstChild(persistentToolName)
				if existing then
					tryReapply(existing)
				end
				conns:add("charReapply", character.ChildAdded:Connect(tryReapply))
			end
			conns:add(
				"charChildAdded",
				character.ChildAdded:Connect(function(child)
					if child:IsA("Tool") then
						onToolEquipped(child)
					end
				end)
			)
			local firstTool = character:FindFirstChildOfClass("Tool")
			if firstTool then
				onToolEquipped(firstTool)
			end
		end
		sizeBox.FocusLost:Connect(function()
			local n = tonumber(sizeBox.Text)
			if n and n > 0 then
				currentReachSize = n
				liveApply()
			else
				sizeBox.Text = tostring(currentReachSize)
			end
			tween(sizeStroke, { Color = Color3.fromRGB(50, 50, 72) }, 0.1)
		end)
		sizeBox.Focused:Connect(function()
			tween(sizeStroke, { Color = Color3.fromRGB(60, 140, 255) }, 0.1)
		end)
		sizeBox:GetPropertyChangedSignal("Text"):Connect(function()
			local n = tonumber(sizeBox.Text)
			if n and n > 0 then
				currentReachSize = n
				liveApply()
			end
		end)
		dirBtn.MouseButton1Click:Connect(function()
			currentReachType = "directional"
			syncTypeButtons()
			liveApply()
		end)
		boxBtn.MouseButton1Click:Connect(function()
			currentReachType = "box"
			syncTypeButtons()
			liveApply()
		end)
		resetBtn.MouseButton1Click:Connect(function()
			resetReach()
			setActiveLabel(nil)
			for _, child in ipairs(scroll:GetChildren()) do
				if child:IsA("TextButton") then
					local s = child:FindFirstChildOfClass("UIStroke")
					if s then
						s.Color = Color3.fromRGB(40, 40, 60)
					end
					child.TextColor3 = Color3.fromRGB(190, 200, 220)
				end
			end
			print("[ReachController] Reach reset.")
		end)
		collapseBtn.MouseButton1Click:Connect(function()
			isCollapsed = not isCollapsed
			local targetH = isCollapsed and H_MIN or H_FULL
			collapseBtn.Text = isCollapsed and "+" or "—"
			content.Visible = not isCollapsed
			sep.Visible = not isCollapsed
			tween(
				frame,
				{ Size = UDim2.fromOffset(W, targetH) },
				0.2,
				Enum.EasingStyle.Quad,
				isCollapsed and Enum.EasingDirection.In or Enum.EasingDirection.Out
			)
		end)
		titleBar.InputBegan:Connect(function(input)
			if input.UserInputType ~= Enum.UserInputType.MouseButton1 then
				return
			end
			local dragStart = input.Position
			local startPos = frame.Position
			local moveConn, endConn
			moveConn = UserInputService.InputChanged:Connect(function(mi)
				if mi.UserInputType == Enum.UserInputType.MouseMovement then
					local d = mi.Position - dragStart
					frame.Position =
						UDim2.new(startPos.X.Scale, startPos.X.Offset + d.X, startPos.Y.Scale, startPos.Y.Offset + d.Y)
				end
			end)
			endConn = UserInputService.InputEnded:Connect(function(ei)
				if ei.UserInputType == Enum.UserInputType.MouseButton1 then
					moveConn:Disconnect()
					endConn:Disconnect()
				end
			end)
		end)
		if LocalPlayer.Character then
			onCharacterAdded(LocalPlayer.Character)
		end
		conns:add("charAdded", LocalPlayer.CharacterAdded:Connect(onCharacterAdded))
		frame.Size = UDim2.fromOffset(W, 0)
		ui.Parent = CoreGui
		tween(frame, { Size = UDim2.fromOffset(W, H_FULL) }, 0.25, Enum.EasingStyle.Back, Enum.EasingDirection.Out)
		DoNotif("Reach Controller: ENABLED.", 2)
	end
	function Modules.ReachController:Disable()
		if not self.State.IsEnabled then
			return
		end
		self.State.IsEnabled = false
		resetReach()
		if self._conns then
			self._conns:clean()
			self._conns = nil
		end
		if self.State.UI then
			self.State.UI:Destroy()
			self.State.UI = nil
		end
		DoNotif("Reach Controller: DISABLED.", 2)
	end
	function Modules.ReachController:Toggle()
		if self.State.IsEnabled then
			self:Disable()
		else
			self:Enable()
		end
	end
	RegisterCommand({
		Name = "reachgui",
		Aliases = { "reachcontroller" },
		Description = "Toggles the advanced tool reach controller GUI.",
	}, function()
		Modules.ReachController:Toggle()
	end)
end

Modules.Reach = {
	Connections = {},
	State = {
		IsEnabled = false,
		ActiveTool = nil,
		ModifiedPart = nil,
		PersistentToolName = nil,
		PersistentPartName = nil,
		ReachType = nil,
		ReachSize = nil,
		UI = {
			ScreenGui = nil,
			Frame = nil,
			ScrollingFrame = nil,
			CloseButton = nil,
		},
	},
}
local ATTRIBUTE_OG_SIZE = "OriginalSize"
local SELECTION_BOX_NAME = "ReachSelectionBox"
function Modules.Reach:_updatePartModification(part, newSize, reachType)
	if not part or not part.Parent then
		return
	end
	local originalSize = part:GetAttribute(ATTRIBUTE_OG_SIZE)
	if not newSize then
		if originalSize then
			part.Size = originalSize
			part:SetAttribute(ATTRIBUTE_OG_SIZE, nil)
		end
		if part:FindFirstChild(SELECTION_BOX_NAME) then
			part[SELECTION_BOX_NAME]:Destroy()
		end
		return
	end
	if not originalSize then
		part:SetAttribute(ATTRIBUTE_OG_SIZE, part.Size)
	end
	local selectionBox = part:FindFirstChild(SELECTION_BOX_NAME)
	if not selectionBox then
		selectionBox = Instance.new("SelectionBox", part)
		selectionBox.Name = SELECTION_BOX_NAME
		selectionBox.Adornee = part
		selectionBox.LineThickness = 0.02
	end
	selectionBox.Color3 = reachType == "box" and Color3.fromRGB(0, 100, 255) or Color3.fromRGB(255, 0, 0)
	if reachType == "box" then
		part.Size = Vector3.one * newSize
	else
		part.Size = Vector3.new(part.Size.X, part.Size.Y, newSize)
	end
	part.Massless = true
end
function Modules.Reach:_populatePartSelector()
	local self = Modules.Reach
	local scroll = self.State.UI.ScrollingFrame
	for _, child in ipairs(scroll:GetChildren()) do
		if child:IsA("TextButton") then
			child:Destroy()
		end
	end
	if not self.State.ActiveTool then
		return
	end
	local parts = {}
	for _, descendant in ipairs(self.State.ActiveTool:GetDescendants()) do
		if descendant:IsA("BasePart") then
			table.insert(parts, descendant)
		end
	end
	if #parts == 0 then
		DoNotif("Equipped tool has no physical parts.", 3)
		return
	end
	for _, part in ipairs(parts) do
		local btn = Instance.new("TextButton", scroll)
		btn.Size = UDim2.new(1, 0, 0, 30)
		btn.BackgroundColor3 = Color3.fromRGB(50, 50, 65)
		btn.TextColor3 = Color3.fromRGB(220, 220, 230)
		btn.Font = Enum.Font.Code
		btn.Text = part.Name
		btn.TextSize = 14
		Instance.new("UICorner", btn).CornerRadius = UDim.new(0, 4)
		btn.MouseButton1Click:Connect(function()
			if not part or not part.Parent or not self.State.ActiveTool then
				self.State.UI.ScreenGui.Enabled = false
				return DoNotif("The selected part or tool no longer exists.", 3)
			end
			self.State.PersistentToolName = self.State.ActiveTool.Name
			self.State.PersistentPartName = part.Name
			if self.State.ModifiedPart and self.State.ModifiedPart ~= part then
				self:_updatePartModification(self.State.ModifiedPart)
			end
			self.State.IsEnabled = true
			self.State.ModifiedPart = part
			self:_updatePartModification(part, self.State.ReachSize, self.State.ReachType)
			self.State.UI.ScreenGui.Enabled = false
			DoNotif("Persistently set reach for " .. part.Name .. " on " .. self.State.PersistentToolName, 3)
		end)
	end
end
function Modules.Reach:_onToolEquipped(tool)
	local self = Modules.Reach
	self.State.ActiveTool = tool
	self:_populatePartSelector()
	if self.Connections.Unequipped then
		self.Connections.Unequipped:Disconnect()
	end
	self.Connections.Unequipped = tool.Unequipped:Connect(function()
		self.State.ActiveTool = nil
		self.State.UI.ScreenGui.Enabled = false
	end)
end
function Modules.Reach:_onCharacterAdded(character)
	local self = Modules.Reach
	if self.State.PersistentToolName and self.State.PersistentPartName then
		local function reapplyModification(tool)
			if tool and tool.Name == self.State.PersistentToolName then
				local part = tool:WaitForChild(self.State.PersistentPartName, 5)
				if part then
					self:_updatePartModification(part, self.State.ReachSize, self.State.ReachType)
					self.State.ModifiedPart = part
					self.State.IsEnabled = true
				end
			end
		end
		local equippedTool = character:FindFirstChild(self.State.PersistentToolName)
		reapplyModification(equippedTool)
		character.ChildAdded:Connect(function(child)
			if child:IsA("Tool") then
				reapplyModification(child)
			end
		end)
	end
	character.ChildAdded:Connect(function(child)
		if child:IsA("Tool") then
			self:_onToolEquipped(child)
		end
	end)
	local firstEquippedTool = character:FindFirstChildOfClass("Tool")
	if firstEquippedTool then
		self:_onToolEquipped(firstEquippedTool)
	end
end
function Modules.Reach:Apply(reachType, size)
	local self = Modules.Reach
	if not self.State.ActiveTool then
		return DoNotif("You must have a tool equipped to select a part.", 3)
	end
	self.State.ReachType = reachType
	self.State.ReachSize = size
	self:_populatePartSelector()
	self.State.UI.ScreenGui.Enabled = true
end
function Modules.Reach:Reset()
	local self = Modules.Reach
	if not self.State.IsEnabled and not self.State.PersistentToolName then
		return DoNotif("Reach is not active and no part is set.", 3)
	end
	local tool
	if self.State.PersistentToolName then
		tool = LocalPlayer.Character and LocalPlayer.Character:FindFirstChild(self.State.PersistentToolName)
		if not tool then
			tool = LocalPlayer.Backpack and LocalPlayer.Backpack:FindFirstChild(self.State.PersistentToolName)
		end
	end
	if tool and self.State.PersistentPartName then
		local part = tool:FindFirstChild(self.State.PersistentPartName, true)
		if part then
			self:_updatePartModification(part)
		end
	end
	self.State.IsEnabled = false
	self.State.ModifiedPart = nil
	self.State.PersistentToolName = nil
	self.State.PersistentPartName = nil
	self.State.ReachType = nil
	self.State.ReachSize = nil
	if self.State.UI.ScreenGui then
		self.State.UI.ScreenGui.Enabled = false
	end
	DoNotif("Tool reach has been fully reset and persistence cleared.", 3)
end
