Modules.AdvancedFling = {
	State = {
		IsFlinging = false,
	},
}
local function findFlingTargets(targetName)
	local targets = {}
	local localPlayer = Players.LocalPlayer
	local lowerTargetName = targetName and targetName:lower() or "nil"
	if not targetName or lowerTargetName == "me" then
		return { localPlayer }
	end
	if lowerTargetName == "all" then
		return Players:GetPlayers()
	end
	if lowerTargetName == "others" then
		for _, p in ipairs(Players:GetPlayers()) do
			if p ~= localPlayer then
				table.insert(targets, p)
			end
		end
		return targets
	end
	if lowerTargetName == "random" then
		local allPlayers = Players:GetPlayers()
		if #allPlayers > 1 then
			local potentialTargets = {}
			for _, p in ipairs(allPlayers) do
				if p ~= localPlayer then
					table.insert(potentialTargets, p)
				end
			end
			if #potentialTargets > 0 then
				return { potentialTargets[math.random(1, #potentialTargets)] }
			end
		end
		return {}
	end
	if lowerTargetName == "nearest" then
		local nearestPlayer, minDist = nil, math.huge
		local localRoot = localPlayer.Character and localPlayer.Character.PrimaryPart
		if not localRoot then
			return {}
		end
		for _, p in ipairs(Players:GetPlayers()) do
			if p ~= localPlayer and p.Character and p.Character.PrimaryPart then
				local dist = (p.Character.PrimaryPart.Position - localRoot.Position).Magnitude
				if dist < minDist then
					minDist = dist
					nearestPlayer = p
				end
			end
		end
		if nearestPlayer then
			return { nearestPlayer }
		end
		return {}
	end
	for _, p in ipairs(Players:GetPlayers()) do
		if p.Name:lower():match("^" .. lowerTargetName) or p.DisplayName:lower():match("^" .. lowerTargetName) then
			table.insert(targets, p)
		end
	end
	return targets
end
function Modules.AdvancedFling:Execute(targetPlayer)
	if self.State.IsFlinging then
		return DoNotif("Fling already in progress.", 2)
	end
	local localCharacter = LocalPlayer.Character
	local localHumanoid = localCharacter and localCharacter:FindFirstChildOfClass("Humanoid")
	local localRootPart = localHumanoid and localHumanoid.RootPart
	if not (localRootPart and targetPlayer.Character) then
		return DoNotif("Cannot fling: A required character is missing.", 3)
	end
	self.State.IsFlinging = true
	local originalPosition = localRootPart.CFrame
	local originalCameraSubject = Workspace.CurrentCamera.CameraSubject
	local originalDestroyHeight = Workspace.FallenPartsDestroyHeight
	task.spawn(function()
		local success, err = pcall(function()
			local TCharacter = targetPlayer.Character
			local THumanoid = TCharacter and TCharacter:FindFirstChildOfClass("Humanoid")
			local TRootPart = THumanoid and THumanoid.RootPart
			local THead = TCharacter and TCharacter:FindFirstChild("Head")
			local Accessory = TCharacter and TCharacter:FindFirstChildOfClass("Accessory")
			local Handle = Accessory and Accessory:FindFirstChild("Handle")
			if not (TCharacter and THumanoid) then
				error("Target character or humanoid not found.")
			end
			if THumanoid.Sit then
				return DoNotif("Fling failed: Target is sitting.", 3)
			end
			if THead then
				Workspace.CurrentCamera.CameraSubject = THead
			elseif Handle then
				Workspace.CurrentCamera.CameraSubject = Handle
			elseif THumanoid then
				Workspace.CurrentCamera.CameraSubject = THumanoid
			end
			if not TCharacter:FindFirstChildWhichIsA("BasePart") then
				return
			end
			local function FPos(BasePart, Pos, Ang)
				localRootPart.CFrame = CFrame.new(BasePart.Position) * Pos * Ang
				localCharacter:SetPrimaryPartCFrame(CFrame.new(BasePart.Position) * Pos * Ang)
				localRootPart.Velocity = Vector3.new(9e7, 9e7 * 10, 9e7)
				localRootPart.RotVelocity = Vector3.new(9e8, 9e8, 9e8)
			end
			local function SFBasePart(BasePart)
				local TimeToWait = 2
				local Time = tick()
				local Angle = 0
				repeat
					if localRootPart and THumanoid and BasePart and BasePart.Parent then
						if BasePart.Velocity.Magnitude < 50 then
							Angle = Angle + 100
							FPos(
								BasePart,
								CFrame.new(0, 1.5, 0) + THumanoid.MoveDirection * BasePart.Velocity.Magnitude / 1.25,
								CFrame.Angles(math.rad(Angle), 0, 0)
							)
							task.wait()
							FPos(
								BasePart,
								CFrame.new(0, -1.5, 0) + THumanoid.MoveDirection * BasePart.Velocity.Magnitude / 1.25,
								CFrame.Angles(math.rad(Angle), 0, 0)
							)
							task.wait()
							FPos(
								BasePart,
								CFrame.new(2.25, 1.5, -2.25)
									+ THumanoid.MoveDirection * BasePart.Velocity.Magnitude / 1.25,
								CFrame.Angles(math.rad(Angle), 0, 0)
							)
							task.wait()
							FPos(
								BasePart,
								CFrame.new(-2.25, -1.5, 2.25)
									+ THumanoid.MoveDirection * BasePart.Velocity.Magnitude / 1.25,
								CFrame.Angles(math.rad(Angle), 0, 0)
							)
							task.wait()
						else
							FPos(BasePart, CFrame.new(0, 1.5, THumanoid.WalkSpeed), CFrame.Angles(math.rad(90), 0, 0))
							task.wait()
							FPos(BasePart, CFrame.new(0, -1.5, -THumanoid.WalkSpeed), CFrame.Angles(0, 0, 0))
							task.wait()
							FPos(
								BasePart,
								CFrame.new(0, 1.5, TRootPart.Velocity.Magnitude / 1.25),
								CFrame.Angles(math.rad(90), 0, 0)
							)
							task.wait()
							FPos(
								BasePart,
								CFrame.new(0, -1.5, -TRootPart.Velocity.Magnitude / 1.25),
								CFrame.Angles(0, 0, 0)
							)
							task.wait()
						end
					else
						break
					end
				until BasePart.Velocity.Magnitude > 500
					or not BasePart.Parent
					or BasePart.Parent ~= TCharacter
					or not targetPlayer.Parent
					or THumanoid.Sit
					or localHumanoid.Health <= 0
					or tick() > Time + TimeToWait
			end
			Workspace.FallenPartsDestroyHeight = 0 / 0
			localHumanoid:SetStateEnabled(Enum.HumanoidStateType.Seated, false)
			local primaryFlingPart
			if TRootPart and THead and (TRootPart.Position - THead.Position).Magnitude > 5 then
				primaryFlingPart = THead
			elseif TRootPart then
				primaryFlingPart = TRootPart
			elseif THead then
				primaryFlingPart = THead
			elseif Handle then
				primaryFlingPart = Handle
			else
				return DoNotif("Fling failed: Target is missing critical parts.", 3)
			end
			SFBasePart(primaryFlingPart)
		end)
		pcall(function()
			localHumanoid:SetStateEnabled(Enum.HumanoidStateType.Seated, true)
			Workspace.CurrentCamera.CameraSubject = localCharacter
			Workspace.FallenPartsDestroyHeight = originalDestroyHeight
			repeat
				if localRootPart and localRootPart.Parent then
					localRootPart.CFrame = originalPosition
					localRootPart.Velocity, localRootPart.RotVelocity = Vector3.new(), Vector3.new()
				end
				task.wait()
			until not self.State.IsFlinging
				or not localRootPart.Parent
				or (localRootPart.Position - originalPosition.Position).Magnitude < 25
		end)
		if not success then
			warn("Fling Error:", err)
			DoNotif("Fling failed. Target may have reset or left.", 3)
		else
			DoNotif("Fling sequence complete.", 2)
		end
		self.State.IsFlinging = false
	end)
end
RegisterCommand({ Name = "advfling", Aliases = { "af" }, Description = "Fling a player." }, function(args)
	local targetName = args[1]
	if not targetName then
		return DoNotif("Usage: ;fling <player|all|others|random|nearest>", 3)
	end
	local targets = findFlingTargets(targetName)
	if #targets == 0 then
		return DoNotif("No valid target found.", 3)
	end
	if #targets > 1 then
		DoNotif("Flinging multiple targets...", 2)
	else
		DoNotif("Target found: " .. targets[1].Name, 2)
	end
	for _, targetPlayer in ipairs(targets) do
		if targetPlayer ~= LocalPlayer then
			Modules.AdvancedFling:Execute(targetPlayer)
			task.wait(0.1)
		end
	end
end)
Modules.SetSpawnPoint = {
	State = {
		CustomSpawnCFrame = nil,
		CharacterAddedConnection = nil,
	},
}
function Modules.SetSpawnPoint:OnCharacterAdded(newCharacter)
	if not self.State.CustomSpawnCFrame then
		return
	end
	local rootPart = newCharacter:WaitForChild("HumanoidRootPart", 5)
	if rootPart then
		task.wait()
		rootPart.CFrame = self.State.CustomSpawnCFrame
	end
end
RegisterCommand({
	Name = "setspawnpoint",
	Aliases = { "setspawn", "ssp" },
	Description = "Sets your respawn point to your current location. Use 'clear' to reset.",
}, function(args)
	local localPlayer = Players.LocalPlayer
	local commandArg = args[1] and string.lower(args[1])
	if commandArg == "clear" or commandArg == "reset" then
		if Modules.SetSpawnPoint.State.CustomSpawnCFrame then
			Modules.SetSpawnPoint.State.CustomSpawnCFrame = nil
			print("Custom spawn point cleared. You will now use the default spawn.")
			if Modules.SetSpawnPoint.State.CharacterAddedConnection then
				Modules.SetSpawnPoint.State.CharacterAddedConnection:Disconnect()
				Modules.SetSpawnPoint.State.CharacterAddedConnection = nil
			end
		else
			print("No custom spawn point was set.")
		end
		return
	end
	local character = localPlayer and localPlayer.Character
	local rootPart = character and character:FindFirstChild("HumanoidRootPart")
	if not rootPart then
		print("Error: Could not set spawn point. Player character not found.")
		return
	end
	Modules.SetSpawnPoint.State.CustomSpawnCFrame = rootPart.CFrame
	print("Custom spawn point set at: " .. tostring(rootPart.Position))
	if not Modules.SetSpawnPoint.State.CharacterAddedConnection then
		Modules.SetSpawnPoint.State.CharacterAddedConnection = localPlayer.CharacterAdded:Connect(function(char)
			Modules.SetSpawnPoint:OnCharacterAdded(char)
		end)
	end
end)
Modules.AntiRubberband = {
	State = {
		IsEnabled = false,
		Connections = {},
		LastClientPos = nil,
	},
	Config = {
		CorrectionThreshold = 12,
		SimRadius = math.huge,
	},
}
function Modules.AntiRubberband:_assertOwnership()
	pcall(function()
		sethiddenproperty(LocalPlayer, "SimulationRadius", self.Config.SimRadius)
	end)
	LocalPlayer.ReplicationFocus = game:GetService("Workspace")
end
function Modules.AntiRubberband:Enable()
	if self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = true
	self.State.Connections.Ownership = RunService.Heartbeat:Connect(function()
		self:_assertOwnership()
	end)
	self.State.Connections.Render = RunService.RenderStepped:Connect(function()
		local char = LocalPlayer.Character
		local hrp = char and char:FindFirstChild("HumanoidRootPart")
		if not hrp then
			return
		end
		local current = hrp.CFrame
		if self.State.LastClientPos then
			local delta = (current.Position - self.State.LastClientPos.Position).Magnitude
			if delta > self.Config.CorrectionThreshold then
				pcall(function()
					hrp.CFrame = self.State.LastClientPos
					hrp.AssemblyLinearVelocity = Vector3.zero
				end)
				return
			end
		end
		self.State.LastClientPos = current
	end)
	self.State.Connections.CharAdded = LocalPlayer.CharacterAdded:Connect(function()
		self.State.LastClientPos = nil
	end)
	DoNotif("Anti-Rubberband: ENABLED", 2)
end
function Modules.AntiRubberband:Disable()
	if not self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = false
	self.State.LastClientPos = nil
	for _, conn in pairs(self.State.Connections) do
		if conn then
			conn:Disconnect()
		end
	end
	self.State.Connections = {}
	DoNotif("Anti-Rubberband: DISABLED", 2)
end
function Modules.AntiRubberband:Toggle()
	if self.State.IsEnabled then
		self:Disable()
	else
		self:Enable()
	end
end
function Modules.AntiRubberband:SetThreshold(n)
	self.Config.CorrectionThreshold = tonumber(n) or 12
	DoNotif(("Correction threshold: %d studs"):format(self.Config.CorrectionThreshold), 2)
end
function Modules.AntiRubberband:Initialize()
	local module = self
	RegisterCommand({
		Name = "antir",
		Aliases = {},
		Description = "Blocks server position corrections (rubberband) at all times.",
	}, function()
		module:Toggle()
	end)
	RegisterCommand({
		Name = "rbthreshold",
		Aliases = { "rbdist" },
		Description = "Set how many studs counts as a server correction. Default: 12",
	}, function(args)
		module:SetThreshold(args[1])
	end)
end
Modules.NetCommander = {
	State = {
		PinnedRemote = nil,
		PinnedPath = "",
		LastResult = nil,
	},
	Dependencies = { "HttpService", "ReplicatedStorage" },
}

function Modules.NetCommander:_resolvePath(path)
	if not path or path == "" then
		return nil
	end

	local aliases = {
		["^RS%."] = "ReplicatedStorage.",
		["^RSF%."] = "ReplicatedFirst.",
		["^WS%."] = "Workspace.",
		["^workspace%."] = "Workspace.",
		["^SS%."] = "ServerStorage.",
		["^SSS%."] = "ServerScriptService.",
		["^CSP%."] = "CoreGui.",
		["^SG%."] = "StarterGui.",
		["^SP%."] = "StarterPack.",
		["^SC%."] = "StarterCharacterScripts.",
		["^SPS%."] = "StarterPlayerScripts.",
		["^LPS%."] = "PlayerGui.",
		["^TS%."] = "TweenService.",
		["^HS%."] = "HttpService.",
		["^PS%."] = "Players.",
		["^TW%."] = "Teams.",
		["^LG%."] = "Lighting.",
		["^chat%."] = "Chat.",
		["^CHAT%."] = "Chat.",
		["^game%."] = "",
		["^Game%."] = "",
	}

	for pattern, replacement in pairs(aliases) do
		path = path:gsub(pattern, replacement)
	end

	path = path:gsub("^Workspace%.", "workspace.")

	-- game:GetService("...").Path full resolution
	local svcName, remainder = path:match("^game:GetService%(['\"](.+)['\"]%)(%.?(.*))")
	if not svcName then
		svcName, remainder = path:match("^:GetService%(['\"](.+)['\"]%)(%.?(.*))")
	end

	if svcName then
		local success, svc = pcall(game.GetService, game, svcName)
		if success and svc then
			if not remainder or remainder == "" then
				return svc
			end
			local current = svc
			for seg in remainder:gmatch("([^%.]+)") do
				if current then
					local found = current:FindFirstChild(seg)
					if not found then
						local ok, result = pcall(function()
							return current:WaitForChild(seg, 1)
						end)
						found = ok and result or nil
					end
					if not found then
						local ok, val = pcall(function()
							return current[seg]
						end)
						found = ok and val or nil
					end
					current = found
				end
			end
			return current
		end
	end
	local nilPrefixes = { "^nil%.", "^nilinstance%.", "^gc%.", "^garbage%." }
	local isNilSearch = false
	local nilSearchName = nil

	for _, prefix in ipairs(nilPrefixes) do
		if path:match(prefix) then
			nilSearchName = path:gsub(prefix, "")
			isNilSearch = true
			break
		end
	end

	if isNilSearch and nilSearchName and getnilinstances then
		local segments = {}
		for seg in nilSearchName:gmatch("([^%.]+)") do
			table.insert(segments, seg)
		end

		local rootName = segments[1]
		local found = nil

		for _, inst in ipairs(getnilinstances()) do
			if inst.Name == rootName then
				found = inst
				break
			end
		end

		if not found then
			return nil
		end

		table.remove(segments, 1)
		for _, seg in ipairs(segments) do
			if found then
				local child = found:FindFirstChild(seg)
				if not child then
					local ok, val = pcall(function()
						return found[seg]
					end)
					child = ok and val or nil
				end
				found = child
			end
		end

		return found
	end
	local knownServices = {
		"ReplicatedStorage",
		"ReplicatedFirst",
		"ServerStorage",
		"ServerScriptService",
		"StarterGui",
		"StarterPack",
		"StarterPlayer",
		"StarterCharacterScripts",
		"StarterPlayerScripts",
		"Teams",
		"Lighting",
		"Chat",
		"SoundService",
		"HttpService",
		"TweenService",
		"RunService",
		"UserInputService",
		"GuiService",
		"Players",
		"TextService",
		"MarketplaceService",
		"BadgeService",
		"TeleportService",
		"PathfindingService",
		"PhysicsService",
		"ContextActionService",
		"VirtualInputManager",
		"CoreGui",
	}

	local current = game
	local segments = {}

	for seg in path:gmatch("([^%.]+)") do
		table.insert(segments, seg)
	end

	if #segments == 0 then
		return game
	end

	local firstSeg = segments[1]
	local matchedService = false

	for _, svcName in ipairs(knownServices) do
		if firstSeg:lower() == svcName:lower() then
			local success, svc = pcall(game.GetService, game, svcName)
			if success and svc then
				current = svc
				table.remove(segments, 1)
				matchedService = true
				break
			end
		end
	end

	if not matchedService then
		if firstSeg:lower() == "workspace" then
			current = workspace
			table.remove(segments, 1)
		elseif firstSeg:lower() == "playergui" then
			local lp = game:GetService("Players").LocalPlayer
			if lp then
				current = lp:FindFirstChild("PlayerGui") or lp
				table.remove(segments, 1)
			end
		elseif firstSeg:lower() == "localplayer" or firstSeg:lower() == "lp" then
			local lp = game:GetService("Players").LocalPlayer
			if lp then
				current = lp
				table.remove(segments, 1)
			end
		elseif firstSeg:lower() == "character" or firstSeg:lower() == "char" then
			local lp = game:GetService("Players").LocalPlayer
			if lp and lp.Character then
				current = lp.Character
				table.remove(segments, 1)
			end
		end
	end

	-- Traverse remaining segments
	for _, segment in ipairs(segments) do
		if current then
			local found = current:FindFirstChild(segment)
			if not found then
				local success, result = pcall(function()
					return current:WaitForChild(segment, 1)
				end)
				found = success and result or nil
			end
			if not found then
				local ok, val = pcall(function()
					return current[segment]
				end)
				found = ok and val or nil
			end
			current = found
		end
	end

	return current
end

function Modules.NetCommander:_parseArgs(argsTable)
	local processed = {}
	for _, arg in ipairs(argsTable) do
		local lower = arg:lower()
		if tonumber(arg) then
			table.insert(processed, tonumber(arg))
		elseif lower == "true" then
			table.insert(processed, true)
		elseif lower == "false" then
			table.insert(processed, false)
		elseif lower == "nil" then
			table.insert(processed, nil)
		elseif arg:sub(1, 1) == "{" and arg:sub(-1, -1) == "}" then
			local success, tbl = pcall(function()
				return game:GetService("HttpService"):JSONDecode(arg)
			end)
			table.insert(processed, success and tbl or arg)
		elseif lower == "me" or lower == "localplayer" then
			table.insert(processed, game:GetService("Players").LocalPlayer)
		else
			table.insert(processed, arg)
		end
	end
	return processed
end

function Modules.NetCommander:Execute(pathArray, isInvoke)
	local target = nil
	local remainingArgs = {}
	local resolvedPath = ""

	for i = 1, #pathArray do
		local testPath = table.concat(pathArray, " ", 1, i)
		local result = self:_resolvePath(testPath)
		if result then
			target = result
			resolvedPath = testPath
			remainingArgs = {}
			for j = i + 1, #pathArray do
				table.insert(remainingArgs, pathArray[j])
			end
		end
	end

	if not target then
		return DoNotif("Target not found: " .. table.concat(pathArray, " "), 3)
	end

	local cleanArgs = self:_parseArgs(remainingArgs)

	if target:IsA("RemoteEvent") then
		local success, err = pcall(function()
			target:FireServer(unpack(cleanArgs))
		end)
		if success then
			DoNotif("Fired Event: " .. target.Name, 2)
		else
			warn("--> [NET]: FireServer Error:", err)
			DoNotif("FireServer Failed. Check F9.", 3)
		end
	elseif target:IsA("RemoteFunction") then
		DoNotif("Invoking Function...", 1.5)
		task.spawn(function()
			local success, result = pcall(function()
				return target:InvokeServer(unpack(cleanArgs))
			end)
			if success then
				print("--> [NET]: Invoke Result for " .. target.Name .. ":", result)
				self.State.LastResult = result
				DoNotif("Invoke Success. Result in F9.", 3)
			else
				warn("--> [NET]: Invoke Failed:", result)
				DoNotif("Invoke FAILED.", 3)
			end
		end)
	else
		DoNotif("Error: '" .. target.Name .. "' is a " .. target.ClassName .. " (Not a Remote).", 3)
	end
end

function Modules.NetCommander:Initialize()
	local module = self
	module.Services = {
		HttpService = game:GetService("HttpService"),
		Players = game:GetService("Players"),
	}

	RegisterCommand({
		Name = "fire",
		Aliases = {},
		Description = "Fires a RemoteEvent. Handles paths with spaces.",
	}, function(args)
		if #args < 1 then
			return DoNotif("Usage: ;fire [Path] [Args]", 3)
		end
		module:Execute(args, false)
	end)

	RegisterCommand({
		Name = "invoke",
		Aliases = { "inv", "rfcall" },
		Description = "Invokes a RemoteFunction. Handles paths with spaces.",
	}, function(args)
		if #args < 1 then
			return DoNotif("Usage: ;inv [Path] [Args]", 3)
		end
		module:Execute(args, true)
	end)

	RegisterCommand({
		Name = "pinremote",
		Aliases = { "mark" },
		Description = "Pins a remote path.",
	}, function(args)
		if not args[1] then
			return DoNotif("Usage: ;pin [Path]", 3)
		end
		module.State.PinnedPath = table.concat(args, " ")
		DoNotif("Pinned: " .. module.State.PinnedPath, 2)
	end)

	RegisterCommand({
		Name = "runremote",
		Aliases = { "r" },
		Description = "Runs the pinned remote.",
	}, function(args)
		if module.State.PinnedPath == "" then
			return DoNotif("No remote pinned.", 3)
		end
		local combinedArgs = {}
		for part in string.gmatch(module.State.PinnedPath, "%S+") do
			table.insert(combinedArgs, part)
		end
		for _, arg in ipairs(args) do
			table.insert(combinedArgs, arg)
		end
		module:Execute(combinedArgs, false)
	end)

	RegisterCommand({
		Name = "listnils",
		Aliases = { "nils", "gclist" },
		Description = "Lists all nil instances, optionally filtered by name or classname.",
	}, function(args)
		if not getnilinstances then
			return DoNotif("getnilinstances() not available on this executor.", 3)
		end

		local filter = args[1] and args[1]:lower() or nil
		local count = 0

		for _, inst in ipairs(getnilinstances()) do
			local className = inst.ClassName:lower()
			if not filter or className == filter or inst.Name:lower():find(filter) then
				print(string.format("[NIL] %s (%s)", inst.Name, inst.ClassName))
				count = count + 1
			end
		end

		DoNotif("Found " .. count .. " nil instance(s). Check F9.", 3)
	end)
end
