Modules.ToSpawn = {
	State = {
		Enabled = false,
	},
}
function Modules.ToSpawn:Initialize()
	RegisterCommand({
		Name = "tospawn",
		Aliases = { "ts" },
		Description = "Teleports you to the nearest SpawnLocation.",
	}, function(args)
		local Players = game:GetService("Players")
		local Workspace = game:GetService("Workspace")
		local localPlayer = Players.LocalPlayer
		local character = localPlayer.Character
		if not character then
			return DoNotif("Character not found.", 3)
		end
		local root = character:FindFirstChild("HumanoidRootPart")
		if not root then
			return DoNotif("HumanoidRootPart not found.", 3)
		end
		local closestSpawn = nil
		local shortestDistance = math.huge
		local rootPosition = root.Position
		for _, part in ipairs(Workspace:GetDescendants()) do
			if part:IsA("SpawnLocation") then
				local distance = (part.Position - rootPosition).Magnitude
				if distance < shortestDistance then
					shortestDistance = distance
					closestSpawn = part
				end
			end
		end
		if closestSpawn then
			root.CFrame = closestSpawn.CFrame * CFrame.new(0, 3, 0)
		else
			return DoNotif("No SpawnLocation found in workspace.", 3)
		end
	end)
end
Modules.TriggerRemoteTouch = {
	State = {
		IsExecuting = false,
		FoundParts = {},
		OriginalPosition = nil,
		TeleportMode = true,
		ScanMethod = "auto",
	},
	Services = {
		Players = game:GetService("Players"),
		Workspace = game:GetService("Workspace"),
		RunService = game:GetService("RunService"),
	},
	Config = {
		ScanDelay = 0.5,
		HoldDuration = 1.5,
		TeleportOffset = Vector3.new(0, 3, 0),
		ReturnDelay = 0.3,
		UseMultipleMethods = true,
		IncludeProximityPrompts = true,
		IncludeClickDetectors = true,
		IncludeTouchTransmitters = true,
		MaxDistance = 500,
		ShowDebug = false,
		SafeTeleport = true,
	},
}
function Modules.TriggerRemoteTouch:_debugLog(msg)
	if self.Config.ShowDebug then
		print("[TouchTrigger Debug]", msg)
	end
end
function Modules.TriggerRemoteTouch:_savePosition()
	local char = self.Services.Players.LocalPlayer.Character
	local hrp = char and char:FindFirstChild("HumanoidRootPart")
	if hrp then
		self.State.OriginalPosition = hrp.CFrame
		self:_debugLog("Saved position: " .. tostring(hrp.Position))
		return true
	end
	return false
end
function Modules.TriggerRemoteTouch:_returnToOriginal()
	if not self.State.OriginalPosition then
		return false
	end
	local char = self.Services.Players.LocalPlayer.Character
	local hrp = char and char:FindFirstChild("HumanoidRootPart")
	if hrp then
		hrp.CFrame = self.State.OriginalPosition
		self:_debugLog("Returned to original position")
		return true
	end
	return false
end
function Modules.TriggerRemoteTouch:_teleportToPart(part, offset)
	local char = self.Services.Players.LocalPlayer.Character
	local hrp = char and char:FindFirstChild("HumanoidRootPart")
	if not (hrp and part) then
		return false
	end
	local targetPos = part.Position + (offset or self.Config.TeleportOffset)
	if self.Config.SafeTeleport then
		if targetPos.Y < -1000 or targetPos.Y > 10000 then
			self:_debugLog("Unsafe position detected, skipping")
			return false
		end
	end
	hrp.CFrame = CFrame.new(targetPos)
	self:_debugLog("Teleported to: " .. part:GetFullName())
	self.Services.RunService.Heartbeat:Wait()
	return true
end
function Modules.TriggerRemoteTouch:_triggerProximityPrompt(prompt, useTeleport)
	if not prompt or not prompt:IsA("ProximityPrompt") then
		return false
	end
	local part = prompt.Parent
	if useTeleport and self.State.TeleportMode then
		if not self:_teleportToPart(part) then
			return false
		end
		task.wait(0.1)
	end
	self:_debugLog("Triggering ProximityPrompt: " .. prompt:GetFullName())
	if fireproximityprompt then
		local success = pcall(function()
			if prompt.HoldDuration > 0 then
				fireproximityprompt(prompt, self.Config.HoldDuration)
			else
				fireproximityprompt(prompt)
			end
		end)
		if success then
			if prompt.HoldDuration > 0 then
				task.wait(math.max(prompt.HoldDuration, self.Config.HoldDuration))
			end
			return true
		end
	end
	if prompt.Triggered then
		pcall(function()
			for _, connection in pairs(getconnections(prompt.Triggered)) do
				if connection.Function then
					connection.Function()
				end
			end
		end)
	end
	return false
end
function Modules.TriggerRemoteTouch:_triggerClickDetector(detector, useTeleport)
	if not detector or not detector:IsA("ClickDetector") then
		return false
	end
	local part = detector.Parent
	if useTeleport and self.State.TeleportMode then
		if not self:_teleportToPart(part) then
			return false
		end
		task.wait(0.1)
	end
	self:_debugLog("Triggering ClickDetector: " .. detector:GetFullName())
	if fireclickdetector then
		pcall(function()
			fireclickdetector(detector)
		end)
		return true
	end
	return false
end
function Modules.TriggerRemoteTouch:_triggerTouchInterest(part, useTeleport)
	if not part or not part:IsA("BasePart") then
		return false
	end
	local hrp = self.Services.Players.LocalPlayer.Character
		and self.Services.Players.LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
	if not hrp then
		return false
	end
	if useTeleport and self.State.TeleportMode then
		if not self:_teleportToPart(part) then
			return false
		end
		task.wait(0.1)
	end
	self:_debugLog("Triggering Touch: " .. part:GetFullName())
	if firetouchinterest then
		local success = pcall(function()
			firetouchinterest(hrp, part, 0)
			task.wait(0.1)
			firetouchinterest(hrp, part, 1)
		end)
		if success then
			return true
		end
	end
	if part.Touched and getconnections then
		local success = pcall(function()
			for _, connection in pairs(getconnections(part.Touched)) do
				if connection.Function then
					connection.Function(hrp)
				end
			end
		end)
		if success then
			return true
		end
	end
	if not useTeleport then
		local originalCFrame = hrp.CFrame
		pcall(function()
			hrp.CFrame = part.CFrame
			self.Services.RunService.Heartbeat:Wait()
			hrp.CFrame = originalCFrame
		end)
	end
	return true
end
function Modules.TriggerRemoteTouch:_scanProximityPrompts()
	local found = {}
	for _, descendant in ipairs(self.Services.Workspace:GetDescendants()) do
		if descendant:IsA("ProximityPrompt") and descendant.Enabled then
			local part = descendant.Parent
			if part and part:IsA("BasePart") then
				local hrp = self.Services.Players.LocalPlayer.Character
					and self.Services.Players.LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
				if hrp then
					local distance = (part.Position - hrp.Position).Magnitude
					table.insert(found, {
						Type = "ProximityPrompt",
						Object = descendant,
						Part = part,
						Name = descendant:GetFullName(),
						Distance = distance,
						RequiresHold = descendant.HoldDuration > 0,
						HoldTime = descendant.HoldDuration,
					})
				end
			end
		end
	end
	return found
end
function Modules.TriggerRemoteTouch:_scanClickDetectors()
	local found = {}
	for _, descendant in ipairs(self.Services.Workspace:GetDescendants()) do
		if descendant:IsA("ClickDetector") then
			local part = descendant.Parent
			if part and part:IsA("BasePart") then
				local hrp = self.Services.Players.LocalPlayer.Character
					and self.Services.Players.LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
				if hrp then
					local distance = (part.Position - hrp.Position).Magnitude
					table.insert(found, {
						Type = "ClickDetector",
						Object = descendant,
						Part = part,
						Name = descendant:GetFullName(),
						Distance = distance,
					})
				end
			end
		end
	end
	return found
end
function Modules.TriggerRemoteTouch:_scanTouchParts()
	local found = {}
	local hrp = self.Services.Players.LocalPlayer.Character
		and self.Services.Players.LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
	if not hrp then
		return found
	end
	for _, descendant in ipairs(self.Services.Workspace:GetDescendants()) do
		if descendant:IsA("BasePart") then
			local hasTouchedEvent = false
			if getconnections then
				pcall(function()
					local connections = getconnections(descendant.Touched)
					if connections and #connections > 0 then
						hasTouchedEvent = true
					end
				end)
			end
			if not hasTouchedEvent and descendant:FindFirstChildOfClass("TouchTransmitter") then
				hasTouchedEvent = true
			end
			if hasTouchedEvent then
				local distance = (descendant.Position - hrp.Position).Magnitude
				table.insert(found, {
					Type = "TouchPart",
					Object = descendant,
					Part = descendant,
					Name = descendant:GetFullName(),
					Distance = distance,
				})
			end
		end
	end
	return found
end
function Modules.TriggerRemoteTouch:Scan()
	if self.State.IsExecuting then
		return DoNotif("Scan already in progress.", 2)
	end
	self.State.IsExecuting = true
	DoNotif("Scanning for interactive objects...", 2)
	task.spawn(function()
		table.clear(self.State.FoundParts)
		local allFound = {}
		if self.Config.IncludeProximityPrompts then
			local prompts = self:_scanProximityPrompts()
			for _, item in ipairs(prompts) do
				table.insert(allFound, item)
			end
			self:_debugLog("Found " .. #prompts .. " ProximityPrompts")
		end
		if self.Config.IncludeClickDetectors then
			local detectors = self:_scanClickDetectors()
			for _, item in ipairs(detectors) do
				table.insert(allFound, item)
			end
			self:_debugLog("Found " .. #detectors .. " ClickDetectors")
		end
		if self.Config.IncludeTouchTransmitters then
			local touchParts = self:_scanTouchParts()
			for _, item in ipairs(touchParts) do
				table.insert(allFound, item)
			end
			self:_debugLog("Found " .. #touchParts .. " Touch Parts")
		end
		table.sort(allFound, function(a, b)
			return a.Distance < b.Distance
		end)
		self.State.FoundParts = allFound
		print("=== Touch Scan Results ===")
		print(string.format("Total Found: %d objects", #allFound))
		local typeCount = {}
		for _, item in ipairs(allFound) do
			typeCount[item.Type] = (typeCount[item.Type] or 0) + 1
		end
		for objType, count in pairs(typeCount) do
			print(string.format("  • %s: %d", objType, count))
		end
		if #allFound > 0 then
			print("\nClosest 5:")
			for i = 1, math.min(5, #allFound) do
				local item = allFound[i]
				local holdInfo = item.RequiresHold and string.format(" [HOLD %.1fs]", item.HoldTime) or ""
				print(string.format("  [%d] %s (%.1fm)%s - %s", i, item.Type, item.Distance, holdInfo, item.Name))
			end
		end
		print("==========================")
		DoNotif(string.format("Scan complete: %d objects found", #allFound), 3)
		self.State.IsExecuting = false
	end)
end
function Modules.TriggerRemoteTouch:TriggerAll()
	if self.State.IsExecuting then
		return DoNotif("Operation already in progress.", 2)
	end
	if #self.State.FoundParts == 0 then
		return DoNotif("No parts found. Run ';touch scan' first.", 3)
	end
	if not self:_savePosition() then
		return DoNotif("Failed to save position.", 3)
	end
	self.State.IsExecuting = true
	DoNotif(
		string.format(
			"Triggering all %d objects... (%s mode)",
			#self.State.FoundParts,
			self.State.TeleportMode and "TELEPORT" or "REMOTE"
		),
		3
	)
	task.spawn(function()
		local triggered = 0
		local failed = 0
		for i, item in ipairs(self.State.FoundParts) do
			if not self.State.IsExecuting then
				break
			end
			local success = false
			if item.Type == "ProximityPrompt" then
				success = self:_triggerProximityPrompt(item.Object, true)
			elseif item.Type == "ClickDetector" then
				success = self:_triggerClickDetector(item.Object, true)
			elseif item.Type == "TouchPart" then
				success = self:_triggerTouchInterest(item.Part, true)
			end
			if success then
				triggered = triggered + 1
				DoNotif(string.format("[%d/%d]  %s", i, #self.State.FoundParts, item.Part.Name), 1)
			else
				failed = failed + 1
				self:_debugLog(string.format("Failed: %s", item.Name))
			end
			task.wait(self.Config.ReturnDelay)
		end
		if self.State.TeleportMode then
			task.wait(0.2)
			self:_returnToOriginal()
			DoNotif("Returned to start position", 2)
		end
		DoNotif(string.format("Complete: %d succeeded, %d failed", triggered, failed), 3)
		self.State.IsExecuting = false
	end)
end
function Modules.TriggerRemoteTouch:TriggerSingle(keyword)
	if not keyword then
		return DoNotif("Usage: ;touch single <keyword>", 3)
	end
	if #self.State.FoundParts == 0 then
		return DoNotif("No parts found. Run ';touch scan' first.", 3)
	end
	self:_savePosition()
	local lowerKeyword = keyword:lower()
	for _, item in ipairs(self.State.FoundParts) do
		if item.Name:lower():find(lowerKeyword, 1, true) then
			local success = false
			if item.Type == "ProximityPrompt" then
				success = self:_triggerProximityPrompt(item.Object, true)
			elseif item.Type == "ClickDetector" then
				success = self:_triggerClickDetector(item.Object, true)
			elseif item.Type == "TouchPart" then
				success = self:_triggerTouchInterest(item.Part, true)
			end
			if self.State.TeleportMode then
				task.wait(self.Config.ReturnDelay)
				self:_returnToOriginal()
			end
			if success then
				DoNotif(" Triggered: " .. item.Part.Name, 2)
			else
				DoNotif(" Failed: " .. item.Part.Name, 3)
			end
			return
		end
	end
	DoNotif("No match found for: " .. keyword, 3)
end
function Modules.TriggerRemoteTouch:TriggerIndex(index)
	local idx = tonumber(index)
	if not idx or idx < 1 or idx > #self.State.FoundParts then
		return DoNotif(string.format("Invalid index. Use 1-%d", #self.State.FoundParts), 3)
	end
	self:_savePosition()
	local item = self.State.FoundParts[idx]
	local success = false
	if item.Type == "ProximityPrompt" then
		success = self:_triggerProximityPrompt(item.Object, true)
	elseif item.Type == "ClickDetector" then
		success = self:_triggerClickDetector(item.Object, true)
	elseif item.Type == "TouchPart" then
		success = self:_triggerTouchInterest(item.Part, true)
	end
	if self.State.TeleportMode then
		task.wait(self.Config.ReturnDelay)
		self:_returnToOriginal()
	end
	if success then
		DoNotif(string.format("[%d]  %s", idx, item.Part.Name), 2)
	else
		DoNotif(string.format("[%d]  %s", idx, item.Part.Name), 3)
	end
end
function Modules.TriggerRemoteTouch:ToggleTeleportMode()
	self.State.TeleportMode = not self.State.TeleportMode
	DoNotif("Teleport Mode: " .. (self.State.TeleportMode and "ENABLED" or "DISABLED"), 2)
end
function Modules.TriggerRemoteTouch:Stop()
	if self.State.IsExecuting then
		self.State.IsExecuting = false
		if self.State.TeleportMode and self.State.OriginalPosition then
			self:_returnToOriginal()
		end
		DoNotif("Stopped and returned to start.", 2)
	else
		DoNotif("No operation in progress.", 2)
	end
end
function Modules.TriggerRemoteTouch:ListResults()
	if #self.State.FoundParts == 0 then
		return DoNotif("No scan results. Run ';touch scan' first.", 3)
	end
	print("=== Scan Results (First 20) ===")
	for i = 1, math.min(20, #self.State.FoundParts) do
		local item = self.State.FoundParts[i]
		local holdInfo = item.RequiresHold and string.format(" [HOLD %.1fs]", item.HoldTime) or ""
		print(string.format("[%d] %s (%.1fm)%s - %s", i, item.Type, item.Distance, holdInfo, item.Name))
	end
	if #self.State.FoundParts > 20 then
		print(string.format("... and %d more", #self.State.FoundParts - 20))
	end
	print("Mode: " .. (self.State.TeleportMode and "TELEPORT" or "REMOTE"))
	DoNotif(string.format("Listed %d results in console (F9)", math.min(20, #self.State.FoundParts)), 2)
end
function Modules.TriggerRemoteTouch:Initialize()
	local module = self
	RegisterCommand({
		Name = "touch",
		Aliases = { "trigger", "interact" },
		Description = "Scan and trigger interactive objects (teleports to each one).",
	}, function(args)
		local subCommand = args[1] and args[1]:lower()
		if subCommand == "scan" then
			module:Scan()
		elseif subCommand == "all" then
			module:TriggerAll()
		elseif subCommand == "single" or subCommand == "s" then
			module:TriggerSingle(args[2])
		elseif subCommand == "index" or subCommand == "i" then
			module:TriggerIndex(args[2])
		elseif subCommand == "stop" then
			module:Stop()
		elseif subCommand == "list" or subCommand == "l" then
			module:ListResults()
		elseif subCommand == "mode" or subCommand == "teleport" then
			module:ToggleTeleportMode()
		else
			DoNotif("Usage: ;touch <scan|all|single|index|list|stop|mode>", 4)
		end
	end)
	RegisterCommand({
		Name = "touchmode",
		Aliases = { "tpmode" },
		Description = "Toggle between teleport and remote trigger modes.",
	}, function()
		module:ToggleTeleportMode()
	end)
	RegisterCommand({
		Name = "touchdebug",
		Aliases = {},
		Description = "Toggle touch trigger debug mode.",
	}, function()
		module.Config.ShowDebug = not module.Config.ShowDebug
		DoNotif("Touch Debug: " .. (module.Config.ShowDebug and "ON" or "OFF"), 2)
	end)
	RegisterCommand({
		Name = "touchdelay",
		Aliases = {},
		Description = "Set delay between triggers (seconds).",
	}, function(args)
		local delay = tonumber(args[1])
		if not delay then
			DoNotif("Current delay: " .. module.Config.ReturnDelay .. "s", 2)
			return
		end
		module.Config.ReturnDelay = math.max(0.1, delay)
		DoNotif("Trigger delay set to: " .. module.Config.ReturnDelay .. "s", 2)
	end)
	RegisterCommand({
		Name = "touchhold",
		Aliases = {},
		Description = "Set hold duration for proximity prompts.",
	}, function(args)
		local duration = tonumber(args[1])
		if not duration then
			DoNotif("Current hold: " .. module.Config.HoldDuration .. "s", 2)
			return
		end
		module.Config.HoldDuration = math.max(0.1, duration)
		DoNotif("Hold duration set to: " .. module.Config.HoldDuration .. "s", 2)
	end)
end
local ContextActionService = game:GetService("ContextActionService")
Modules.AdvancedAirwalk = {
	State = {
		IsEnabled = false,
		AirwalkPart = nil,
		RenderConnection = nil,
		Connections = {},
		GUIs = {},
		IsTyping = false,
		Increase = false,
		Decrease = false,
		Offset = 0,
		LastValidRoot = nil,
		SmoothOffset = 0,
	},
	Config = {
		VerticalSpeed = 1.75,
		SmoothSpeed = 0.15,
		Keybinds = {
			Increase = Enum.KeyCode.Space,
			Decrease = Enum.KeyCode.LeftControl,
		},
		DisableOnDeath = false,
		ShowPlatform = false,
	},
	Services = {
		RunService = game:GetService("RunService"),
		UserInputService = game:GetService("UserInputService"),
		Players = game:GetService("Players"),
		Workspace = game:GetService("Workspace"),
		CoreGui = game:GetService("CoreGui"),
	},
}
function Modules.AdvancedAirwalk:Disable()
	if not self.State.IsEnabled then
		return
	end
	if self.State.RenderConnection then
		self.State.RenderConnection:Disconnect()
		self.State.RenderConnection = nil
	end
	if self.State.AirwalkPart and self.State.AirwalkPart.Parent then
		self.State.AirwalkPart:Destroy()
	end
	self.State.AirwalkPart = nil
	for key, conn in pairs(self.State.Connections) do
		if conn then
			conn:Disconnect()
		end
		self.State.Connections[key] = nil
	end
	for key, gui in pairs(self.State.GUIs) do
		if gui and gui.Parent then
			gui:Destroy()
		end
		self.State.GUIs[key] = nil
	end
	self.State.IsEnabled = false
	self.State.IsTyping = false
	self.State.Increase = false
	self.State.Decrease = false
	self.State.Offset = 0
	self.State.SmoothOffset = 0
	self.State.LastValidRoot = nil
	DoNotif("Advanced Airwalk: OFF", 2)
end
function Modules.AdvancedAirwalk:Enable()
	if self.State.IsEnabled then
		self:Disable()
	end
	self.State.IsEnabled = true
	local localPlayer = self.Services.Players.LocalPlayer
	local uis = self.Services.UserInputService
	local isMobile = uis.TouchEnabled
	DoNotif(isMobile and "Advanced Airwalk: ON" or "Advanced Airwalk: ON (Space & LCtrl)", 2)
	local function createMobileButton(parent, text, position, callbackDown, callbackUp)
		local button = Instance.new("TextButton")
		button.Parent = parent
		button.BackgroundColor3 = Color3.fromRGB(45, 45, 45)
		button.Position = position
		button.Size = UDim2.new(0.08, 0, 0.12, 0)
		button.Font = Enum.Font.SourceSansBold
		button.Text = text
		button.TextColor3 = Color3.fromRGB(255, 255, 255)
		button.TextScaled = true
		Instance.new("UICorner", button).CornerRadius = UDim.new(0.2, 0)
		local stroke = Instance.new("UIStroke", button)
		stroke.Color = Color3.fromRGB(255, 255, 255)
		stroke.Thickness = 1.5
		button.MouseButton1Down:Connect(callbackDown)
		button.MouseButton1Up:Connect(callbackUp)
		button.TouchTap:Connect(callbackDown)
		button.TouchEnded:Connect(callbackUp)
		return button
	end
	if isMobile then
		local mobileGui = Instance.new("ScreenGui", self.Services.CoreGui)
		mobileGui.Name = "AdvancedAirwalkMobileControls"
		mobileGui.ResetOnSpawn = false
		self.State.GUIs.MobileControls = mobileGui
		createMobileButton(mobileGui, "UP", UDim2.new(0.9, 0, 0.55, 0), function()
			self.State.Increase = true
		end, function()
			self.State.Increase = false
		end)
		createMobileButton(mobileGui, "DOWN", UDim2.new(0.9, 0, 0.7, 0), function()
			self.State.Decrease = true
		end, function()
			self.State.Decrease = false
		end)
	else
		self.State.Connections.Focused = uis.TextBoxFocused:Connect(function()
			self.State.IsTyping = true
		end)
		self.State.Connections.Released = uis.TextBoxFocusReleased:Connect(function()
			self.State.IsTyping = false
		end)
		self.State.Connections.InputBegan = uis.InputBegan:Connect(function(input, gpe)
			if gpe or self.State.IsTyping then
				return
			end
			if input.KeyCode == self.Config.Keybinds.Increase then
				self.State.Increase = true
			end
			if input.KeyCode == self.Config.Keybinds.Decrease then
				self.State.Decrease = true
			end
		end)
		self.State.Connections.InputEnded = uis.InputEnded:Connect(function(input)
			if input.KeyCode == self.Config.Keybinds.Increase then
				self.State.Increase = false
			end
			if input.KeyCode == self.Config.Keybinds.Decrease then
				self.State.Decrease = false
			end
		end)
	end
	local awPart = Instance.new("Part")
	awPart.Name = "Zuka_AirwalkPart"
	awPart.Size = Vector3.new(8, 1.5, 8)
	awPart.Transparency = self.Config.ShowPlatform and 0.7 or 1
	awPart.Anchored = true
	awPart.CanCollide = true
	awPart.CanQuery = false
	awPart.Parent = self.Services.Workspace
	if self.Config.ShowPlatform then
		awPart.Color = Color3.fromRGB(100, 150, 255)
		awPart.Material = Enum.Material.Neon
	end
	self.State.AirwalkPart = awPart
	if not self.Config.DisableOnDeath then
		self.State.Connections.CharacterAdded = localPlayer.CharacterAdded:Connect(function(newChar)
			task.wait(0.5)
			self.State.Offset = 0
			self.State.SmoothOffset = 0
		end)
	end
	self.State.RenderConnection = self.Services.RunService.RenderStepped:Connect(function(deltaTime)
		if not self.State.IsEnabled then
			self:Disable()
			return
		end
		if not (self.State.AirwalkPart and self.State.AirwalkPart.Parent) then
			self:Disable()
			return
		end
		local success, char, root, hum = pcall(function()
			local c = localPlayer.Character
			return c, c and c:FindFirstChild("HumanoidRootPart"), c and c:FindFirstChildOfClass("Humanoid")
		end)
		if not (success and char and root and hum) then
			if self.State.LastValidRoot then
				self.State.AirwalkPart.CanCollide = false
			else
				if self.Config.DisableOnDeath then
					self:Disable()
				else
					self.State.AirwalkPart.CanCollide = false
				end
			end
			return
		end
		if hum.Health <= 0 then
			if self.Config.DisableOnDeath then
				self:Disable()
			else
				self.State.AirwalkPart.CanCollide = false
			end
			return
		end
		self.State.AirwalkPart.CanCollide = true
		self.State.LastValidRoot = root.Position
		local hrpHalf = root.Size.Y * 0.5
		local feetFromRoot
		if hum.RigType == Enum.HumanoidRigType.R6 then
			feetFromRoot = hrpHalf + (hum.HipHeight > 0 and hum.HipHeight or 2)
		else
			feetFromRoot = hrpHalf + (hum.HipHeight or 2)
		end
		local baseOffset = feetFromRoot + (self.State.AirwalkPart.Size.Y * 0.5)
		local delta = 0
		if self.State.Increase then
			delta = -self.Config.VerticalSpeed
		end
		if self.State.Decrease then
			delta = self.Config.VerticalSpeed
		end
		self.State.Offset = self.State.Offset + delta
		self.State.SmoothOffset = self.State.SmoothOffset
			+ (self.State.Offset - self.State.SmoothOffset) * self.Config.SmoothSpeed
		local newY = root.Position.Y - baseOffset - self.State.SmoothOffset
		self.State.AirwalkPart.CFrame = CFrame.new(root.Position.X, newY, root.Position.Z)
	end)
end
