RegisterCommand({
	Name = "snaptofarmer",
	Aliases = { "sna" },
	Description = "this attempts to counter an exploiter from hovering behind you / attaching and out does their attaching with your own causing you and him to unrender",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	local CONFIG = {
		SNAP_OFFSET = Vector3.new(0, -50000, 2),
		STAY_TIME = 0,
		ACTIVE = false,
		TARGET_NAME = "",
	}
	local localPlayer = Players.LocalPlayer
	local targetPlayer = nil
	local function getRoot(char)
		return char and char:FindFirstChild("HumanoidRootPart")
	end
	local function executeGhostSnap()
		local myChar = localPlayer.Character
		local myRoot = getRoot(myChar)
		local tChar = targetPlayer and targetPlayer.Character
		local tRoot = getRoot(tChar)
		if not myRoot or not tRoot then
			return
		end
		local originalCFrame = myRoot.CFrame
		local behindTarget = tRoot.CFrame * CFrame.new(CONFIG.SNAP_OFFSET)
		myRoot.CFrame = behindTarget
		task.wait(CONFIG.STAY_TIME)
		myRoot.CFrame = originalCFrame
	end
	RunService.Heartbeat:Connect(function()
		if CONFIG.ACTIVE and targetPlayer then
			executeGhostSnap()
		end
	end)
	local function setTarget(name)
		for _, p in ipairs(Players:GetPlayers()) do
