			toggleBtn:FindFirstChildOfClass("UIStroke").Color = Color3.fromRGB(180, 50, 50)
			accentBar.BackgroundColor3 = Color3.fromRGB(80, 220, 120)
		elseif CONFIG.ACTIVE and not targetPlayer then
			statusLabel.Text = "Status: NO TARGET"
