			toggleBtn.BackgroundColor3 = Color3.fromRGB(25, 25, 38)
			toggleBtn:FindFirstChildOfClass("UIStroke").Color = Color3.fromRGB(80, 55, 160)
			accentBar.BackgroundColor3 = Color3.fromRGB(120, 80, 255)
		end
	end
	setBtn.MouseButton1Click:Connect(function()
		local name = inputBox.Text
		if name == "" then
