		CONFIG.TARGET_NAME = name
		local found = setTarget(name)
		if found then
			statusLabel.Text = "Target: " .. targetPlayer.Name
			statusLabel.TextColor3 = Color3.fromRGB(140, 200, 255)
		else
			statusLabel.Text = "Player not found!"
			statusLabel.TextColor3 = Color3.fromRGB(255, 100, 100)
		end
	end)
	toggleBtn.MouseButton1Click:Connect(function()
		CONFIG.ACTIVE = not CONFIG.ACTIVE
		updateStatus()
	end)
	closeBtn.MouseButton1Click:Connect(function()
		local tween = TweenService:Create(
			mainFrame,
			TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In),
			{ Size = UDim2.new(0, 280, 0, 0) }
		)
		tween:Play()
		tween.Completed:Connect(function()
			screenGui:Destroy()
		end)
	end)
	for _, btn in ipairs({ setBtn, toggleBtn, closeBtn }) do
		btn.MouseEnter:Connect(function()
			TweenService:Create(btn, TweenInfo.new(0.12), { BackgroundTransparency = 0.15 }):Play()
		end)
		btn.MouseLeave:Connect(function()
			TweenService:Create(btn, TweenInfo.new(0.12), { BackgroundTransparency = 0 }):Play()
		end)
	end
	inputBox.FocusLost:Connect(function(enterPressed)
		if enterPressed then
			local name = inputBox.Text
			if name ~= "" then
				CONFIG.TARGET_NAME = name
				local found = setTarget(name)
				if found then
					statusLabel.Text = "Target: " .. targetPlayer.Name
					statusLabel.TextColor3 = Color3.fromRGB(140, 200, 255)
				else
					statusLabel.Text = "Player not found!"
					statusLabel.TextColor3 = Color3.fromRGB(255, 100, 100)
				end
			end
		end
	end)
	local dragging = false
	local dragStart = nil
	local startPos = nil
	local function onInputBegan(input)
		if
			input.UserInputType == Enum.UserInputType.MouseButton1
			or input.UserInputType == Enum.UserInputType.Touch
		then
			dragging = true
			dragStart = input.Position
			startPos = mainFrame.Position
		end
	end
	local function onInputChanged(input)
		if
			dragging
			and (
				input.UserInputType == Enum.UserInputType.MouseMovement
				or input.UserInputType == Enum.UserInputType.Touch
			)
		then
			local delta = input.Position - dragStart
			mainFrame.Position =
				UDim2.new(startPos.X.Scale, startPos.X.Offset + delta.X, startPos.Y.Scale, startPos.Y.Offset + delta.Y)
		end
	end
	local function onInputEnded(input)
		if
			input.UserInputType == Enum.UserInputType.MouseButton1
			or input.UserInputType == Enum.UserInputType.Touch
		then
			dragging = false
		end
	end
	titleBar.InputBegan:Connect(onInputBegan)
	UserInputService.InputChanged:Connect(onInputChanged)
	UserInputService.InputEnded:Connect(onInputEnded)
	mainFrame.Size = UDim2.new(0, 280, 0, 0)
	TweenService:Create(
		mainFrame,
		TweenInfo.new(0.25, Enum.EasingStyle.Back, Enum.EasingDirection.Out),
		{ Size = UDim2.new(0, 280, 0, 140) }
	):Play()
	updateStatus()
end)
RegisterCommand({
	Name = "netlib",
	Aliases = { "netli" },
	Description = "beta",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	local Players = game:GetService("Players")
	local RunService = game:GetService("RunService")
	local LocalPlayer = Players.LocalPlayer
	if not getgenv().Network then
		getgenv().Network = {
			BaseParts = {},
			FakeConnections = {},
			Connections = {},
			Output = {
				Enabled = true,
				Prefix = "[NETWORK] ",
				Send = function(Type, Output, BypassOutput)
					if
						typeof(Type) == "function"
						and (Type == print or Type == warn or Type == error)
						and typeof(Output) == "string"
						and (typeof(BypassOutput) == "nil" or typeof(BypassOutput) == "boolean")
					then
						if Network["Output"].Enabled or BypassOutput then
							Type(Network["Output"].Prefix .. Output)
						end
					elseif Network["Output"].Enabled then
						error(Network["Output"].Prefix .. "Output Send Error : Invalid syntax.")
					end
				end,
			},
			LostParts = {},
			CharacterRelative = true,
			LastCharacter = nil,
			TryKeep = true,
			PartOwnership = {
				PreMethodSettings = {},
				Enabled = false,
			},
		}
		Network["Output"].Send(print, ": Loading.")
		Network["RetainPart"] = function(Part, Silent, ReturnFakePart)
			assert(
				Network["PartOwnership"]["Enabled"],
				Network["Output"].Prefix .. " RetainPart Error : PartOwnership is Disabled."
			)
			assert(
				typeof(Part) == "Instance" and Part:IsA("BasePart") and not Part:IsGrounded(),
				Network["Output"].Prefix
					.. "RetainPart Error : Invalid syntax: Arg1 (Part) must be an ungrounded BasePart which is a descendant of workspace."
			)
			if not Part:IsDescendantOf(workspace) then
				Network["Output"].Send(
					error,
					"RetainPart Error : Invalid syntax: Arg1 (Part) must be an ungrounded BasePart which is a descendant of workspace."
				)
				local Index = table.find(Network["LostParts"], Part)
				if Index then
					table.remove(Network["LostParts"], Index)
				end
				return false
			end
			assert(
				typeof(Silent) == "boolean" or typeof(Silent) == "nil",
				Network["Output"].Prefix .. "RetainPart Error : Invalid syntax: Arg2 (Silent) must be a boolean or nil."
			)
			assert(
				typeof(ReturnFakePart) == "boolean" or typeof(ReturnFakePart) == "nil",
				Network["Output"].Prefix
					.. "RetainPart Error : Invalid syntax: Arg3 (ReturnFakePart) must be a boolean or nil."
			)
			if not table.find(Network["BaseParts"], Part) and not table.find(Network["LostParts"], Part) then
				table.insert(Network["BaseParts"], Part)
				Part.CustomPhysicalProperties = PhysicalProperties.new(0, 0, 0, 0, 0)
				if not Silent then
					Network["Output"].Send(
						print,
						"PartOwnership Output : PartOwnership applied to BasePart " .. Part:GetFullName() .. "."
					)
				end
				if ReturnFakePart then
					local workspaceParts = {}
					return FakePart
				end
			else
				Network["Output"].Send(
					warn,
					"RetainPart Warning : PartOwnership not applied to BasePart "
						.. Part:GetFullName()
						.. ", as it already active."
				)
				return false
			end
		end
		Network["RemovePart"] = function(Part, Silent)
			assert(
				typeof(Part) == "Instance" and Part:IsA("BasePart"),
				Network["Output"].Prefix .. "RemovePart Error : Invalid syntax: Arg1 (Part) must be a BasePart."
			)
			local Index1 = table.find(Network["BaseParts"], Part)
			local Index2 = table.find(Network["LostParts"], Part)
			if Index1 then
				table.remove(Network["BaseParts"], Index1)
			else
				if not Silent then
					Network["Output"].Send(
						warn,
						"RemovePart Warning : BasePart " .. Part:GetFullName() .. " not found in BaseParts table."
					)
				end
				return
			end
			if Index2 then
				table.remove(Network["LostParts"], Index2)
			end
			if not Silent then
				Network["Output"].Send(
					print,
					"RemovePart Output: PartOwnership removed from BasePart " .. Part:GetFullName() .. "."
				)
			end
		end
		Network["PartOwnership"]["PartCoroutine"] = coroutine.create(function(Part)
			if Part:IsDescendantOf(workspace) then
				if Network.CharacterRelative then
					local Character = Network["LastCharacter"]
					if not Character.PrimaryPart then
						for _, Inst in pairs(Character:GetDescendants()) do
							if Inst:IsA("BasePart") then
								Character.PrimaryPart = Inst
								break
							end
						end
					end
					if Character and Character.PrimaryPart then
						local Distance = (Character.PrimaryPart.Position - Part.Position).Magnitude
						if
							Distance > gethiddenproperty(LocalPlayer, "MaximumSimulationRadius")
							and not isnetworkowner(Part)
						then
							Network["Output"].Send(
								warn,
								"PartOwnership Warning : PartOwnership not applied to BasePart "
									.. Part:GetFullName()
									.. ", as it is more than "
									.. gethiddenproperty(LocalPlayer, "MaximumSimulationRadius")
									.. " studs away."
							)
							Network["RemovePart"](Part)
							if not Part:IsGrounded() then
								table.insert(Network["LostParts"], Part)
							else
								Network["Output"].Send(
									warn,
									"PartOwnership Warning : PartOwnership not applied to BasePart "
										.. Part:GetFullName()
										.. ", as it is grounded."
								)
							end
						end
					else
						Network["Output"].Send(
							warn,
							"PartOwnership Warning : PartOwnership not applied to BasePart "
								.. Part:GetFullName()
								.. ", as the LocalPlayer Character's PrimaryPart does not exist."
						)
					end
				end
				Part.AssemblyLinearVelocity = (Part.AssemblyLinearVelocity.Unit + Vector3.new(0.01, 0.01, 0.01))
					* (50 + math.cos(tick() * 10))
			else
				Network["RemovePart"](Part)
			end
		end)
		Network["PartOwnership"]["Enable"] = coroutine.create(function()
			if not Network["PartOwnership"]["Enabled"] then
				Network["PartOwnership"]["Enabled"] = true
				Network["PartOwnership"]["PreMethodSettings"].ReplicationFocus = LocalPlayer.ReplicationFocus
				LocalPlayer.ReplicationFocus = workspace
				Network["PartOwnership"]["PreMethodSettings"].SimulationRadius =
					gethiddenproperty(LocalPlayer, "SimulationRadius")
				Network["PartOwnership"]["Connection"] = RunService.Stepped:Connect(function()
					Network["LastCharacter"] = pcall(function()
						return LocalPlayer.Character
					end) or Network["LastCharacter"]
					sethiddenproperty(LocalPlayer, "SimulationRadius", 1 / 0)
					coroutine.wrap(function()
						for _, Part in pairs(Network["BaseParts"]) do
							coroutine.resume(Network["PartOwnership"]["PartCoroutine"], Part)
						end
					end)()
					coroutine.wrap(function()
						for _, Part in pairs(Network["LostParts"]) do
							Network.RetainPart(Part, true)
						end
					end)()
				end)
				Network["Output"].Send(print, "PartOwnership Output : PartOwnership enabled.")
			else
				Network["Output"].Send(warn, "PartOwnership Output : PartOwnership already enabled.")
			end
		end)
		Network["PartOwnership"]["Disable"] = coroutine.create(function()
			if Network["PartOwnership"]["Connection"] then
				Network["PartOwnership"]["Connection"]:Disconnect()
				LocalPlayer.ReplicationFocus = Network["PartOwnership"]["PreMethodSettings"].ReplicationFocus
				sethiddenproperty(
					LocalPlayer,
					"SimulationRadius",
					Network["PartOwnership"]["PreMethodSettings"].SimulationRadius
				)
				Network["PartOwnership"]["PreMethodSettings"] = {}
				for _, Part in pairs(Network["BaseParts"]) do
					Network["RemovePart"](Part)
				end
				for Index, Part in pairs(Network["LostParts"]) do
					table.remove(Network["LostParts"], Index)
				end
				Network["PartOwnership"]["Enabled"] = false
				Network["Output"].Send(print, "PartOwnership Output : PartOwnership disabled.")
			else
				Network["Output"].Send(warn, "PartOwnership Output : PartOwnership already disabled.")
			end
		end)
		Network["Output"].Send(print, ": Loaded.")
	end
	coroutine.resume(Network["PartOwnership"]["Enable"])
end)
Modules.Attacher = {
	State = {
		isGuiBuilt = false,
		followSpeed = 1,
		selectedPlayerName = "Nearest Player",
		isFollowing = false,
		isAttaching = false,
		isAutoAttacking = false,
		attackSpeed = 1,
		isChaosMode = false,
		flingStrength = 0.5,
		oscillationValue = 1,
		lastChaosTime = 0,
		chaosInterval = 0.1,
		UI = {},
		Connections = {},
	},
	Services = {},
}
function Modules.Attacher:Deactivate()
	if not self.State.isGuiBuilt then
		return
	end
	for _, conn in pairs(self.State.Connections) do
		conn:Disconnect()
	end
	table.clear(self.State.Connections)
	if self.State.UI.window and self.State.UI.window.Parent then
		self.State.UI.window:Destroy()
	end
	if self.State.UI.currentHighlight and self.State.UI.currentHighlight.Parent then
		self.State.UI.currentHighlight:Destroy()
	end
	table.clear(self.State.UI)
	self.State.isGuiBuilt = false
	DoNotif("Attacher module deactivated.", 2)
end
function Modules.Attacher:Activate()
	if self.State.isGuiBuilt then
		return
	end
	local self = self
	self.Services.Players = self.Services.Players or game:GetService("Players")
	self.Services.RunService = self.Services.RunService or game:GetService("RunService")
	self.Services.StarterGui = self.Services.StarterGui or game:GetService("StarterGui")
	local LocalPlayer = self.Services.Players.LocalPlayer
	local library =
		loadstring(game:HttpGet("https://raw.githubusercontent.com/bloodball/-back-ups-for-libs/main/wall%20v3"))()
	local w = library:CreateWindow("Attacher")
	self.State.UI.window = w
	local function notify(title, text, duration)
		pcall(function()
			self.Services.StarterGui:SetCore("SendNotification", {
				Title = title,
				Text = text,
				Duration = duration or 3,
			})
		end)
	end
	local function clearHighlight()
		if self.State.UI.currentHighlight and self.State.UI.currentHighlight.Parent then
			self.State.UI.currentHighlight:Destroy()
			self.State.UI.currentHighlight = nil
		end
	end
	local function applyHighlight(targetPlayer)
		clearHighlight()
		if targetPlayer and targetPlayer.Character then
			local h = Instance.new("Highlight", targetPlayer.Character)
			h.Name = "TargetHighlight"
			h.FillColor = Color3.fromRGB(255, 0, 0)
			h.OutlineColor = Color3.fromRGB(255, 255, 255)
			h.FillTransparency = 0.45
			h.Adornee = targetPlayer.Character
			self.State.UI.currentHighlight = h
		end
	end
	local function findPlayerByPartialName(partialName)
		local localChar = LocalPlayer.Character
		if not localChar or not localChar:FindFirstChild("HumanoidRootPart") then
			return nil
		end
		local myPos = localChar.HumanoidRootPart.Position
		local lowerPartialName = partialName:lower()
		local matches = {}
		for _, p in ipairs(self.Services.Players:GetPlayers()) do
			if p ~= LocalPlayer then
				if
					p.Name:lower():find(lowerPartialName, 1, true)
					or p.DisplayName:lower():find(lowerPartialName, 1, true)
				then
					table.insert(matches, p)
				end
			end
		end
		if #matches == 0 then
			return nil
		end
		if #matches == 1 then
			return matches[1]
		end
		local closestPlayer, closestDist = nil, math.huge
		for _, matchedPlayer in ipairs(matches) do
			if matchedPlayer.Character and matchedPlayer.Character:FindFirstChild("HumanoidRootPart") then
				local dist = (matchedPlayer.Character.HumanoidRootPart.Position - myPos).Magnitude
				if dist < closestDist then
					closestDist, closestPlayer = dist, matchedPlayer
				end
			end
		end
		return closestPlayer
	end
	local function updateNearestPlayerButton()
		if not self.State.UI.nearestPlayerButton then
			return
		end
		if self.State.selectedPlayerName == "Nearest Player" then
			self.State.UI.nearestPlayerButton.Name = "-> Nearest Player"
		else
			self.State.UI.nearestPlayerButton.Name = "Nearest Player"
		end
	end
	local mainFolder = w:CreateFolder("Follow Settings")
	mainFolder:Slider("Speed", { min = 0, max = 5, precise = true }, function(value)
		self.State.followSpeed = value
	end)
	mainFolder:Box("Enter Username", "string", function(value)
		if value == "" then
			notify("Input Error", "Please type a valid username.", 3)
			return
		end
		local found = findPlayerByPartialName(value)
		if found and found ~= LocalPlayer then
			self.State.selectedPlayerName = found.Name
			applyHighlight(found)
			notify("Player Selected", "Targeting " .. found.Name, 2)
			updateNearestPlayerButton()
		else
			self.State.selectedPlayerName = "Nearest Player"
			updateNearestPlayerButton()
			notify("Player Not Found", "Could not find player: " .. value, 3)
		end
	end)
	self.State.UI.nearestPlayerButton = mainFolder:Button("-> Nearest Player", function()
		self.State.selectedPlayerName = "Nearest Player"
		clearHighlight()
		notify("Player Selected", "Nearest Player", 2)
		updateNearestPlayerButton()
	end)
	mainFolder:Toggle("Enable Following", function(bool)
		self.State.isFollowing = bool
		notify("Following", bool and "Enabled" or "Disabled")
	end)
	mainFolder:Toggle("Attach", function(bool)
		self.State.isAttaching = bool
		notify("Attach", bool and "Enabled" or "Disabled")
	end)
	local combatFolder = w:CreateFolder("Combat")
	combatFolder:Slider("Attack Speed", { min = 0.1, max = 5, precise = true }, function(value)
		self.State.attackSpeed = value
	end)
	combatFolder:Toggle("Auto Attack (M1)", function(bool)
		self.State.isAutoAttacking = bool
		notify("Auto Attack", bool and "ENABLED - Spamming M1" or "Disabled")
	end)
	local chaosFolder = w:CreateFolder("Anti-Aimbot")
	chaosFolder:Slider("Fling Strength", { min = 0.1, max = 2, precise = true }, function(value)
		self.State.flingStrength = value
	end)
	chaosFolder:Toggle("Chaos Movement", function(bool)
		self.State.isChaosMode = bool
		notify("Chaos Mode", bool and "ENABLED - Breaking Aimbots" or "Disabled")
	end)
	local function getNearestPlayer()
		local localChar = LocalPlayer.Character
		if not (localChar and localChar:FindFirstChild("HumanoidRootPart")) then
			return nil
		end
		local myPos = localChar.HumanoidRootPart.Position
		local closest, dist = nil, math.huge
		for _, p in ipairs(self.Services.Players:GetPlayers()) do
			if p ~= LocalPlayer and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then
				local d = (p.Character.HumanoidRootPart.Position - myPos).Magnitude
				if d < dist then
					closest, dist = p, d
				end
			end
		end
		return closest
	end
	local function getSelectedPlayer()
		if self.State.selectedPlayerName == "Nearest Player" then
			local n = getNearestPlayer()
			if n then
				applyHighlight(n)
			else
				clearHighlight()
			end
			return n
		elseif
			self.State.selectedPlayerName and self.Services.Players:FindFirstChild(self.State.selectedPlayerName)
		then
			local p = self.Services.Players[self.State.selectedPlayerName]
			if
				p.Character
				and p.Character:FindFirstChild("HumanoidRootPart")
				and p.Character:FindFirstChildOfClass("Humanoid").Health > 0
			then
				return p
			end
		end
		clearHighlight()
		return nil
	end
	local lastAttackTime = 0
	self.State.Connections.RenderStepped = self.Services.RunService.RenderStepped:Connect(function()
		local target = getSelectedPlayer()
		if (self.State.isFollowing or self.State.isAttaching) and target then
			local localChar, targetChar = LocalPlayer.Character, target.Character
			if localChar and targetChar then
				local part, targetPart =
					localChar:FindFirstChild("HumanoidRootPart"), targetChar:FindFirstChild("HumanoidRootPart")
				if part and targetPart then
					local hum = localChar:FindFirstChildOfClass("Humanoid")
					if hum then
						hum.AutoRotate = false
					end
					if self.State.isAttaching then
						part.CFrame = part.CFrame:Lerp(targetPart.CFrame, self.State.followSpeed)
						local thum = targetChar:FindFirstChildOfClass("Humanoid")
						if thum and thum.Jump then
							hum.Jump = true
						end
					elseif self.State.isFollowing then
						part.CFrame =
							part.CFrame:Lerp(CFrame.new(part.Position, targetPart.Position), self.State.followSpeed)
						hum:MoveTo(targetPart.Position)
					end
				end
			end
		else
			local c = LocalPlayer.Character
			if c and c:FindFirstChildOfClass("Humanoid") then
				c:FindFirstChildOfClass("Humanoid").AutoRotate = true
			end
		end
		if self.State.isChaosMode then
			local character = LocalPlayer.Character
			local rootPart = character and character:FindFirstChild("HumanoidRootPart")
			if rootPart then
				local currentTime = tick()
				if currentTime - self.State.lastChaosTime >= self.State.chaosInterval then
					self.State.lastChaosTime = currentTime
					self.State.oscillationValue = -self.State.oscillationValue
					local offsetX = math.sin(currentTime * 8) * self.State.flingStrength * 5
					local offsetY = self.State.oscillationValue * self.State.flingStrength * 3
					local offsetZ = math.cos(currentTime * 8) * self.State.flingStrength * 5
					rootPart.CFrame = rootPart.CFrame * CFrame.new(offsetX, offsetY, offsetZ)
					local oscillationVelocity = Vector3.new(
						math.sin(currentTime * 5) * self.State.flingStrength * 30,
						self.State.oscillationValue * self.State.flingStrength * 15,
						math.cos(currentTime * 5) * self.State.flingStrength * 30
					)
					rootPart.Velocity = rootPart.Velocity + oscillationVelocity
				end
			end
		end
		if self.State.isAutoAttacking and target then
			local localChar = LocalPlayer.Character
			if localChar then
				local currentTime = tick()
				local attackDelay = 1 / self.State.attackSpeed
				if currentTime - lastAttackTime >= attackDelay then
					lastAttackTime = currentTime
					local backpack = LocalPlayer:FindFirstChild("Backpack")
					local equippedTool = localChar:FindFirstChildOfClass("Tool")
					if not equippedTool and backpack then
						local tool = backpack:FindFirstChildOfClass("Tool")
						if tool then
							tool.Parent = localChar
							equippedTool = tool
						end
					end
					if equippedTool and equippedTool:FindFirstChild("Handle") then
						local targetChar = target.Character
						if targetChar and targetChar:FindFirstChild("HumanoidRootPart") then
							local handle = equippedTool:FindFirstChild("Handle")
							if handle then
								handle.CFrame = CFrame.new(handle.Position, targetChar.HumanoidRootPart.Position)
							end
							equippedTool:Activate()
						end
					end
				end
			end
		end
	end)
	self.State.Connections.KeyDown = LocalPlayer:GetMouse().KeyDown:Connect(function(k)
		k = k:lower()
		if k == "x" then
			self.State.isFollowing = not self.State.isFollowing
			notify("Following", self.State.isFollowing and "Enabled" or "Disabled")
		elseif k == "z" then
			self.State.isAttaching = not self.State.isAttaching
			notify("Attach", self.State.isAttaching and "Enabled" or "Disabled")
		elseif k == "c" then
			self.State.isAutoAttacking = not self.State.isAutoAttacking
			notify("Auto Attack", self.State.isAutoAttacking and "ENABLED - Spamming M1" or "Disabled")
		elseif k == "v" then
			self.State.isChaosMode = not self.State.isChaosMode
			notify("Chaos Mode", self.State.isChaosMode and "ENABLED - Breaking Aimbots" or "Disabled")
		end
	end)
	self.State.isGuiBuilt = true
	DoNotif("Attacher module activated.", 2)
end
function Modules.Attacher:Toggle()
	if self.State.isGuiBuilt then
		self:Deactivate()
	else
		self:Activate()
	end
end
RegisterCommand({
	Name = "attacher",
	Aliases = { "attachui", "followui" },
	Description = "Toggles the Player Attacher/Follower UI.",
}, function()
	if not Modules.Attacher.Toggle then
		local originalFunctions = loadfile("path/to/your/AttacherModule.lua")()
		Modules.Attacher.Activate = originalFunctions.Activate
		Modules.Attacher.Deactivate = originalFunctions.Deactivate
		Modules.Attacher.Toggle = originalFunctions.Toggle
	end
	Modules.Attacher:Toggle()
end)
Modules.StaffSentry = {
	State = {
		IsEnabled = false,
		AutoJoinConnection = nil,
		StaffGroups = { 1200769, 14246738, 4199740 },
	},
}
function Modules.StaffSentry:Scan()
	local found = {}
	for _, player in ipairs(Players:GetPlayers()) do
		if player == LocalPlayer then
			continue
		end
		local isStaff = false
		for _, groupId in ipairs(self.State.StaffGroups) do
			if player:GetRankInGroup(groupId) > 0 then
				isStaff = true
				break
			end
		end
		if isStaff or player:IsFriendsWith(LocalPlayer.UserId) == false and (player.AccountAge < 5) then
			table.insert(found, player.Name)
		end
	end
	if #found > 0 then
		DoNotif("Staff/Suspects Found: " .. table.concat(found, ", "), 5)
	else
		DoNotif("No staff members detected in current server.", 3)
	end
end
function Modules.StaffSentry:Initialize()
	RegisterCommand({
		Name = "staffcheck",
		Aliases = { "scheck", "admins" },
		Description = "Scans the server for players in common staff groups or with suspicious account ages.",
	}, function()
		self:Scan()
	end)
end
