	modeLabel.Text = "Mode:"
	modeLabel.TextColor3 = Color3.new(1, 1, 1)
	modeLabel.TextSize = 13
	modeLabel.TextXAlignment = Enum.TextXAlignment.Left
	local modeButtons = {}
