local function applyStroke(parent, color, thickness)
	local s = Instance.new("UIStroke")
	s.Color = color
	s.Thickness = thickness or 1
	s.LineJoinMode = Enum.LineJoinMode.Miter
	s.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
	s.Parent = parent
	return s
end
local function applyCorner(parent, radius)
	local c = Instance.new("UICorner")
	c.CornerRadius = UDim.new(0, radius or 4)
	c.Parent = parent
	return c
end
local function hoverFx(btn, T)
	local normal = btn.BackgroundColor3
	btn.MouseEnter:Connect(function()
		T.Services.TweenService:Create(btn, TweenInfo.new(0.1), { BackgroundColor3 = T.Theme.BG_BTN_HOV }):Play()
	end)
	btn.MouseLeave:Connect(function()
		T.Services.TweenService:Create(btn, TweenInfo.new(0.1), { BackgroundColor3 = normal }):Play()
	end)
end
