function Modules.ScriptExecutor2:LoadSavedScripts()
	if not listfiles or not isfolder then
		print("[Synapse] listfiles or isfolder not available")
		return 0
	end
	local success, files = pcall(function()
		if not isfolder(self.Config.SCRIPTS_DIR) then
			return {}
		end
		return listfiles(self.Config.SCRIPTS_DIR)
	end)
	if not success or not files then
		return 0
	end
	local count = 0
	for _, filePath in ipairs(files) do
		if filePath:lower():match("%.lua$") then
			local loadSuccess, content = pcall(function()
				return readfile(filePath)
			end)
			if loadSuccess and content then
				local scriptName = filePath:match("([^/\\]+)%.lua$") or filePath:match("([^/\\]+)$")
				self.State.SavedScripts[scriptName] = {
					path = filePath,
					code = content,
					saved = os.time(),
				}
				count = count + 1
			end
		end
	end
	return count
end
function Modules.ScriptExecutor2:UpdateLineNumbers(scriptBox, lineNumText)
	local lineCount = select(2, scriptBox.Text:gsub("\n", "\n")) + 1
	local numbers = {}
	for i = 1, math.min(lineCount, 1000) do
		table.insert(numbers, tostring(i))
	end
	lineNumText.Text = table.concat(numbers, "\n")
end
function Modules.ScriptExecutor2:CreateModernButton(parent, props)
	local T = self.Theme
	local button = Instance.new("TextButton", parent)
	button.Name = props.Name or "Button"
	button.Position = props.Position
	button.Size = props.Size
	button.BackgroundColor3 = T.BG_BTN
	button.BorderSizePixel = 0
	button.Font = Enum.Font.Gotham
	button.Text = props.Text or ""
	button.TextColor3 = T.TEXT_MAIN
	button.TextSize = props.TextSize or 12
	button.ZIndex = props.ZIndex or 2
	applyCorner(button, 3)
	applyStroke(button, props.Accent and T.STROKE_ACCENT or T.STROKE_BTN, 1)
	button.MouseEnter:Connect(function()
		self.Services.TweenService:Create(button, TweenInfo.new(0.1), { BackgroundColor3 = T.BG_BTN_HOV }):Play()
	end)
	button.MouseLeave:Connect(function()
		self.Services.TweenService:Create(button, TweenInfo.new(0.1), { BackgroundColor3 = T.BG_BTN }):Play()
	end)
	button.MouseButton1Down:Connect(function()
		self.Services.TweenService:Create(button, TweenInfo.new(0.06), { BackgroundColor3 = T.BG_DEEP }):Play()
	end)
	button.MouseButton1Up:Connect(function()
		self.Services.TweenService:Create(button, TweenInfo.new(0.06), { BackgroundColor3 = T.BG_BTN_HOV }):Play()
	end)
	if props.Callback then
		button.MouseButton1Click:Connect(props.Callback)
	end
	return button
end
