		else
			DoNotif("Clipboard not supported", 2)
			statusText.Text = "Clipboard not available"
			statusText.TextColor3 = T.TEXT_ERR
		end
	end)
	saveBtn.MouseButton1Click:Connect(function()
		module:ShowSaveDialog(scriptBox.Text)
	end)
	local resizeHandle = Instance.new("Frame", mainFrame)
	resizeHandle.Name = "ResizeHandle"
	resizeHandle.Size = UDim2.fromOffset(16, 16)
	resizeHandle.Position = UDim2.new(1, -16, 1, -16)
	resizeHandle.BackgroundColor3 = T.BG_PANEL
	resizeHandle.BorderSizePixel = 0
	resizeHandle.ZIndex = 10
	for i = 0, 2 do
		local dot = Instance.new("Frame", resizeHandle)
		dot.Size = UDim2.fromOffset(3, 3)
		dot.Position = UDim2.fromOffset(4 + i * 4, 10 - i * 4)
		dot.BackgroundColor3 = T.STROKE_BTN
		dot.BorderSizePixel = 0
		dot.ZIndex = 11
		applyCorner(dot, 1)
	end
	local dragging, resizing = false, false
	local dragStart, resizeStart, startPos, startSize
	titleBar.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 and not module.State.IsMaximized then
			dragging = true
			dragStart = input.Position
			startPos = mainFrame.Position
			local conn
			conn = input.Changed:Connect(function()
				if input.UserInputState == Enum.UserInputState.End then
					dragging = false
					conn:Disconnect()
				end
			end)
		end
	end)
	local lastClick = 0
	titleBar.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 then
			local now = tick()
			if now - lastClick < 0.3 then
				module:Maximize()
			end
			lastClick = now
		end
	end)
	resizeHandle.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 and not module.State.IsMaximized then
			resizing = true
			resizeStart = input.Position
			startSize = mainFrame.Size
			startPos = mainFrame.Position
			local conn
			conn = input.Changed:Connect(function()
				if input.UserInputState == Enum.UserInputState.End then
					resizing = false
					conn:Disconnect()
				end
			end)
		end
	end)
	self.Services.UserInputService.InputChanged:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseMovement then
			if dragging then
				local delta = input.Position - dragStart
				mainFrame.Position = UDim2.new(
					startPos.X.Scale,
					startPos.X.Offset + delta.X,
					startPos.Y.Scale,
					startPos.Y.Offset + delta.Y
				)
			elseif resizing then
				local delta = Vector2.new(input.Position.X - resizeStart.X, input.Position.Y - resizeStart.Y)
				local newWidth = math.max(module.Config.MIN_WIDTH, startSize.X.Offset + delta.X)
				local newHeight = math.max(module.Config.MIN_HEIGHT, startSize.Y.Offset + delta.Y)
				mainFrame.Size = UDim2.new(0, newWidth, 0, newHeight)
			end
		end
	end)
	self.State.IsEnabled = true
	statusText.Text = "Synapse X:"
	DoNotif("Synapse opened", 2)
	self:RefreshScriptList()
end
function Modules.ScriptExecutor2:Toggle()
	if self.State.IsEnabled then
		self:DestroyUI()
		DoNotif("Synapse closed", 2)
	else
		self:CreateUI()
	end
end
function Modules.ScriptExecutor2:Initialize()
	local module = self
	RegisterCommand({
		Name = "synapse",
		Aliases = {},
		Description = "Opens the synapse internal GUI",
	}, function()
		module:Toggle()
	end)
end
Modules.MirrorMimic = {
	State = {
		IsEnabled = false,
		TargetPlayer = nil,
		Delay = 0,
		UID = 0,
		AnimatePrevDisabled = nil,
		PrevAutoRotate = true,
		PoseQueue = {},
		PoseHead = 1,
		AnimEvents = {},
		AnimHead = 1,
		ActiveSlots = {},
		Connections = {},
	},
	Dependencies = { "RunService", "Players", "Workspace" },
	Services = {},
}
function Modules.MirrorMimic:_cleanup()
	local lp = self.Services.Players.LocalPlayer
	local char = lp.Character
	local hum = char and char:FindFirstChildOfClass("Humanoid")
	for key, conn in pairs(self.State.Connections) do
		conn:Disconnect()
	end
	table.clear(self.State.Connections)
	for _, slot in pairs(self.State.ActiveSlots) do
		if slot.mt then
			pcall(function()
				slot.mt:Stop(0)
			end)
		end
	end
	table.clear(self.State.ActiveSlots)
	if hum then
		local animator = hum:FindFirstChildOfClass("Animator")
		if animator then
			for _, tr in ipairs(animator:GetPlayingAnimationTracks()) do
				pcall(function()
					tr:Stop(0)
				end)
			end
		end
		hum.AutoRotate = self.State.PrevAutoRotate
	end
	local animate = char and char:FindFirstChild("Animate")
	if animate and self.State.AnimatePrevDisabled ~= nil then
		animate.Disabled = self.State.AnimatePrevDisabled
	end
	self.State.PoseQueue = {}
	self.State.PoseHead = 1
	self.State.AnimEvents = {}
	self.State.AnimHead = 1
	self.State.IsEnabled = false
	self.State.TargetPlayer = nil
end
function Modules.MirrorMimic:_scheduleAnim(track, kind, extra)
	local now = os.clock()
	table.insert(self.State.AnimEvents, {
		t = now + self.State.Delay,
		kind = kind,
		track = track,
		animId = track.Animation.AnimationId,
		speed = (type(track.Speed) == "number" and track.Speed) or 1,
		baseTP = track.TimePosition or 0,
		looped = track.Looped,
		data = extra,
	})
end
function Modules.MirrorMimic:Enable(targetName, delayVal)
	local target = Utilities.findPlayer(targetName)
	if not target or not target.Character then
		return DoNotif("Mimic: Target not found or has no character.", 3)
	end
	local lp = self.Services.Players.LocalPlayer
	local myChar = lp.Character
	local tChar = target.Character
	local myHum = myChar and myChar:FindFirstChildOfClass("Humanoid")
	local tHum = tChar and tChar:FindFirstChildOfClass("Humanoid")
	if not (myHum and tHum) or myHum.RigType ~= tHum.RigType then
		return DoNotif("Mimic Error: Character rig types do not match.", 3)
	end
	self:_cleanup()
	self.State.IsEnabled = true
	self.State.TargetPlayer = target
	self.State.Delay = tonumber(delayVal) or 0
	self.State.PrevAutoRotate = myHum.AutoRotate
	myHum.AutoRotate = false
	local myRoot = myChar:FindFirstChild("HumanoidRootPart")
	local tRoot = tChar:FindFirstChild("HumanoidRootPart")
	local myAnimator = myHum:FindFirstChildOfClass("Animator") or Instance.new("Animator", myHum)
	local tAnimator = tHum:FindFirstChildOfClass("Animator")
	local animate = myChar:FindFirstChild("Animate")
	if animate then
		self.State.AnimatePrevDisabled = animate.Disabled
		animate.Disabled = true
	end
	self.State.Connections.AnimPlayed = tHum.AnimationPlayed:Connect(function(tt)
		self:_scheduleAnim(tt, "start")
		self.State.Connections["TrackSpd_" .. tostring(tt)] = tt:GetPropertyChangedSignal("Speed"):Connect(function()
			self:_scheduleAnim(tt, "speed")
		end)
		self.State.Connections["TrackStop_" .. tostring(tt)] = tt.Stopped:Connect(function()
			self:_scheduleAnim(tt, "stop")
		end)
	end)
	self.State.Connections.ToolEquip = tChar.ChildAdded:Connect(function(child)
		if child:IsA("Tool") then
			local match = lp.Backpack:FindFirstChild(child.Name)
			if match then
				pcall(function()
					myHum:EquipTool(match)
				end)
			end
		end
	end)
	local lastLook = Vector3.new(0, 0, -1)
	self.State.Connections.MainLoop = self.Services.RunService.Heartbeat:Connect(function()
		if not (tChar.Parent and tRoot.Parent and myChar.Parent) then
			return self:_cleanup()
		end
		local now = os.clock()
		local lv = tRoot.CFrame.LookVector
		local flat = Vector3.new(lv.X, 0, lv.Z)
		if flat.Magnitude >= 1e-4 then
			lastLook = flat.Unit
		end
		table.insert(self.State.PoseQueue, {
			t = now,
			pos = tRoot.Position,
			look = lastLook,
			vel = tRoot.AssemblyLinearVelocity,
			angY = tRoot.AssemblyAngularVelocity.Y,
		})
		local snap
		while
			self.State.PoseHead <= #self.State.PoseQueue
			and self.State.PoseQueue[self.State.PoseHead].t <= (now - self.State.Delay)
		do
			snap = self.State.PoseQueue[self.State.PoseHead]
			self.State.PoseHead = self.State.PoseHead + 1
		end
		if snap then
			myRoot.CFrame = CFrame.lookAt(snap.pos, snap.pos + snap.look)
			myRoot.AssemblyLinearVelocity = snap.vel
			myRoot.AssemblyAngularVelocity = Vector3.new(0, snap.angY, 0)
			if self.State.PoseHead > 64 then
				local newBuf = {}
				for i = self.State.PoseHead, #self.State.PoseQueue do
					table.insert(newBuf, self.State.PoseQueue[i])
				end
				self.State.PoseQueue, self.State.PoseHead = newBuf, 1
			end
		end
		while self.State.AnimHead <= #self.State.AnimEvents and self.State.AnimEvents[self.State.AnimHead].t <= now do
			local e = self.State.AnimEvents[self.State.AnimHead]
			self.State.AnimHead = self.State.AnimHead + 1
			if e.kind == "start" and e.animId ~= "" then
				self.State.UID = self.State.UID + 1
				local animObj = Instance.new("Animation")
				animObj.AnimationId = e.animId
				local mt = myAnimator:LoadAnimation(animObj)
				pcall(function()
					mt:Play(0, 1, 1)
					mt:AdjustSpeed(0)
					mt.TimePosition = e.baseTP
				end)
				self.State.ActiveSlots[self.State.UID] = {
					mt = mt,
					track = e.track,
					baseTP = e.baseTP,
					segments = { { t = e.t, speed = e.speed } },
					looped = e.looped,
					alive = true,
				}
			elseif e.kind == "speed" then
				for _, s in pairs(self.State.ActiveSlots) do
					if s.alive and s.track == e.track then
						table.insert(s.segments, { t = e.t, speed = e.speed })
					end
				end
			elseif e.kind == "stop" then
				for id, s in pairs(self.State.ActiveSlots) do
					if s.alive and s.track == e.track then
						pcall(function()
							s.mt:Stop(0)
						end)
						s.alive = false
						self.State.ActiveSlots[id] = nil
					end
				end
			end
		end
		for _, s in pairs(self.State.ActiveSlots) do
			if s.alive and s.mt then
				local len = s.mt.Length
				if len > 0 then
					local tp = s.baseTP
					for i = 1, #s.segments do
						local st = s.segments[i].t
						local sp = s.segments[i].speed
						local en = (i < #s.segments) and s.segments[i + 1].t or now
						if en > st then
							tp = tp + (en - st) * sp
						end
					end
					tp = s.looped and (tp % len) or math.clamp(tp, 0, len - 0.03)
					pcall(function()
						s.mt.TimePosition = tp
					end)
				end
			end
		end
	end)
	DoNotif("Mirror Active: Mimicking " .. target.Name, 2)
end
function Modules.MirrorMimic:Initialize()
	local module = self
	for _, serviceName in ipairs(module.Dependencies) do
		module.Services[serviceName] = game:GetService(serviceName)
	end
	RegisterCommand({
		Name = "mimic",
		Aliases = { "mirror", "mclone", "mcopy", "mimi" },
		Description = "Clones a player's movement and animations.",
	}, function(args)
		if #args == 0 then
			return DoNotif("Usage: ;mimic <PlayerName> [delay]", 3)
		end
		module:Enable(args[1], args[2] or 0)
	end)
	RegisterCommand({
		Name = "unmimic",
		Aliases = { "mstop", "moff", "stopmimic" },
		Description = "Stops movement mirroring.",
	}, function()
		module:_cleanup()
		DoNotif("Mimic Disabled.", 2)
	end)
end
Modules.ServerHopper = {
	State = {
		IsSearching = false,
	},
	Dependencies = { "HttpService", "TeleportService", "Players" },
	Services = {},
}
function Modules.ServerHopper:Hop(mode)
	if self.State.IsSearching then
		return
	end
	self.State.IsSearching = true
	local http = self.Services.HttpService
	local tp = self.Services.TeleportService
	local placeId = game.PlaceId
	local jobId = game.JobId
	DoNotif("Searching for a " .. (mode == "High" and "large" or "small") .. " server...", 3)
	task.spawn(function()
		local success, result = pcall(function()
			return game:HttpGet(
				string.format("https://games.roblox.com/v1/games/%d/servers/Public?sortOrder=Asc&limit=100", placeId)
			)
		end)
		if not success or not result then
			self.State.IsSearching = false
			return DoNotif("Server Hop Error: Failed to fetch server list.", 3)
		end
		local data = http:JSONDecode(result)
		if not data or not data.data then
			self.State.IsSearching = false
			return DoNotif("Server Hop Error: Empty API response.", 3)
		end
		local serverList = data.data
		local candidates = {}
		for _, server in ipairs(serverList) do
			if server.id ~= jobId and server.playing < server.maxPlayers then
				table.insert(candidates, server)
			end
		end
		if #candidates == 0 then
			self.State.IsSearching = false
			return DoNotif("No valid servers found in this batch.", 3)
		end
		if mode == "High" then
			table.sort(candidates, function(a, b)
				return a.playing > b.playing
			end)
		else
			table.sort(candidates, function(a, b)
				return a.playing < b.playing
			end)
		end
		local target = candidates[1]
		DoNotif(string.format("Joining server [%d/%d players]...", target.playing, target.maxPlayers), 3)
		task.wait(0.5)
		local tpSuccess, tpErr = pcall(function()
			tp:TeleportToPlaceInstance(placeId, target.id, self.Services.Players.LocalPlayer)
		end)
		if not tpSuccess then
			warn("--> [ServerHopper] Teleport Failed:", tpErr)
			DoNotif("Teleport failed. Check console.", 3)
		end
		self.State.IsSearching = false
	end)
end
function Modules.ServerHopper:Initialize()
	local module = self
	for _, serviceName in ipairs(module.Dependencies) do
		module.Services[serviceName] = game:GetService(serviceName)
	end
	RegisterCommand({
		Name = "serverhop",
		Aliases = { "shop", "hop" },
		Description = "Teleports you to a different, populated server.",
	}, function()
		module:Hop("High")
	end)
	RegisterCommand({
		Name = "smallserverhop",
		Aliases = { "sshop", "smallhop", "minihop" },
		Description = "Teleports you to a server with the fewest players.",
	}, function()
		module:Hop("Low")
	end)
end
RegisterCommand({
	Name = "spawn",
	Aliases = { "qs" },
	Description = "force spawn",
}, function(args)
	local function forceToWorkspace(character)
		if not character then
			return
		end
		character.AncestryChanged:Connect(function(_, newParent)
			if newParent and newParent ~= workspace then
				task.defer(function()
					if character and character.Parent ~= workspace then
						character.Parent = workspace
						print("[ForceWorkspace] Character moved back to Workspace from: " .. tostring(newParent))
					end
				end)
			end
		end)
		if character.Parent ~= workspace then
			character.Parent = workspace
		end
	end
	if localPlayer.Character then
		forceToWorkspace(localPlayer.Character)
	end
	localPlayer.CharacterAdded:Connect(forceToWorkspace)
end)
Modules.HumanShield = {
	State = {
		IsEnabled = false,
		TrackedPlayers = {},
		Connections = {},
		CharacterConnections = {},
	},
	Config = {
		DISTANCE = 5.5,
		VERTICAL_OFFSET = 0,
	},
	Dependencies = { "Players", "RunService" },
}
function Modules.HumanShield:Stop()
	self.State.IsEnabled = false
	for _, connection in pairs(self.State.Connections) do
		if connection then
			connection:Disconnect()
		end
	end
	for _, connection in pairs(self.State.CharacterConnections) do
		if connection then
			connection:Disconnect()
		end
	end
	self.State.Connections = {}
	self.State.CharacterConnections = {}
	self.State.TrackedPlayers = {}
end
function Modules.HumanShield:_setupPlayerBring(player)
	local character = player.Character
	if not character then
		return
	end
	local tRoot = character:FindFirstChild("HumanoidRootPart")
	if not tRoot then
		return
	end
	local connectionId = "Bring_" .. player.UserId
	if self.State.Connections[connectionId] then
		self.State.Connections[connectionId]:Disconnect()
	end
	local connection = RunService.Heartbeat:Connect(function()
		local myChar = Players.LocalPlayer.Character
		local myRoot = myChar and myChar:FindFirstChild("HumanoidRootPart")
		if not self.State.TrackedPlayers[player] then
			if self.State.Connections[connectionId] then
				self.State.Connections[connectionId]:Disconnect()
				self.State.Connections[connectionId] = nil
			end
			return
		end
		if not (myRoot and tRoot and tRoot.Parent) then
			return
		end
		tRoot.Velocity = Vector3.new(0, 30.01, 0)
		tRoot.CFrame = myRoot.CFrame * CFrame.new(0, self.Config.VERTICAL_OFFSET, -self.Config.DISTANCE)
	end)
	self.State.Connections[connectionId] = connection
end
function Modules.HumanShield:_trackPlayer(player)
	if self.State.TrackedPlayers[player] then
		return
	end
	self.State.TrackedPlayers[player] = true
	if player.Character then
		self:_setupPlayerBring(player)
	end
	local respawnConnectionId = "Respawn_" .. player.UserId
	self.State.CharacterConnections[respawnConnectionId] = player.CharacterAdded:Connect(function(character)
		task.wait(0.1)
		if self.State.TrackedPlayers[player] then
			self:_setupPlayerBring(player)
			DoNotif(player.Name .. " respawned - re-bringing", 1.5)
		end
	end)
end
function Modules.HumanShield:_untrackPlayer(player)
	self.State.TrackedPlayers[player] = nil
	local connectionId = "Bring_" .. player.UserId
	if self.State.Connections[connectionId] then
		self.State.Connections[connectionId]:Disconnect()
		self.State.Connections[connectionId] = nil
	end
	local respawnConnectionId = "Respawn_" .. player.UserId
	if self.State.CharacterConnections[respawnConnectionId] then
		self.State.CharacterConnections[respawnConnectionId]:Disconnect()
		self.State.CharacterConnections[respawnConnectionId] = nil
	end
end
function Modules.HumanShield:PossessAll()
	if self.State.IsEnabled then
		self:Stop()
	end
	local myChar = Players.LocalPlayer.Character
	if not myChar or not myChar:FindFirstChild("HumanoidRootPart") then
		return DoNotif("Your character not found.", 2)
	end
	local validPlayers = {}
	for _, player in pairs(Players:GetPlayers()) do
		if player ~= Players.LocalPlayer then
			table.insert(validPlayers, player)
		end
	end
	if #validPlayers == 0 then
		return DoNotif("No valid targets found.", 2)
	end
	self.State.IsEnabled = true
	for _, player in ipairs(validPlayers) do
		self:_trackPlayer(player)
	end
	self.State.CharacterConnections.PlayerAdded = Players.PlayerAdded:Connect(function(player)
		if self.State.IsEnabled and player ~= Players.LocalPlayer then
			task.wait(0.5)
			self:_trackPlayer(player)
			DoNotif("New player joined - bringing " .. player.Name, 2)
		end
	end)
	self.State.CharacterConnections.PlayerRemoving = Players.PlayerRemoving:Connect(function(player)
		self:_untrackPlayer(player)
	end)
	DoNotif("Shield Active: All players (" .. #validPlayers .. ")", 2)
end
function Modules.HumanShield:Possess(targetName)
	local targetPlr = Utilities.findPlayer(targetName)
	if not targetPlr then
		return DoNotif("Target not found.", 2)
	end
	if self.State.IsEnabled then
		self:Stop()
	end
	self.State.IsEnabled = true
	self:_trackPlayer(targetPlr)
end
function Modules.HumanShield:Initialize()
	local module = self
	RegisterCommand({
		Name = "bring",
		Aliases = { "b" },
		Description = "Positions a player in front of you (persists through respawns). Use 'all' to bring all players.",
	}, function(args)
		if module.State.IsEnabled then
			module:Stop()
			DoNotif("Shield Released.", 2)
		else
			if #args > 0 then
				if args[1]:lower() == "all" then
					module:PossessAll()
				else
					module:Possess(args[1])
				end
			else
				DoNotif("Usage: ;bring [player/all]", 3)
			end
		end
	end)
	RegisterCommand({
		Name = "unbring",
		Aliases = { "ub", "release" },
		Description = "Releases a specific player from the shield.",
	}, function(args)
		if not module.State.IsEnabled then
			return DoNotif("Shield is not active.", 2)
		end
		if not args[1] then
			return DoNotif("Usage: ;unbring [player]", 3)
		end
		local targetPlr = Utilities.findPlayer(args[1])
		if not targetPlr then
			return DoNotif("Player not found.", 2)
		end
		if not module.State.TrackedPlayers[targetPlr] then
			return DoNotif(targetPlr.Name .. " is not being brought.", 2)
		end
		module:_untrackPlayer(targetPlr)
		DoNotif("Released: " .. targetPlr.Name, 2)
	end)
	RegisterCommand({
		Name = "bringlist",
		Aliases = { "bl" },
		Description = "Lists all players currently being brought.",
	}, function()
		if not module.State.IsEnabled then
			return DoNotif("Shield is not active.", 2)
		end
		local count = 0
		print("=== Brought Players ===")
		for player, _ in pairs(module.State.TrackedPlayers) do
			if player and player.Parent then
				print("  • " .. player.Name)
				count = count + 1
			end
		end
		print("Player Killer.")
		DoNotif("Bringing " .. count .. " player(s). Check console (F9)", 2)
	end)
end
Modules.NPCShield = {
	State = {
		IsEnabled = false,
		TrackedNPCs = {},
		Connections = {},
	},
	Config = {
		DISTANCE = 10.5,
		VERTICAL_OFFSET = 0,
	},
}
function Modules.NPCShield:Stop()
	self.State.IsEnabled = false
	for _, connection in pairs(self.State.Connections) do
		if connection then
			connection:Disconnect()
		end
	end
	self.State.Connections = {}
	self.State.TrackedNPCs = {}
end
function Modules.NPCShield:_isValidNPC(model)
	if not model or not model.Parent then
		return false
	end
	for _, plr in ipairs(Players:GetPlayers()) do
		if plr.Character == model then
			return false
		end
	end
	return model:FindFirstChild("HumanoidRootPart") ~= nil
end
function Modules.NPCShield:_setupNPCBring(model)
	local tRoot = model:FindFirstChild("HumanoidRootPart")
	if not tRoot then
		return
	end
	local connectionId = "Bring_NPC_" .. model:GetDebugId()
	if self.State.Connections[connectionId] then
		self.State.Connections[connectionId]:Disconnect()
	end
	local connection = RunService.Heartbeat:Connect(function()
		local myChar = Players.LocalPlayer.Character
		local myRoot = myChar and myChar:FindFirstChild("HumanoidRootPart")
		if not self.State.TrackedNPCs[model] then
			if self.State.Connections[connectionId] then
				self.State.Connections[connectionId]:Disconnect()
				self.State.Connections[connectionId] = nil
			end
			return
		end
		if not tRoot.Parent then
			self:_watchForRespawn(model, connectionId)
			return
		end
		if not myRoot then
			return
		end
		tRoot.Velocity = Vector3.new(0, 30.01, 0)
		tRoot.CFrame = myRoot.CFrame * CFrame.new(0, self.Config.VERTICAL_OFFSET, -self.Config.DISTANCE)
	end)
	self.State.Connections[connectionId] = connection
end
function Modules.NPCShield:_watchForRespawn(model, connectionId)
	if self.State.Connections[connectionId] then
		self.State.Connections[connectionId]:Disconnect()
		self.State.Connections[connectionId] = nil
	end
	local watchId = "Watch_" .. connectionId
	local elapsed = 0
	self.State.Connections[watchId] = RunService.Heartbeat:Connect(function(dt)
		elapsed = elapsed + dt
		if not self.State.TrackedNPCs[model] then
			self.State.Connections[watchId]:Disconnect()
			self.State.Connections[watchId] = nil
			return
		end
		if elapsed > 30 then
			self.State.Connections[watchId]:Disconnect()
			self.State.Connections[watchId] = nil
			return
		end
		local hrp = model:FindFirstChild("HumanoidRootPart")
		local humanoid = model:FindFirstChildOfClass("Humanoid")
		if hrp and humanoid and humanoid.Health > 0 then
			self.State.Connections[watchId]:Disconnect()
			self.State.Connections[watchId] = nil
			task.wait(0.1)
			if self.State.TrackedNPCs[model] and self.State.IsEnabled then
				self:_setupNPCBring(model)
				DoNotif(model.Name .. " respawned - re-bringing", 1.5)
			end
		end
	end)
end
function Modules.NPCShield:_trackNPC(model)
	if self.State.TrackedNPCs[model] then
		return
	end
	self.State.TrackedNPCs[model] = true
	self:_setupNPCBring(model)
end
function Modules.NPCShield:_untrackNPC(model)
	self.State.TrackedNPCs[model] = nil
	local connectionId = "Bring_NPC_" .. model:GetDebugId()
	if self.State.Connections[connectionId] then
		self.State.Connections[connectionId]:Disconnect()
		self.State.Connections[connectionId] = nil
	end
	local watchId = "Watch_" .. connectionId
	if self.State.Connections[watchId] then
		self.State.Connections[watchId]:Disconnect()
		self.State.Connections[watchId] = nil
	end
end
function Modules.NPCShield:_gatherNPCs()
	local found = {}
	for _, descendant in ipairs(Workspace:GetDescendants()) do
		if descendant:IsA("Model") and self:_isValidNPC(descendant) then
			local humanoid = descendant:FindFirstChildOfClass("Humanoid")
			if humanoid and humanoid.Health > 0 then
				table.insert(found, descendant)
			end
		end
	end
	return found
end
function Modules.NPCShield:PossessAll()
	if self.State.IsEnabled then
		self:Stop()
	end
	local myChar = Players.LocalPlayer.Character
	if not myChar or not myChar:FindFirstChild("HumanoidRootPart") then
		return DoNotif("Your character not found.", 2)
	end
	local npcs = self:_gatherNPCs()
	if #npcs == 0 then
		return DoNotif("No valid NPCs found in workspace.", 2)
	end
	self.State.IsEnabled = true
	for _, model in ipairs(npcs) do
		self:_trackNPC(model)
	end
	self.State.Connections.DescendantAdded = Workspace.DescendantAdded:Connect(function(descendant)
		if not self.State.IsEnabled then
			return
		end
		task.defer(function()
			if descendant:IsA("Model") and self:_isValidNPC(descendant) and not self.State.TrackedNPCs[descendant] then
				self:_trackNPC(descendant)
				DoNotif("New NPC detected - bringing " .. descendant.Name, 1.5)
			end
		end)
	end)
	DoNotif("NPC Shield Active: " .. #npcs .. " NPC(s)", 2)
end
function Modules.NPCShield:Possess(targetName)
	local found = nil
	local lower = targetName:lower()
	for _, descendant in ipairs(Workspace:GetDescendants()) do
		if descendant:IsA("Model") and self:_isValidNPC(descendant) then
			if descendant.Name:lower():find(lower) then
				found = descendant
				break
			end
		end
	end
	if not found then
		return DoNotif("NPC '" .. targetName .. "' not found.", 2)
	end
	if self.State.IsEnabled then
		self:Stop()
	end
	self.State.IsEnabled = true
	self:_trackNPC(found)
	DoNotif("NPC Shield Active: " .. found.Name .. " (persistent)", 2)
end
function Modules.NPCShield:Initialize()
	local module = self
	RegisterCommand({
		Name = "npcbring",
		Aliases = { "nb", "npcshield" },
		Description = "Brings NPC(s) in front of you persistently. Use 'all' or an NPC name.",
	}, function(args)
		if module.State.IsEnabled then
			module:Stop()
			DoNotif("NPC Shield Released.", 2)
		else
			if #args > 0 then
				if args[1]:lower() == "all" then
					module:PossessAll()
				else
					module:Possess(args[1])
				end
			else
				DoNotif("Usage: ;npcbring [npcname/all]", 3)
			end
		end
	end)
	RegisterCommand({
		Name = "npcrelease",
		Aliases = { "nr" },
		Description = "Releases a specific NPC from the shield.",
	}, function(args)
		if not module.State.IsEnabled then
			return DoNotif("NPC Shield is not active.", 2)
		end
		if not args[1] then
			return DoNotif("Usage: ;npcrelease [npcname]", 3)
		end
		local lower = args[1]:lower()
		local target = nil
		for model in pairs(module.State.TrackedNPCs) do
			if model and model.Parent and model.Name:lower():find(lower) then
				target = model
				break
			end
		end
		if not target then
			return DoNotif("NPC not found in shield list.", 2)
		end
		module:_untrackNPC(target)
		DoNotif("Released: " .. target.Name, 2)
	end)
	RegisterCommand({
		Name = "npclist",
		Aliases = {},
		Description = "Lists all NPCs currently being brought.",
	}, function()
		if not module.State.IsEnabled then
			return DoNotif("NPC Shield is not active.", 2)
		end
		local count = 0
		print("=== Brought NPCs ===")
		for model in pairs(module.State.TrackedNPCs) do
			if model and model.Parent then
				print("  • " .. model.Name)
				count = count + 1
			end
		end
		print("====================")
		DoNotif("Bringing " .. count .. " NPC(s). Check console (F9)", 2)
	end)
end
Modules.NPCDmgNeutralizer = {
	State = {
		IsEnabled = false,
		Neutralized = {},
		Connections = {},
	},
	Config = {
		DESTROY_DAMAGE_PARTS = false,
		RESCAN_INTERVAL = 1.5,
		STRIP_BODY_TOUCHED = true,
		DAMAGE_PART_NAMES = {
			"damage",
			"hitbox",
			"hit",
			"hurtbox",
			"attack",
			"punch",
			"slash",
			"sword",
			"blade",
			"weapon",
			"hurt",
			"melee",
			"fist",
			"claw",
			"bite",
		},
		BODY_PART_NAMES = {
			"HumanoidRootPart",
			"Torso",
			"UpperTorso",
			"LowerTorso",
			"LeftArm",
			"RightArm",
			"LeftUpperArm",
			"RightUpperArm",
			"LeftLowerArm",
			"RightLowerArm",
			"LeftHand",
			"RightHand",
			"Head",
		},
	},
}
function Modules.NPCDmgNeutralizer:_isValidNPC(model)
	if not model or not model.Parent then
		return false
	end
	if model == LocalPlayer.Character then
		return false
	end
	for _, plr in ipairs(Players:GetPlayers()) do
		if plr.Character == model then
			return false
		end
	end
	return model:FindFirstChild("HumanoidRootPart") ~= nil
end
function Modules.NPCDmgNeutralizer:_isDamagePart(part)
	if not part:IsA("BasePart") then
		return false
	end
	local n = part.Name:lower()
	for _, kw in ipairs(self.Config.DAMAGE_PART_NAMES) do
		if n:find(kw, 1, true) then
			return true
		end
	end
	return false
end
function Modules.NPCDmgNeutralizer:_isBodyPart(part)
	if not part:IsA("BasePart") then
		return false
	end
	if #self.Config.BODY_PART_NAMES == 0 then
		return true
	end
	for _, name in ipairs(self.Config.BODY_PART_NAMES) do
		if part.Name == name then
			return true
		end
	end
	return false
end
function Modules.NPCDmgNeutralizer:_stripTouched(part)
	local count = 0
	if getconnections then
		for _, signal in ipairs({ part.Touched, part.TouchEnded }) do
			local ok, conns = pcall(getconnections, signal)
			if ok and conns then
				for _, conn in ipairs(conns) do
					pcall(function()
						conn:Disable()
						count = count + 1
					end)
				end
			end
		end
	end
	pcall(function()
		part.CanTouch = false
	end)
	return count
end
function Modules.NPCDmgNeutralizer:_neutralize(model)
	if not self:_isValidNPC(model) then
		return
	end
	for _, desc in ipairs(model:GetDescendants()) do
		if self:_isDamagePart(desc) then
			if self.Config.DESTROY_DAMAGE_PARTS then
				pcall(function()
					desc:Destroy()
				end)
			else
				self:_stripTouched(desc)
			end
		elseif self.Config.STRIP_BODY_TOUCHED and self:_isBodyPart(desc) then
			self:_stripTouched(desc)
		end
	end
	model.DescendantAdded:Connect(function(desc)
		if not self.State.IsEnabled then
			return
		end
		task.defer(function()
			if self:_isDamagePart(desc) then
				if self.Config.DESTROY_DAMAGE_PARTS then
					pcall(function()
						desc:Destroy()
					end)
				else
					self:_stripTouched(desc)
				end
			elseif self.Config.STRIP_BODY_TOUCHED and self:_isBodyPart(desc) then
				self:_stripTouched(desc)
			end
		end)
	end)
	self.State.Neutralized[model] = true
end
function Modules.NPCDmgNeutralizer:_scanAll()
	for _, desc in ipairs(Workspace:GetDescendants()) do
		if desc:IsA("Model") and not self.State.Neutralized[desc] and self:_isValidNPC(desc) then
			self:_neutralize(desc)
		end
	end
end
function Modules.NPCDmgNeutralizer:Enable()
	if self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = true
	self.State.Neutralized = {}
	self:_scanAll()
	self.State.Connections.Added = Workspace.DescendantAdded:Connect(function(desc)
		if not self.State.IsEnabled then
			return
		end
		task.defer(function()
			if desc:IsA("Model") and not self.State.Neutralized[desc] and self:_isValidNPC(desc) then
				self:_neutralize(desc)
			end
		end)
	end)
	self.State.Connections.Removing = Workspace.DescendantRemoving:Connect(function(desc)
		if desc:IsA("Model") then
			self.State.Neutralized[desc] = nil
		end
	end)
	task.spawn(function()
		while self.State.IsEnabled do
			task.wait(self.Config.RESCAN_INTERVAL)
			if self.State.IsEnabled then
				self:_scanAll()
			end
		end
	end)
	DoNotif("NPC Dmg Neutralizer: Enabled", 2)
end
function Modules.NPCDmgNeutralizer:Disable()
	if not self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = false
	for _, conn in pairs(self.State.Connections) do
		pcall(function()
			conn:Disconnect()
		end)
	end
	self.State.Connections = {}
	DoNotif("NPC Dmg Neutralizer: Disabled (existing strips remain)", 2)
end
function Modules.NPCDmgNeutralizer:Toggle()
	if self.State.IsEnabled then
		self:Disable()
	else
		self:Enable()
	end
end
function Modules.NPCDmgNeutralizer:Initialize()
	local module = self
	RegisterCommand({
		Name = "npcneutralize",
		Aliases = { "nn", "nodmg", "npcgod" },
		Description = "Strips Touched damage connections from all NPC hitbox/body parts.",
	}, function()
		module:Toggle()
	end)
	RegisterCommand({
		Name = "npcdestroyparts",
		Aliases = { "ndp" },
		Description = "Toggles whether DamageParts are destroyed entirely vs just disconnected.",
	}, function()
		module.Config.DESTROY_DAMAGE_PARTS = not module.Config.DESTROY_DAMAGE_PARTS
		DoNotif("Destroy DamageParts: " .. (module.Config.DESTROY_DAMAGE_PARTS and "ON" or "OFF"), 2)
	end)
end
RegisterCommand({
	Name = "partcontrol",
	Aliases = { "partc" },
	Description = "no problem.",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	local CONFIG = {
		ORBIT_RADIUS = 7,
		ORBIT_SPEED = 10,
		VORTEX_HEIGHT = 2.5,
		PART_CAP = 150,
		SCAN_RADIUS = 150,
		FLING_FORCE = 1000000,
		SIM_RADIUS = 1e9,
	}
	local SessionState = {
		Active = false,
		ManagedParts = {},
		Angle = 0,
		MainConnection = nil,
		IsSweeping = false,
	}
	local function GetSafeParent()
		local success, parent = pcall(function()
			return gethui() or CoreGui or LocalPlayer:FindFirstChildOfClass("PlayerGui")
		end)
		return success and parent or nil
	end
	local function SetHiddenProperty(instance, property, value)
		pcall(function()
			if sethiddenproperty then
				sethiddenproperty(instance, property, value)
			end
		end)
	end
	local function ToggleCharacterCollision(state)
		local char = LocalPlayer.Character
		if not char then
			return
		end
		for _, part in ipairs(char:GetDescendants()) do
			if part:IsA("BasePart") then
				part.CanCollide = state
			end
		end
	end
	local function CollectParts()
		local char = LocalPlayer.Character
		local hrp = char and char:FindFirstChild("HumanoidRootPart")
		if not hrp then
			return {}
		end
		local collected = {}
		local count = 0
		for _, v in ipairs(Workspace:GetDescendants()) do
			if count >= CONFIG.PART_CAP then
				break
			end
			if v:IsA("BasePart") and not v.Anchored and not v:IsDescendantOf(char) then
				if not v.Parent:FindFirstChildOfClass("Humanoid") then
					local dist = (v.Position - hrp.Position).Magnitude
					if dist < CONFIG.SCAN_RADIUS then
						table.insert(collected, v)
						count = count + 1
					end
				end
			end
		end
		return collected
	end
	local function StartPhysicsEngine()
		if SessionState.MainConnection then
			SessionState.MainConnection:Disconnect()
		end
		SessionState.MainConnection = RunService.Heartbeat:Connect(function(dt)
			if not SessionState.Active then
				SessionState.MainConnection:Disconnect()
				return
			end
			local char = LocalPlayer.Character
			local hrp = char and char:FindFirstChild("HumanoidRootPart")
			if not hrp then
				return
			end
			SessionState.Angle = SessionState.Angle + (dt * CONFIG.ORBIT_SPEED)
			ToggleCharacterCollision(false)
			for part, data in pairs(SessionState.ManagedParts) do
				if not part.Parent or part.Anchored then
					pcall(function()
						data.Vel:Destroy()
					end)
					pcall(function()
						data.Spin:Destroy()
					end)
					SessionState.ManagedParts[part] = nil
					continue
				end
				pcall(function()
					part:SetNetworkOwner(LocalPlayer)
				end)
				local s = data.Seed
				local offset = Vector3.new(
					math.cos(SessionState.Angle + s) * CONFIG.ORBIT_RADIUS,
					math.sin(SessionState.Angle * 0.5 + s) * CONFIG.VORTEX_HEIGHT,
					math.sin(SessionState.Angle + s) * CONFIG.ORBIT_RADIUS
				)
				data.Vel.Velocity = ((hrp.Position + offset) - part.Position) * 20
			end
		end)
	end
	local function ToggleState(enabled)
		SessionState.Active = enabled
		if enabled then
			local targetParts = CollectParts()
			for _, part in ipairs(targetParts) do
				local bv = Instance.new("BodyVelocity")
				bv.MaxForce = Vector3.new(1, 1, 1) * math.huge
				bv.Parent = part
				local bav = Instance.new("BodyAngularVelocity")
				bav.MaxTorque = Vector3.new(1, 1, 1) * math.huge
				bav.AngularVelocity = Vector3.new(0, CONFIG.FLING_FORCE, 0)
				bav.Parent = part
				SessionState.ManagedParts[part] = {
					Vel = bv,
					Spin = bav,
					Seed = math.random(1, 100),
				}
			end
			StartPhysicsEngine()
		else
			for part, data in pairs(SessionState.ManagedParts) do
				pcall(function()
					data.Vel:Destroy()
				end)
				pcall(function()
					data.Spin:Destroy()
				end)
			end
			SessionState.ManagedParts = {}
			ToggleCharacterCollision(true)
		end
	end
	local function ConstructUI()
		local parent = GetSafeParent()
		if not parent then
			return
		end
		local Screen = Instance.new("ScreenGui")
		Screen.Name = "ArchitectVortex_v4_2"
		Screen.Parent = parent
		local Main = Instance.new("Frame")
		Main.Size = UDim2.fromOffset(200, 80)
		Main.Position = UDim2.new(0.5, -100, 0.1, 0)
		Main.BackgroundColor3 = Color3.fromRGB(15, 15, 20)
		Main.Parent = Screen
		Instance.new("UICorner", Main).CornerRadius = UDim.new(0, 4)
		local s = Instance.new("UIStroke", Main)
		s.Color = Color3.fromRGB(0, 255, 170)
		s.Thickness = 1.5
		local ActionBtn = Instance.new("TextButton", Main)
		ActionBtn.Size = UDim2.new(0.9, 0, 0.6, 0)
		ActionBtn.Position = UDim2.new(0.05, 0, 0.2, 0)
		ActionBtn.BackgroundColor3 = Color3.fromRGB(25, 25, 30)
		ActionBtn.Text = "INITIATE VORTEX"
		ActionBtn.TextColor3 = Color3.fromRGB(200, 200, 200)
		ActionBtn.Font = Enum.Font.Code
		ActionBtn.TextSize = 14
		ActionBtn.Parent = Main
		Instance.new("UICorner", ActionBtn)
		ActionBtn.MouseButton1Click:Connect(function()
			if not SessionState.Active then
				ActionBtn.Text = "SHIELD ACTIVE"
				ActionBtn.TextColor3 = Color3.fromRGB(0, 255, 170)
				ToggleState(true)
			else
				ActionBtn.Text = "INITIATE VORTEX"
				ActionBtn.TextColor3 = Color3.fromRGB(200, 200, 200)
				ToggleState(false)
			end
		end)
	end
	task.spawn(function()
		while true do
			SetHiddenProperty(LocalPlayer, "SimulationRadius", CONFIG.SIM_RADIUS)
			task.wait(1)
		end
	end)
	ConstructUI()
end)
Modules.VelocitySpoofer = {
	State = {
		IsEnabled = false,
		RootPart = nil,
		Connections = {},
		Applying = false,
	},
	Config = {
		PoisonVector = Vector3.new(0, -20000, 0),
		PoisonJitter = 120,
		DisableRagdoll = true,
		DisableFallingDown = true,
		RagdollCheckInterval = 0.5,
		StripConstraints = true,
	},
}
function Modules.VelocitySpoofer:_getPoisonVector()
	local cfg = self.Config
	local base = cfg.PoisonVector
	local j = cfg.PoisonJitter
	return Vector3.new(base.X + math.random(-j, j), base.Y, base.Z + math.random(-j, j))
end
function Modules.VelocitySpoofer:_stripAttachedConstraints()
	local hrp = self.State.RootPart
	if not hrp then
		return
	end
	pcall(function()
		for _, c in ipairs(hrp:GetChildren()) do
			if
				c:IsA("LinearVelocity")
				or c:IsA("VectorForce")
				or c:IsA("BodyVelocity")
				or c:IsA("BodyForce")
				or c:IsA("AlignPosition")
				or c:IsA("RocketPropulsion")
			then
				c:Destroy()
			end
		end
		for _, c in ipairs(hrp:GetChildren()) do
			if c:IsA("Attachment") then
				for _, constraint in ipairs(c:GetChildren()) do
					if constraint:IsA("AlignPosition") or constraint:IsA("LinearVelocity") then
						constraint:Destroy()
					end
				end
			end
		end
	end)
end
function Modules.VelocitySpoofer:_applyVelocityChanger()
	if self.Applying then
		return
	end
	local hrp = self.State.RootPart
	if not hrp or not self.State.IsEnabled then
		return
	end
	self.Applying = true
	pcall(function()
		if self.Config.StripConstraints then
			self:_stripAttachedConstraints()
		end
		local real = hrp.AssemblyLinearVelocity
		hrp.AssemblyLinearVelocity = self:_getPoisonVector()
		RunService.RenderStepped:Wait()
		if hrp and hrp.Parent then
			hrp.AssemblyLinearVelocity = real
		end
	end)
	self.Applying = false
end
function Modules.VelocitySpoofer:_disableRagdollStates()
	local conn
	conn = RunService.Heartbeat:Connect(function()
		if not self.State.IsEnabled then
			conn:Disconnect()
			return
		end
		local char = LocalPlayer.Character
		if not char then
			return
		end
		local humanoid = char:FindFirstChildOfClass("Humanoid")
		if not humanoid then
			return
		end
		if self.Config.DisableFallingDown then
			humanoid:SetStateEnabled(Enum.HumanoidStateType.FallingDown, false)
		end
		if self.Config.DisableRagdoll then
			humanoid:SetStateEnabled(Enum.HumanoidStateType.Ragdoll, false)
		end
	end)
	self.State.Connections.RagdollGuard = conn
end
function Modules.VelocitySpoofer:_updateRootPart()
	if LocalPlayer.Character then
		self.State.RootPart = LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
	end
end
function Modules.VelocitySpoofer:Enable()
	if self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = true
	self.Applying = false
	self:_updateRootPart()
	self.State.Connections.Heartbeat = RunService.Heartbeat:Connect(function()
		if not self.State.RootPart and LocalPlayer.Character then
			self:_updateRootPart()
		end
		if self.State.RootPart and self.State.IsEnabled then
			self:_applyVelocityChanger()
		end
	end)
	self.State.Connections.CharacterAdded = LocalPlayer.CharacterAdded:Connect(function()
		task.wait(0.1)
		self:_updateRootPart()
	end)
	self:_disableRagdollStates()
	DoNotif("Velocity Spoofer: ENABLED", 2)
end
function Modules.VelocitySpoofer:Disable()
	if not self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = false
	self.Applying = false
	for _, conn in pairs(self.State.Connections) do
		if conn then
			conn:Disconnect()
		end
	end
	self.State.Connections = {}
	local char = LocalPlayer.Character
	if char then
		local humanoid = char:FindFirstChildOfClass("Humanoid")
		if humanoid then
			humanoid:SetStateEnabled(Enum.HumanoidStateType.FallingDown, true)
			humanoid:SetStateEnabled(Enum.HumanoidStateType.Ragdoll, true)
		end
	end
	self.State.RootPart = nil
	DoNotif("Velocity Spoofer: DISABLED", 2)
end
function Modules.VelocitySpoofer:Toggle()
	if self.State.IsEnabled then
		self:Disable()
	else
		self:Enable()
	end
end
function Modules.VelocitySpoofer:SetPoisonVector(x, y, z)
	self.Config.PoisonVector = Vector3.new(tonumber(x) or 0, tonumber(y) or -10000, tonumber(z) or 0)
	local v = self.Config.PoisonVector
	DoNotif(("Poison Vector: (%.0f, %.0f, %.0f)"):format(v.X, v.Y, v.Z), 2)
end
function Modules.VelocitySpoofer:SetJitter(amount)
	self.Config.PoisonJitter = tonumber(amount) or 120
	DoNotif(("Jitter: ±%d"):format(self.Config.PoisonJitter), 2)
end
function Modules.VelocitySpoofer:ToggleRagdoll()
	self.Config.DisableRagdoll = not self.Config.DisableRagdoll
	DoNotif("Ragdoll Prevention: " .. (self.Config.DisableRagdoll and "ON" or "OFF"), 2)
end
function Modules.VelocitySpoofer:ToggleFallingDown()
	self.Config.DisableFallingDown = not self.Config.DisableFallingDown
	DoNotif("Falling Prevention: " .. (self.Config.DisableFallingDown and "ON" or "OFF"), 2)
end
function Modules.VelocitySpoofer:ToggleConstraintStripping()
	self.Config.StripConstraints = not self.Config.StripConstraints
	DoNotif("Constraint Stripping: " .. (self.Config.StripConstraints and "ON" or "OFF"), 2)
end
function Modules.VelocitySpoofer:Initialize()
	local module = self
	RegisterCommand({
		Name = "velocityspoof",
		Aliases = { "vspoof" },
		Description = "Spoofs velocity to counter aimbot attachment/network kicks.",
	}, function()
		module:Toggle()
	end)
	RegisterCommand({
		Name = "poisonvector",
		Aliases = { "setvector", "spoofvector" },
		Description = "Set the spoof vector. Usage: ;poisonvector <x> <y> <z>",
	}, function(args)
		if #args < 3 then
			local v = module.Config.PoisonVector
			DoNotif(("Current: (%.0f, %.0f, %.0f)"):format(v.X, v.Y, v.Z), 3)
			DoNotif("Usage: ;poisonvector <x> <y> <z>", 2)
			return
		end
		module:SetPoisonVector(args[1], args[2], args[3])
	end)
	RegisterCommand({
		Name = "spooferjitter",
		Aliases = { "vjitter" },
		Description = "Set XZ jitter amount for spoof pattern randomization.",
	}, function(args)
		module:SetJitter(args[1])
	end)
	RegisterCommand({
		Name = "stripconstraints",
		Aliases = { "stripvc" },
		Description = "Toggle automatic removal of LinearVelocity/force constraints.",
	}, function()
		module:ToggleConstraintStripping()
	end)
end
RegisterCommand({
	Name = "antiragdoll2",
	Aliases = {},
	Description = "Toggle ragdoll prevention.",
}, function()
	module:ToggleRagdoll()
end)
RegisterCommand({
	Name = "antifall",
	Aliases = { "nofall" },
	Description = "Toggle falling down state prevention.",
}, function()
	module:ToggleFallingDown()
end)
RegisterCommand({
	Name = "veloptions",
	Aliases = { "vspoofinfo" },
	Description = "Shows current velocity spoofer settings.",
}, function()
	print("=== Velocity Spoofer Settings ===")
	print("Status:", module.State.IsEnabled and "ENABLED" or "DISABLED")
