			module.Config.PoisonVector.X,
			module.Config.PoisonVector.Y,
			module.Config.PoisonVector.Z
		)
	)
	print("Anti-Ragdoll:", module.Config.DisableRagdoll and "ON" or "OFF")
	print("Anti-Fall:", module.Config.DisableFallingDown and "ON" or "OFF")
end)
RegisterCommand({
	Name = "raknet",
	Aliases = { "rsync" },
	Description = "raknet desync mines still better",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	local uis = game:GetService("UserInputService")
	local players = game:GetService("Players")
	local rs = game:GetService("RunService")
	local lp = players.LocalPlayer
	local hooked = false
	local toggle = Enum.KeyCode.End
	local ghostModel = nil
	local groundParts = {}
	local attachments = {}
	local vfxConn = nil

	local PI2 = math.pi * 2
	local OUTER_RADIUS = 3.2
	local INNER_RADIUS = 1.8
	local OUTER_SPEED = 2.5
	local INNER_SPEED = -3.5
	local GROUND_OFFSET = 3.1
	local SPARK_INTERVAL = 0.05

	local lightningColor = ColorSequence.new({
		ColorSequenceKeypoint.new(0, Color3.fromRGB(255, 255, 255)),
		ColorSequenceKeypoint.new(0.5, Color3.fromRGB(100, 180, 255)),
		ColorSequenceKeypoint.new(1, Color3.fromRGB(0, 40, 200)),
	})

	local sparkSize = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.18),
		NumberSequenceKeypoint.new(0.5, 0.08),
		NumberSequenceKeypoint.new(1, 0),
	})

	local ringSizeOuter = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.1),
		NumberSequenceKeypoint.new(1, 0),
	})

	local ringSizeInner = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.07),
		NumberSequenceKeypoint.new(1, 0),
	})

	local function removeGhost()
		if vfxConn then
			vfxConn:Disconnect()
			vfxConn = nil
		end
		for _, p in ipairs(groundParts) do
			if p.dot and p.dot.Parent then
				p.dot:Destroy()
			end
		end
		groundParts = {}
		attachments = {}
		if ghostModel then
			ghostModel:Destroy()
			ghostModel = nil
		end
	end

	local function rakhook(packet)
		if packet.PacketId == 0x1B then
			local buf = packet.AsBuffer
			buffer.writeu32(buf, 1, 0xFFFFFFFF)
			packet:SetData(buf)
		end
	end

	local function makeSparks(parent)
		local att = Instance.new("Attachment")
		att.Parent = parent
		local sparks = Instance.new("ParticleEmitter")
		sparks.Color = lightningColor
		sparks.LightEmission = 1
		sparks.LightInfluence = 0
		sparks.Size = sparkSize
		sparks.Lifetime = NumberRange.new(0.1, 0.3)
		sparks.Rate = 0
		sparks.Speed = NumberRange.new(5, 20)
		sparks.SpreadAngle = Vector2.new(180, 180)
		sparks.RotSpeed = NumberRange.new(-360, 360)
		sparks.Rotation = NumberRange.new(0, 360)
		sparks.Parent = att
		return att
	end

	local function makeRingDot(px, py, pz, sz, col, sparksSize)
		local dot = Instance.new("Part")
		dot.Anchored = true
		dot.CanCollide = false
		dot.CanTouch = false
		dot.CanQuery = false
		dot.CastShadow = false
		dot.Size = Vector3.new(sz, sz, sz)
		dot.Shape = Enum.PartType.Ball
		dot.Material = Enum.Material.Neon
		dot.Color = col
		dot.Transparency = 0
		dot.CFrame = CFrame.new(px, py, pz)
		dot.Parent = workspace
		local att = Instance.new("Attachment")
		att.Parent = dot
		local em = Instance.new("ParticleEmitter")
		em.Color = lightningColor
		em.LightEmission = 1
		em.LightInfluence = 0
		em.Size = sparksSize
		em.Lifetime = NumberRange.new(0.1, 0.2)
		em.Rate = 10
		em.Speed = NumberRange.new(1, 5)
		em.SpreadAngle = Vector2.new(180, 180)
		em.Parent = att
		return dot
	end

	local function createGhost(pos)
		removeGhost()

		local char = lp.Character
		if not char then
			return
		end
		local hrp = char:FindFirstChild("HumanoidRootPart")
		if not hrp then
			return
		end

		local offset = pos - hrp.Position

		char.Archivable = true
		local ghost = char:Clone()
		char.Archivable = false
		if not ghost then
			return
		end

		ghost.Name = "GhostMarker"

		for _, v in ipairs(ghost:GetDescendants()) do
			pcall(function()
				if
					v:IsA("Script")
					or v:IsA("LocalScript")
					or v:IsA("ModuleScript")
					or v:IsA("Animator")
					or v:IsA("AnimationController")
				then
					v:Destroy()
				end
			end)
		end

		local hum = ghost:FindFirstChildOfClass("Humanoid")
		if hum then
			hum:Destroy()
		end

		for _, v in ipairs(ghost:GetDescendants()) do
			pcall(function()
				if v:IsA("BasePart") then
					v.Anchored = true
					v.CanCollide = false
					v.CanTouch = false
					v.CanQuery = false
					v.CastShadow = false
					v.Transparency = 0
					v.Material = Enum.Material.SmoothPlastic
					v.Color = Color3.fromRGB(0, 20, 80)
					v.CFrame = v.CFrame + offset
					if v.Name ~= "HumanoidRootPart" then
						for e = 1, 3 do
							local att = makeSparks(v)
							table.insert(attachments, att)
						end
					end
				end
			end)
		end

		local ghostHRP = ghost:FindFirstChild("HumanoidRootPart")
		if ghostHRP then
			ghostHRP.Transparency = 1
			ghostHRP.CFrame = CFrame.new(pos) * (hrp.CFrame - hrp.CFrame.Position)
		end

		local hl = Instance.new("Highlight")
		hl.FillColor = Color3.fromRGB(0, 60, 180)
		hl.FillTransparency = 0
		hl.OutlineColor = Color3.fromRGB(0, 120, 255)
		hl.OutlineTransparency = 0
		hl.DepthMode = Enum.HighlightDepthMode.AlwaysOnTop
		hl.Adornee = ghost
		hl.Parent = ghost

		ghost.Parent = workspace
		ghostModel = ghost

		for _, v in ipairs(ghost:GetDescendants()) do
			if v:IsA("BasePart") then
				v.CanCollide = false
				v.CanTouch = false
				v.CanQuery = false
			end
		end
		for _, v in ipairs(ghost:GetChildren()) do
			if v:IsA("BasePart") then
				v.CanCollide = false
				v.CanTouch = false
				v.CanQuery = false
			end
		end

		local rCount = 32
		local iCount = 20
		local gy = pos.Y - GROUND_OFFSET
		local outerCol = Color3.fromRGB(0, 100, 255)
		local innerCol = Color3.fromRGB(150, 210, 255)

		for i = 1, rCount do
			local a = (i / rCount) * PI2
			local dot = makeRingDot(
				pos.X + math.cos(a) * OUTER_RADIUS,
				gy,
				pos.Z + math.sin(a) * OUTER_RADIUS,
				0.25,
				outerCol,
				ringSizeOuter
			)
			table.insert(groundParts, { dot = dot, baseAngle = a, isOuter = true })
		end

		for i = 1, iCount do
			local a = (i / iCount) * PI2
			local dot = makeRingDot(
				pos.X + math.cos(a) * INNER_RADIUS,
				gy,
				pos.Z + math.sin(a) * INNER_RADIUS,
				0.15,
				innerCol,
				ringSizeInner
			)
			table.insert(groundParts, { dot = dot, baseAngle = a, isOuter = false })
		end

		local sparkTimer = 0

		vfxConn = rs.Heartbeat:Connect(function(dt)
			if not ghostModel or not ghostModel.Parent then
				return
			end
			local t = tick()
			local pulse = math.abs(math.sin(t * 2))
			local fillG = math.floor(40 + pulse * 30)
			local fillB = math.floor(160 + pulse * 60)
			local outG = math.floor(100 + pulse * 60)

			hl.FillColor = Color3.fromRGB(0, fillG, fillB)
			hl.OutlineColor = Color3.fromRGB(0, outG, 255)
			hl.OutlineTransparency = pulse * 0.3

			for _, entry in ipairs(groundParts) do
				if entry.dot and entry.dot.Parent then
					local radius = entry.isOuter and OUTER_RADIUS or INNER_RADIUS
					local speed = entry.isOuter and OUTER_SPEED or INNER_SPEED
					local a = entry.baseAngle + t * speed
					local wave = math.abs(math.sin(t * 5 + entry.baseAngle)) * 0.2
					local bright = math.abs(math.sin(t * 6 + entry.baseAngle)) * 0.4
					entry.dot.CFrame = CFrame.new(pos.X + math.cos(a) * radius, gy + wave, pos.Z + math.sin(a) * radius)
					entry.dot.Transparency = bright
					if entry.isOuter then
						local r = math.floor(80 + pulse * 60)
						entry.dot.Color = Color3.fromRGB(0, r, 255)
					else
						local r = math.floor(120 + pulse * 60)
						local g = math.floor(180 + pulse * 40)
						entry.dot.Color = Color3.fromRGB(r, g, 255)
					end
				end
			end

			sparkTimer = sparkTimer + dt
			if sparkTimer >= SPARK_INTERVAL then
				sparkTimer = 0
				local numAtts = #attachments
				if numAtts > 0 then
					local bursts = math.random(2, 5)
					for b = 1, bursts do
						local pick = attachments[math.random(1, numAtts)]
						if pick and pick.Parent then
							local emitter = pick:FindFirstChildOfClass("ParticleEmitter")
							if emitter then
								emitter:Emit(math.random(8, 25))
							end
						end
					end
				end
				for _, v in ipairs(ghostModel:GetDescendants()) do
					if v:IsA("BasePart") then
						v.CanCollide = false
						v.CanTouch = false
						v.CanQuery = false
						v.Anchored = true
					end
				end
			end
		end)
	end

	uis.InputBegan:Connect(function(obj)
		if obj.KeyCode ~= toggle then
			return
		end
		if hooked then
			raknet.remove_send_hook(rakhook)
			removeGhost()
		else
			local char = lp.Character
			if not char then
				return
			end
			local hrp = char:FindFirstChild("HumanoidRootPart")
			if not hrp then
				return
			end
			createGhost(hrp.Position)
			raknet.add_send_hook(rakhook)
		end
		hooked = not hooked
	end)
end)
RegisterCommand({
	Name = "netenforcer",
	Aliases = { "net2" },
	Description = "no problem.",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	if not getgenv().Network then
		getgenv().Network = {
			BaseParts = {},
			FakeConnections = {},
			Connections = {},
			Output = {
				Enabled = true,
				Prefix = "[NETWORK] ",
				Send = function(Type, Output, BypassOutput)
					if
						typeof(Type) == "function"
						and (Type == print or Type == warn or Type == error)
						and typeof(Output) == "string"
						and (typeof(BypassOutput) == "nil" or typeof(BypassOutput) == "boolean")
					then
						if Network["Output"].Enabled or BypassOutput then
							Type(Network["Output"].Prefix .. Output)
						end
					elseif Network["Output"].Enabled then
						error(Network["Output"].Prefix .. "Output Send Error : Invalid syntax.")
					end
				end,
			},
			LostParts = {},
			CharacterRelative = true,
			LastCharacter = nil,
			TryKeep = true,
			PartOwnership = {
				PreMethodSettings = {},
				Enabled = false,
			},
		}
		Network["Output"].Send(print, ": Loading.")
		Network["RetainPart"] = function(Part, Silent, ReturnFakePart)
			assert(
				Network["PartOwnership"]["Enabled"],
				Network["Output"].Prefix .. " RetainPart Error : PartOwnership is Disabled."
			)
			assert(
				typeof(Part) == "Instance" and Part:IsA("BasePart") and not Part:IsGrounded(),
				Network["Output"].Prefix
					.. "RetainPart Error : Invalid syntax: Arg1 (Part) must be an ungrounded BasePart which is a descendant of workspace."
			)
			if not Part:IsDescendantOf(workspace) then
				Network["Output"].Send(
					error,
					"RetainPart Error : Invalid syntax: Arg1 (Part) must be an ungrounded BasePart which is a descendant of workspace."
				)
				local Index = table.find(Network["LostParts"], Part)
				if Index then
					table.remove(Network["LostParts"], Index)
				end
				return false
			end
			assert(
				typeof(Silent) == "boolean" or typeof(Silent) == "nil",
				Network["Output"].Prefix .. "RetainPart Error : Invalid syntax: Arg2 (Silent) must be a boolean or nil."
			)
			assert(
				typeof(ReturnFakePart) == "boolean" or typeof(ReturnFakePart) == "nil",
				Network["Output"].Prefix
					.. "RetainPart Error : Invalid syntax: Arg3 (ReturnFakePart) must be a boolean or nil."
			)
			if not table.find(Network["BaseParts"], Part) and not table.find(Network["LostParts"], Part) then
				table.insert(Network["BaseParts"], Part)
				Part.CustomPhysicalProperties = PhysicalProperties.new(0, 0, 0, 0, 0)
				if not Silent then
					Network["Output"].Send(
						print,
						"PartOwnership Output : PartOwnership applied to BasePart " .. Part:GetFullName() .. "."
					)
				end
				if ReturnFakePart then
					local workspaceParts = {}
					return FakePart
				end
			else
				Network["Output"].Send(
					warn,
					"RetainPart Warning : PartOwnership not applied to BasePart "
						.. Part:GetFullName()
						.. ", as it already active."
				)
				return false
			end
		end
		Network["RemovePart"] = function(Part, Silent)
			assert(
				typeof(Part) == "Instance" and Part:IsA("BasePart"),
				Network["Output"].Prefix .. "RemovePart Error : Invalid syntax: Arg1 (Part) must be a BasePart."
			)
			local Index1 = table.find(Network["BaseParts"], Part)
			local Index2 = table.find(Network["LostParts"], Part)
			if Index1 then
				table.remove(Network["BaseParts"], Index1)
			else
				if not Silent then
					Network["Output"].Send(
						warn,
						"RemovePart Warning : BasePart " .. Part:GetFullName() .. " not found in BaseParts table."
					)
				end
				return
			end
			if Index2 then
				table.remove(Network["LostParts"], Index2)
			end
			if not Silent then
				Network["Output"].Send(
					print,
					"RemovePart Output: PartOwnership removed from BasePart " .. Part:GetFullName() .. "."
				)
			end
		end
		Network["PartOwnership"]["PartCoroutine"] = coroutine.create(function(Part)
			if Part:IsDescendantOf(workspace) then
				if Network.CharacterRelative then
					local Character = Network["LastCharacter"]
					if not Character.PrimaryPart then
						for _, Inst in pairs(Character:GetDescendants()) do
							if Inst:IsA("BasePart") then
								Character.PrimaryPart = Inst
								break
							end
						end
					end
					if Character and Character.PrimaryPart then
						local Distance = (Character.PrimaryPart.Position - Part.Position).Magnitude
						if
							Distance > gethiddenproperty(LocalPlayer, "MaximumSimulationRadius")
							and not isnetworkowner(Part)
						then
							Network["Output"].Send(
								warn,
								"PartOwnership Warning : PartOwnership not applied to BasePart "
									.. Part:GetFullName()
									.. ", as it is more than "
									.. gethiddenproperty(LocalPlayer, "MaximumSimulationRadius")
									.. " studs away."
							)
							Network["RemovePart"](Part)
							if not Part:IsGrounded() then
								table.insert(Network["LostParts"], Part)
							else
								Network["Output"].Send(
									warn,
									"PartOwnership Warning : PartOwnership not applied to BasePart "
										.. Part:GetFullName()
										.. ", as it is grounded."
								)
							end
						end
					else
						Network["Output"].Send(
							warn,
							"PartOwnership Warning : PartOwnership not applied to BasePart "
								.. Part:GetFullName()
								.. ", as the LocalPlayer Character's PrimaryPart does not exist."
						)
					end
				end
				Part.AssemblyLinearVelocity = (Part.AssemblyLinearVelocity.Unit + Vector3.new(0.01, 0.01, 0.01))
					* (50 + math.cos(tick() * 10))
			else
				Network["RemovePart"](Part)
			end
		end)
		Network["PartOwnership"]["Enable"] = coroutine.create(function()
			if not Network["PartOwnership"]["Enabled"] then
				Network["PartOwnership"]["Enabled"] = true
				Network["PartOwnership"]["PreMethodSettings"].ReplicationFocus = LocalPlayer.ReplicationFocus
				LocalPlayer.ReplicationFocus = workspace
				Network["PartOwnership"]["PreMethodSettings"].SimulationRadius =
					gethiddenproperty(LocalPlayer, "SimulationRadius")
				Network["PartOwnership"]["Connection"] = RunService.Stepped:Connect(function()
					Network["LastCharacter"] = pcall(function()
						return LocalPlayer.Character
					end) or Network["LastCharacter"]
					sethiddenproperty(LocalPlayer, "SimulationRadius", 1 / 0)
					coroutine.wrap(function()
						for _, Part in pairs(Network["BaseParts"]) do
							coroutine.resume(Network["PartOwnership"]["PartCoroutine"], Part)
						end
					end)()
					coroutine.wrap(function()
						for _, Part in pairs(Network["LostParts"]) do
							Network.RetainPart(Part, true)
						end
					end)()
				end)
				Network["Output"].Send(print, "PartOwnership Output : PartOwnership enabled.")
			else
				Network["Output"].Send(warn, "PartOwnership Output : PartOwnership already enabled.")
			end
		end)
		Network["PartOwnership"]["Disable"] = coroutine.create(function()
			if Network["PartOwnership"]["Connection"] then
				Network["PartOwnership"]["Connection"]:Disconnect()
				LocalPlayer.ReplicationFocus = Network["PartOwnership"]["PreMethodSettings"].ReplicationFocus
				sethiddenproperty(
					LocalPlayer,
					"SimulationRadius",
					Network["PartOwnership"]["PreMethodSettings"].SimulationRadius
				)
				Network["PartOwnership"]["PreMethodSettings"] = {}
				for _, Part in pairs(Network["BaseParts"]) do
					Network["RemovePart"](Part)
				end
				for Index, Part in pairs(Network["LostParts"]) do
					table.remove(Network["LostParts"], Index)
				end
				Network["PartOwnership"]["Enabled"] = false
				Network["Output"].Send(print, "PartOwnership Output : PartOwnership disabled.")
			else
				Network["Output"].Send(warn, "PartOwnership Output : PartOwnership already disabled.")
			end
		end)
		Network["Output"].Send(print, ": Loaded.")
	end
	coroutine.resume(Network["PartOwnership"]["Enable"])
end)

RegisterCommand({
	Name = "punch",
	Aliases = { "pu" },
	Description = "punch a nigga",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	PunchTime = 30
	Power = 50
	Damage = 50
	Closed = false
	RunService = game:GetService("RunService")
	Player = game.Players.LocalPlayer
	function DoTheThing()
		local Character = Player.Character
		local RightArm = (Character:WaitForChild("Right Arm", 1) or Character:WaitForChild("RightLowerArm"))
		local RigType = Character:WaitForChild("Humanoid").RigType
		local PunchTool = Instance.new("Tool", Player.Backpack)
		PunchTool.RequiresHandle = false
		PunchTool.Name = "Punch"
		PunchTool.ToolTip = "Punch anything really"
		local Punching = false
		local Anim = Instance.new("Animation", PunchTool)
		if RigType == Enum.HumanoidRigType.R6 then
			Anim.AnimationId = "rbxassetid://28156406"
		else
			Anim.AnimationId = "rbxassetid://10717116749"
		end
		local Track = Character:WaitForChild("Humanoid"):LoadAnimation(Anim)
		PunchTool.Activated:Connect(function()
			if not Punching then
				Punching = true
				Track:Play()
				if RigType == Enum.HumanoidRigType.R6 then
					task.wait(0.2)
					Track:AdjustSpeed(3)
				else
					Track.TimePosition = 1.65
					Track.Looped = false
					Track:AdjustSpeed(1.1)
				end
				local Times = 0
				RightArm.CanCollide = true
				for Num, Part in RightArm:GetTouchingParts() do
					if
						Part.Parent:FindFirstChildWhichIsA("Humanoid")
						and not Part:FindFirstAncestor(Player.Name)
						and game.Players:GetPlayerFromCharacter(Part.Parent) == nil
					then
						local Humanoid = Part.Parent:WaitForChild("Humanoid")
						Humanoid.Health -= Damage
						Humanoid.HealthDisplayType = Enum.HumanoidHealthDisplayType.AlwaysOn
						print(Humanoid.Health .. "/" .. Humanoid.MaxHealth)
					end
				end
				repeat
					RunService.Heartbeat:Wait()
					RightArm.CanCollide = true
					Times += 1
					local root = Character:WaitForChild("HumanoidRootPart")
					local vel, movel = nil, 0.1
					while not (Character and Character.Parent and root and root.Parent) do
						RunService.Heartbeat:Wait()
						root = Character:WaitForChild("HumanoidRootPart")
					end
					vel = root.Velocity
					root.Velocity = vel * Power + Vector3.new(0, Power, 0)
					RunService.RenderStepped:Wait()
					if Character and Character.Parent and root and root.Parent then
						root.Velocity = vel
					end
					RunService.Stepped:Wait()
					if Character and Character.Parent and root and root.Parent then
						root.Velocity = vel + Vector3.new(0, movel, 0)
						movel = movel * -1
					end
				until Times == PunchTime
				Punching = false
				game:GetService("UserInputService").InputBegan:Connect(function(Input, Processed)
					if Processed then
						return
					end
					if Input.KeyCode == Enum.KeyCode.Backspace then
						PunchTool:Destroy()
						print("Closed")
						Closed = true
						script:Destroy()
					end
				end)
			end
		end)
	end
	while not Player.Character do
		task.wait(0.1)
	end
	DoTheThing()
	Player.CharacterAdded:Connect(function()
		if not Closed then
			DoTheThing()
		end
	end)
end)
Modules.BadgeSpoofer = {
	State = {
		SpoofedBadges = {},
		IsHooked = false,
		OriginalFunctions = {},
		BadgeRemotes = {},
	},
}
function Modules.BadgeSpoofer:_findBadgeRemotes()
	self.State.BadgeRemotes = {}
	local function scan(container)
		for _, child in ipairs(container:GetDescendants()) do
			if child:IsA("RemoteEvent") or child:IsA("RemoteFunction") then
				local name = child.Name:lower()
				if name:find("badge") or name:find("award") or name:find("unlock") then
					table.insert(self.State.BadgeRemotes, child)
				end
			end
		end
	end
	scan(game:GetService("ReplicatedStorage"))
	scan(game:GetService("ReplicatedFirst"))
	return #self.State.BadgeRemotes
end
function Modules.BadgeSpoofer:_hookBadgeService()
	if self.State.IsHooked then
		return
	end
	local BadgeService = game:GetService("BadgeService")
	local mt = getrawmetatable(game)
	if not mt then
		DoNotif("Failed to get metatable", 3)
		return false
	end
	pcall(function()
		if setreadonly then
			setreadonly(mt, false)
		end
	end)
	local oldNamecall = mt.__namecall
	mt.__namecall = newcclosure(function(self, ...)
		local method = getnamecallmethod()
		local args = { ... }
		if method == "UserHasBadgeAsync" then
			local userId = args[1]
			local badgeId = args[2]
			if userId == LocalPlayer.UserId and Modules.BadgeSpoofer.State.SpoofedBadges[badgeId] then
				return true
			end
		end
		if method == "AwardBadge" then
			local userId = args[1]
			local badgeId = args[2]
			if userId == LocalPlayer.UserId then
				Modules.BadgeSpoofer.State.SpoofedBadges[badgeId] = true
				return true
			end
		end
		return oldNamecall(self, ...)
	end)
	pcall(function()
		if setreadonly then
			setreadonly(mt, true)
		end
	end)
	self.State.IsHooked = true
	return true
end
function Modules.BadgeSpoofer:_findGameBadges()
	local badges = {}
	local function searchForBadgeIds(container)
		for _, obj in ipairs(container:GetDescendants()) do
			if obj:IsA("IntValue") or obj:IsA("NumberValue") then
				if obj.Name:lower():find("badge") then
					local badgeId = obj.Value
					if badgeId > 0 then
						table.insert(badges, {
							Id = badgeId,
							Source = obj:GetFullName(),
						})
					end
				end
			end
			if obj:IsA("StringValue") then
				local str = obj.Value
				local badgeId = tonumber(str:match("(%d+)"))
				if badgeId and badgeId > 1000000 then
					table.insert(badges, {
						Id = badgeId,
						Source = obj:GetFullName(),
					})
				end
			end
			if obj:IsA("ModuleScript") then
				local success, source = pcall(function()
					return obj.Source
				end)
				if success and source then
					for badgeId in source:gmatch("(%d%d%d%d%d%d%d+)") do
						local id = tonumber(badgeId)
						if id then
							table.insert(badges, {
								Id = id,
								Source = obj.Name,
							})
						end
					end
				end
			end
		end
	end
	searchForBadgeIds(game:GetService("ReplicatedStorage"))
	searchForBadgeIds(game:GetService("ReplicatedFirst"))
	return badges
end
function Modules.BadgeSpoofer:SpoofBadge(badgeId)
	if not self.State.IsHooked then
		self:_hookBadgeService()
	end
	badgeId = tonumber(badgeId)
	if not badgeId then
		DoNotif("Invalid badge ID", 3)
		return
	end
	self.State.SpoofedBadges[badgeId] = true
	DoNotif(string.format("Spoofed badge: %d", badgeId), 2)
end
function Modules.BadgeSpoofer:SpoofAllFoundBadges()
	if not self.State.IsHooked then
		self:_hookBadgeService()
	end
	local badges = self:_findGameBadges()
	local count = 0
	for _, badgeData in ipairs(badges) do
		if not self.State.SpoofedBadges[badgeData.Id] then
			self.State.SpoofedBadges[badgeData.Id] = true
			count = count + 1
		end
	end
	DoNotif(string.format("Spoofed %d badges", count), 2)
end
function Modules.BadgeSpoofer:ListFoundBadges()
	local badges = self:_findGameBadges()
	print("\n=== FOUND BADGES ===")
	for i, badgeData in ipairs(badges) do
		print(string.format("%d. Badge ID: %d (from %s)", i, badgeData.Id, badgeData.Source))
	end
	print(string.format("\nTotal: %d badges", #badges))
	DoNotif(string.format("Found %d badges (check console)", #badges), 2)
end
function Modules.BadgeSpoofer:RemoveSpoof(badgeId)
	badgeId = tonumber(badgeId)
	if not badgeId then
		DoNotif("Invalid badge ID", 3)
		return
	end
	self.State.SpoofedBadges[badgeId] = nil
	DoNotif(string.format("Removed spoof: %d", badgeId), 2)
end
function Modules.BadgeSpoofer:ClearAllSpoofs()
	local count = 0
	for _ in pairs(self.State.SpoofedBadges) do
		count = count + 1
	end
	self.State.SpoofedBadges = {}
	DoNotif(string.format("Cleared %d spoofed badges", count), 2)
end
function Modules.BadgeSpoofer:ListSpoofedBadges()
	print("\n=== SPOOFED BADGES ===")
	local count = 0
	for badgeId, _ in pairs(self.State.SpoofedBadges) do
		count = count + 1
		print(string.format("%d. Badge ID: %d", count, badgeId))
	end
	print(string.format("\nTotal: %d spoofed", count))
	DoNotif(string.format("%d badges spoofed (check console)", count), 2)
end
function Modules.BadgeSpoofer:FireBadgeRemotes(badgeId)
	badgeId = tonumber(badgeId)
	if not badgeId then
		DoNotif("Invalid badge ID", 3)
		return
	end
	if #self.State.BadgeRemotes == 0 then
		self:_findBadgeRemotes()
	end
	local attempts = 0
	for _, remote in ipairs(self.State.BadgeRemotes) do
		pcall(function()
			if remote:IsA("RemoteEvent") then
				remote:FireServer(badgeId)
				remote:FireServer({ BadgeId = badgeId })
				remote:FireServer("Award", badgeId)
			elseif remote:IsA("RemoteFunction") then
				remote:InvokeServer(badgeId)
				remote:InvokeServer({ BadgeId = badgeId })
			end
			attempts = attempts + 1
		end)
		task.wait(0.05)
	end
	DoNotif(string.format("Fired %d badge remotes", attempts), 2)
end
function Modules.BadgeSpoofer:BruteForceUnlock(itemName)
	DoNotif("Brute forcing unlock for: " .. itemName, 2)
	local unlockRemotes = {}
	local function findUnlockRemotes(container)
		for _, remote in ipairs(container:GetDescendants()) do
			if remote:IsA("RemoteEvent") or remote:IsA("RemoteFunction") then
				local name = remote.Name:lower()
				if
					name:find("unlock")
					or name:find("equip")
					or name:find("purchase")
					or name:find("buy")
					or name:find("claim")
				then
					table.insert(unlockRemotes, remote)
				end
			end
		end
	end
	findUnlockRemotes(game:GetService("ReplicatedStorage"))
	local patterns = {
		itemName,
		{ Item = itemName },
		{ Name = itemName },
		{ ItemName = itemName },
		"Unlock",
		itemName,
		"Equip",
		itemName,
	}
	local attempts = 0
	for _, remote in ipairs(unlockRemotes) do
		for _, pattern in ipairs(patterns) do
			pcall(function()
				if remote:IsA("RemoteEvent") then
					remote:FireServer(pattern)
				else
					remote:InvokeServer(pattern)
				end
			end)
			attempts = attempts + 1
			task.wait(0.02)
		end
	end
	DoNotif(string.format("Tried %d unlock attempts", attempts), 2)
end
