	btnBJDouble.MouseButton1Click:Connect(function()
		if not bjGame then
			return
		end
		if Wallet.balance < Wallet.bet * 2 then
			log(" Not enough to double!", Color3.fromHex("#e74c3c"))
			return
		end
		local origBet = Wallet.bet
		Wallet.bet = origBet * 2
		refreshWallet()
		log("Doubled down! Bet: $" .. fmt(Wallet.bet), Color3.fromHex("#f0c040"))
		bjGame:Hit()
		log(
			"You:    " .. bjGame:HandStr(bjGame.playerHand) .. "  [" .. bjGame:HandValue(bjGame.playerHand) .. "]",
			Color3.fromHex("#7ecfff")
		)
		if not bjGame.done then
			bjGame:Stand()
		end
		finishBJ()
		Wallet.bet = origBet
		refreshWallet()
	end)
