	local chatConn = lp.Chatted:Connect(function(msg)
		msg = msg:lower():match("^%s*(.-)%s*$")
		local args = {}
		for word in msg:gmatch("%S+") do
			table.insert(args, word)
		end
		local cmd = args[1]
		if cmd == "!bet" and args[2] then
			local n = tonumber(args[2])
			if n and n > 0 then
				Wallet.bet = clamp(n, 10, Wallet.balance)
				refreshWallet()
				log("Bet set to $" .. fmt(Wallet.bet), Color3.fromHex("#f0c040"))
			end
		elseif cmd == "!balance" or cmd == "!bal" then
			log(" Balance: $" .. fmt(Wallet.balance) .. "  |  Bet: $" .. fmt(Wallet.bet), Color3.fromHex("#2ecc71"))
		elseif cmd == "!deal" or cmd == "!bj" then
			activateTab(tabBJ)
			hideAllBtns()
			startBJ()
		elseif cmd == "!hit" then
			if bjGame and not bjGame.done then
				bjGame:Hit()
				log(
					"You:    "
						.. bjGame:HandStr(bjGame.playerHand)
						.. "  ["
						.. bjGame:HandValue(bjGame.playerHand)
						.. "]",
					Color3.fromHex("#7ecfff")
				)
				if bjGame.done then
					finishBJ()
				end
			else
				log(" No active hand. !deal first.", Color3.fromHex("#e74c3c"))
			end
		elseif cmd == "!stand" then
			if bjGame and not bjGame.done then
				bjGame:Stand()
				finishBJ()
			else
				log(" No active hand. !deal first.", Color3.fromHex("#e74c3c"))
			end
		elseif cmd == "!double" then
			if bjGame and not bjGame.done then
				btnBJDouble:MouseButton1Click()
			else
				log(" No active hand. !deal first.", Color3.fromHex("#e74c3c"))
			end
		elseif cmd == "!spin" then
			activateTab(tabSlots)
			hideAllBtns()
			btnSpin.Visible = true
			doSlots()
		elseif cmd == "!d6" then
			diceMode = "d6"
			log("Die set to d6", Color3.fromHex("#8899aa"))
		elseif cmd == "!d20" then
			diceMode = "d20"
			log("Die set to d20", Color3.fromHex("#8899aa"))
		elseif cmd == "!roll" or cmd == "!hi" or cmd == "!high" then
			activateTab(tabDice)
			hideAllBtns()
			btnD6.Visible = true
			btnD20.Visible = true
			btnHigh.Visible = true
			btnLow.Visible = true
			dicePrediction = "hi"
			doDice()
		elseif cmd == "!lo" or cmd == "!low" then
			activateTab(tabDice)
			hideAllBtns()
			btnD6.Visible = true
			btnD20.Visible = true
			btnHigh.Visible = true
			btnLow.Visible = true
			dicePrediction = "lo"
			doDice()
		elseif cmd == "!casino" then
			win.Visible = not win.Visible
		elseif cmd == "!help" then
			log(
				" Casino Commands ",
				Color3.fromHex("#f0c040")
			)
			log("!bet <n>    Set bet amount", Color3.fromHex("#ccd6f6"))
			log("!balance    Show balance", Color3.fromHex("#ccd6f6"))
			log("!deal       Start blackjack hand", Color3.fromHex("#ccd6f6"))
			log("!hit !stand !double   BJ actions", Color3.fromHex("#ccd6f6"))
			log("!spin       Spin the slots", Color3.fromHex("#ccd6f6"))
			log("!d6 !d20    Choose die", Color3.fromHex("#ccd6f6"))
			log("!hi / !lo   Roll dice (bet direction)", Color3.fromHex("#ccd6f6"))
			log("!casino     Toggle GUI", Color3.fromHex("#ccd6f6"))
		end
	end)
	lp.CharacterRemoving:Connect(function()
		chatConn:Disconnect()
	end)
end)
RegisterCommand({
	Name = "freezer",
	Aliases = { "fanim" },
	Description = "freezes your animations",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	local Players = game:GetService("Players")
	local UserInputService = game:GetService("UserInputService")
	local player = Players.LocalPlayer
	local character = player.Character or player.CharacterAdded:Wait()
	local humanoid = character:WaitForChild("Humanoid")
	local animator = humanoid:WaitForChild("Animator")
	local frozen = false
	local connection = nil
	local function freeze()
		for _, track in ipairs(animator:GetPlayingAnimationTracks()) do
			track:Stop(0)
		end
		connection = animator.AnimationPlayed:Connect(function(track)
			track:Stop(0)
		end)
		humanoid:ChangeState(Enum.HumanoidStateType.None)
		print("Animations frozen")
	end
	local function unfreeze()
		if connection then
			connection:Disconnect()
			connection = nil
		end
		humanoid:ChangeState(Enum.HumanoidStateType.GettingUp)
		print("Animations unfrozen")
	end
	UserInputService.InputBegan:Connect(function(input, gameProcessed)
		if gameProcessed then
			return
		end
		if input.KeyCode == Enum.KeyCode.J then
			frozen = not frozen
			if frozen then
				freeze()
			else
				unfreeze()
			end
		end
	end)
	player.CharacterAdded:Connect(function(newChar)
		character = newChar
		humanoid = newChar:WaitForChild("Humanoid")
		animator = humanoid:WaitForChild("Animator")
		frozen = false
		connection = nil
	end)
	print("press J to toggle")
end)
Modules.WorkspaceESP = {
	State = {
		Gui = nil,
		MainFrame = nil,
		ScrollFrame = nil,
		RootItemsMap = {},
		Connections = {},
		IsOpen = false,
	},
	Config = {
		Theme = {
			Bg = Color3.fromRGB(15, 15, 15),
			Header = Color3.fromRGB(25, 25, 25),
			Accent = Color3.fromRGB(0, 255, 140),
			Text = Color3.fromRGB(255, 255, 255),
			SubText = Color3.fromRGB(180, 180, 180),
		},
		Size = Vector2.new(320, 500),
	},
}
function Modules.WorkspaceESP:_addESP(object)
	if not object or not object.Parent then
		return
	end
	local T = self.Config.Theme
	local oldH = object:FindFirstChild("ESP_Highlight")
	local oldT = object:FindFirstChild("ESP_Tag")
	if oldH then
		oldH:Destroy()
	end
	if oldT then
		oldT:Destroy()
	end
	local h = Instance.new("Highlight")
	h.Name = "ESP_Highlight"
	h.FillColor = T.Accent
	h.OutlineColor = T.Accent
	h.FillTransparency = 0.5
	h.Adornee = object
	h.Parent = object
	local b = Instance.new("BillboardGui")
	b.Name = "ESP_Tag"
	b.Size = UDim2.new(0, 100, 0, 25)
	b.AlwaysOnTop = true
	b.StudsOffset = Vector3.new(0, 2, 0)
	if object:IsA("Model") then
		local p = object.PrimaryPart or object:FindFirstChildWhichIsA("BasePart")
		if p then
			b.Adornee = p
		end
	elseif object:IsA("Folder") then
		local p = object:FindFirstChildWhichIsA("BasePart")
		if p then
			b.Adornee = p
		end
	end
	local t = Instance.new("TextLabel")
	t.Size = UDim2.new(1, 0, 1, 0)
	t.BackgroundTransparency = 1
	t.Text = object.Name
	t.TextColor3 = T.Accent
	t.Font = Enum.Font.Code
	t.TextSize = 14
	t.TextStrokeTransparency = 0.5
	t.Parent = b
	b.Parent = object
end
function Modules.WorkspaceESP:_removeESP(object)
	if not object then
		return
	end
	local h = object:FindFirstChild("ESP_Highlight")
	local t = object:FindFirstChild("ESP_Tag")
	if h then
		h:Destroy()
	end
	if t then
		t:Destroy()
	end
end
function Modules.WorkspaceESP:_isValid(obj)
	return obj:IsA("Model") or obj:IsA("Folder")
end
function Modules.WorkspaceESP:_hasValidChildren(obj)
	for _, child in pairs(obj:GetChildren()) do
		if self:_isValid(child) then
			return true
		end
	end
	return false
end
function Modules.WorkspaceESP:_setRecursiveESP(object, state)
	if state then
		self:_addESP(object)
	else
		self:_removeESP(object)
	end
	for _, child in pairs(object:GetChildren()) do
		if self:_isValid(child) then
			self:_setRecursiveESP(child, state)
		end
	end
end
function Modules.WorkspaceESP:_updateChildCheckboxes(container, state)
	for _, itemWrapper in pairs(container:GetChildren()) do
		if itemWrapper:IsA("Frame") then
			local row = itemWrapper:FindFirstChild("Row")
			if row then
				local checkbox = row:FindFirstChild("Checkbox")
				if checkbox then
					checkbox.Text = state and "X" or ""
				end
			end
			local nestedChildren = itemWrapper:FindFirstChild("Children")
			if nestedChildren and nestedChildren.Visible then
				self:_updateChildCheckboxes(nestedChildren, state)
			end
		end
	end
end
function Modules.WorkspaceESP:_createItem(parentContainer, object, depth)
	local T = self.Config.Theme
	local itemWrapper = Instance.new("Frame")
	itemWrapper.Name = object.Name
	itemWrapper.Size = UDim2.new(1, 0, 0, 0)
	itemWrapper.AutomaticSize = Enum.AutomaticSize.Y
	itemWrapper.BackgroundTransparency = 1
	itemWrapper.Parent = parentContainer
	local wrapperLayout = Instance.new("UIListLayout")
	wrapperLayout.SortOrder = Enum.SortOrder.LayoutOrder
	wrapperLayout.Parent = itemWrapper
	local rowFrame = Instance.new("Frame")
	rowFrame.Name = "Row"
	rowFrame.Size = UDim2.new(1, 0, 0, 24)
	rowFrame.BackgroundColor3 = T.Header
	rowFrame.BorderSizePixel = 0
	rowFrame.Parent = itemWrapper
	local indent = 15 * depth
	local canExpand = self:_hasValidChildren(object)
	local expandBtn = nil
	if canExpand then
		expandBtn = Instance.new("TextButton")
		expandBtn.Name = "ExpandBtn"
		expandBtn.Size = UDim2.new(0, 20, 1, 0)
		expandBtn.Position = UDim2.fromOffset(indent, 0)
		expandBtn.BackgroundTransparency = 1
		expandBtn.Text = "+"
		expandBtn.TextColor3 = T.SubText
		expandBtn.Font = Enum.Font.Code
		expandBtn.TextSize = 14
		expandBtn.Parent = rowFrame
	end
	local checkbox = Instance.new("TextButton")
	checkbox.Name = "Checkbox"
	checkbox.Size = UDim2.new(0, 24, 1, 0)
	checkbox.Position = UDim2.fromOffset(indent + (canExpand and 20 or 0), 0)
	checkbox.BackgroundTransparency = 1
	checkbox.Text = ""
	checkbox.TextColor3 = T.Accent
	checkbox.Font = Enum.Font.Code
	checkbox.TextSize = 18
	checkbox.TextXAlignment = Enum.TextXAlignment.Center
	checkbox.Parent = rowFrame
	local cStroke = Instance.new("UIStroke")
	cStroke.Color = T.Accent
	cStroke.Thickness = 1
	cStroke.Parent = checkbox
	local label = Instance.new("TextLabel")
	label.Size = UDim2.new(1, -(indent + (canExpand and 50 or 30)), 1, 0)
	label.Position = UDim2.fromOffset(indent + (canExpand and 50 or 30), 0)
	label.BackgroundTransparency = 1
	label.TextColor3 = T.Text
	label.TextXAlignment = Enum.TextXAlignment.Left
	label.Font = Enum.Font.Code
	label.TextSize = 13
	label.Text = object.Name .. " [" .. object.ClassName .. "]"
	label.Parent = rowFrame
	local childContainer = Instance.new("Frame")
	childContainer.Name = "Children"
	childContainer.Size = UDim2.new(1, 0, 0, 0)
	childContainer.AutomaticSize = Enum.AutomaticSize.Y
	childContainer.BackgroundTransparency = 1
	childContainer.Visible = false
	childContainer.Parent = itemWrapper
	local childLayout = Instance.new("UIListLayout")
	childLayout.SortOrder = Enum.SortOrder.Name
	childLayout.Parent = childContainer
	if object:FindFirstChild("ESP_Highlight") then
		checkbox.Text = "X"
	end
	if canExpand then
		local isExpanded = false
		expandBtn.MouseButton1Click:Connect(function()
			isExpanded = not isExpanded
			expandBtn.Text = isExpanded and "-" or "+"
			if isExpanded then
				if #childContainer:GetChildren() == 1 then
					for _, child in pairs(object:GetChildren()) do
						if self:_isValid(child) then
							self:_createItem(childContainer, child, depth + 1)
						end
					end
				end
				childContainer.Visible = true
			else
				childContainer.Visible = false
			end
		end)
	end
	checkbox.MouseButton1Click:Connect(function()
		local willEnable = (checkbox.Text == "")
		checkbox.Text = willEnable and "X" or ""
		self:_setRecursiveESP(object, willEnable)
		self:_updateChildCheckboxes(childContainer, willEnable)
	end)
	return itemWrapper
end
function Modules.WorkspaceESP:_build()
	local T = self.Config.Theme
	local sz = self.Config.Size
	if self.State.Gui then
		pcall(function()
			self.State.Gui:Destroy()
		end)
		self.State.Gui = nil
	end
	local gui = Instance.new("ScreenGui")
	gui.Name = "ZukaWorkspaceESP"
	gui.ResetOnSpawn = false
	gui.IgnoreGuiInset = true
	gui.DisplayOrder = 998
	gui.Parent = game:GetService("CoreGui")
	self.State.Gui = gui
	local mainFrame = Instance.new("Frame")
	mainFrame.Name = "MainWindow"
	mainFrame.Size = UDim2.fromOffset(sz.X, sz.Y)
	mainFrame.Position = UDim2.new(0.5, -sz.X / 2, 0.5, -sz.Y / 2)
	mainFrame.BackgroundColor3 = T.Bg
	mainFrame.BorderSizePixel = 0
	mainFrame.Parent = gui
	self.State.MainFrame = mainFrame
	local mainCorner = Instance.new("UICorner")
	mainCorner.CornerRadius = UDim.new(0, 6)
	mainCorner.Parent = mainFrame
	local mainStroke = Instance.new("UIStroke")
	mainStroke.Color = T.Accent
	mainStroke.Thickness = 1
	mainStroke.Parent = mainFrame
	local header = Instance.new("Frame")
	header.Name = "Header"
	header.Size = UDim2.new(1, 0, 0, 40)
	header.BackgroundColor3 = T.Header
	header.BorderSizePixel = 0
	header.Parent = mainFrame
	local headerCorner = Instance.new("UICorner")
	headerCorner.CornerRadius = UDim.new(0, 6)
	headerCorner.Parent = header
	local headerFix = Instance.new("Frame")
	headerFix.Size = UDim2.new(1, 0, 0, 15)
	headerFix.Position = UDim2.new(0, 0, 1, -15)
	headerFix.BackgroundColor3 = T.Header
	headerFix.BorderSizePixel = 0
	headerFix.Parent = header
	local title = Instance.new("TextLabel")
	title.Text = "MODEL EXPLORER  [LIVE]"
	title.TextColor3 = T.Accent
	title.Font = Enum.Font.Code
	title.TextSize = 16
	title.BackgroundTransparency = 1
	title.Size = UDim2.new(1, -50, 1, 0)
	title.Position = UDim2.fromOffset(15, 0)
	title.TextXAlignment = Enum.TextXAlignment.Left
	title.Parent = header
	local closeBtn = Instance.new("TextButton")
	closeBtn.Text = "—"
	closeBtn.TextColor3 = T.Accent
	closeBtn.Font = Enum.Font.Code
	closeBtn.TextSize = 20
	closeBtn.BackgroundTransparency = 1
	closeBtn.Size = UDim2.new(0, 30, 1, 0)
	closeBtn.Position = UDim2.new(1, -60, 0, 0)
	closeBtn.Parent = header
	local destroyBtn = Instance.new("TextButton")
	destroyBtn.Text = ""
	destroyBtn.TextColor3 = T.Accent
	destroyBtn.Font = Enum.Font.Code
	destroyBtn.TextSize = 16
	destroyBtn.BackgroundTransparency = 1
	destroyBtn.Size = UDim2.new(0, 30, 1, 0)
	destroyBtn.Position = UDim2.new(1, -30, 0, 0)
	destroyBtn.Parent = header
	local body = Instance.new("Frame")
	body.Name = "Body"
	body.Size = UDim2.new(1, 0, 1, -45)
	body.Position = UDim2.new(0, 0, 0, 42)
	body.BackgroundTransparency = 1
	body.Parent = mainFrame
	local scrollFrame = Instance.new("ScrollingFrame")
	scrollFrame.Size = UDim2.new(1, -10, 1, -10)
	scrollFrame.Position = UDim2.fromOffset(5, 5)
	scrollFrame.BackgroundTransparency = 1
	scrollFrame.ScrollBarThickness = 4
	scrollFrame.ScrollBarImageColor3 = T.Accent
	scrollFrame.BorderSizePixel = 0
	scrollFrame.AutomaticCanvasSize = Enum.AutomaticSize.Y
	scrollFrame.Parent = body
	self.State.ScrollFrame = scrollFrame
	local mainLayout = Instance.new("UIListLayout")
	mainLayout.SortOrder = Enum.SortOrder.Name
	mainLayout.Parent = scrollFrame
	local dragging, dragStart, startPos
	header.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 then
			dragging = true
			dragStart = input.Position
			startPos = mainFrame.Position
		end
	end)
	header.InputEnded:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 then
			dragging = false
		end
	end)
	local dragConn = UserInputService.InputChanged:Connect(function(input)
		if dragging and input.UserInputType == Enum.UserInputType.MouseMovement then
			local d = input.Position - dragStart
			mainFrame.Position =
				UDim2.new(startPos.X.Scale, startPos.X.Offset + d.X, startPos.Y.Scale, startPos.Y.Offset + d.Y)
		end
	end)
	table.insert(self.State.Connections, dragConn)
	local isMin = false
	closeBtn.MouseButton1Click:Connect(function()
		isMin = not isMin
		if isMin then
			mainFrame:TweenSize(UDim2.fromOffset(sz.X, 40), "Out", "Quad", 0.2, true)
			closeBtn.Text = "+"
		else
			mainFrame:TweenSize(UDim2.fromOffset(sz.X, sz.Y), "Out", "Quad", 0.2, true)
			closeBtn.Text = "—"
		end
	end)
	destroyBtn.MouseButton1Click:Connect(function()
		self:Close()
	end)
	self.State.RootItemsMap = {}
	for _, obj in pairs(workspace:GetChildren()) do
		if self:_isValid(obj) then
			local guiItem = self:_createItem(scrollFrame, obj, 0)
			self.State.RootItemsMap[obj] = guiItem
		end
	end
	local addedConn = workspace.ChildAdded:Connect(function(child)
		if self:_isValid(child) and not self.State.RootItemsMap[child] then
			local guiItem = self:_createItem(scrollFrame, child, 0)
			self.State.RootItemsMap[child] = guiItem
		end
	end)
	table.insert(self.State.Connections, addedConn)
	local removedConn = workspace.ChildRemoved:Connect(function(child)
		if self.State.RootItemsMap[child] then
			self.State.RootItemsMap[child]:Destroy()
			self.State.RootItemsMap[child] = nil
		end
	end)
	table.insert(self.State.Connections, removedConn)
	self.State.IsOpen = true
end
function Modules.WorkspaceESP:Open()
	if self.State.IsOpen and self.State.Gui and self.State.Gui.Parent then
		if self.State.MainFrame then
			self.State.MainFrame.Visible = true
		end
		return
	end
	self:_build()
	DoNotif("Workspace ESP opened", 1.5)
end
function Modules.WorkspaceESP:Close()
	for _, conn in pairs(self.State.Connections) do
		pcall(function()
			conn:Disconnect()
		end)
	end
	self.State.Connections = {}
	self.State.RootItemsMap = {}
	self.State.IsOpen = false
	if self.State.Gui then
		pcall(function()
			self.State.Gui:Destroy()
		end)
		self.State.Gui = nil
		self.State.MainFrame = nil
		self.State.ScrollFrame = nil
	end
	DoNotif("Workspace ESP closed", 1.5)
end
function Modules.WorkspaceESP:Toggle()
	if self.State.IsOpen then
		self:Close()
	else
		self:Open()
	end
end
function Modules.WorkspaceESP:ClearAll()
	for _, obj in pairs(workspace:GetDescendants()) do
		if obj:IsA("Model") or obj:IsA("Folder") then
			self:_removeESP(obj)
		end
	end
	DoNotif("All workspace ESP cleared", 1.5)
end
function Modules.WorkspaceESP:Initialize()
	RegisterCommand({
		Name = "wesp",
		Aliases = { "workspaceesp", "modelexplorer" },
		Description = "Open the live Workspace Model Explorer / ESP panel",
	}, function()
		Modules.WorkspaceESP:Toggle()
	end)
	RegisterCommand({
		Name = "wespclear",
		Aliases = { "clearwesp" },
		Description = "Remove all workspace ESP highlights and tags",
	}, function()
		Modules.WorkspaceESP:ClearAll()
	end)
end
Modules.TableUnlocker = {
	State = {
		UnlockedTables = {},
		OriginalMetatables = {},
		IsMonitoring = false,
		MonitorConnection = nil,
	},
}
function Modules.TableUnlocker:_unlockTable(tbl)
	if type(tbl) ~= "table" then
		return false
	end
	local success = pcall(function()
		if setreadonly then
			setreadonly(tbl, false)
		elseif make_writeable then
			make_writeable(tbl)
		end
	end)
	if success then
		self.State.UnlockedTables[tbl] = true
		return true
	end
	return false
end
function Modules.TableUnlocker:_unlockMetatable(tbl)
	if type(tbl) ~= "table" then
		return false
	end
	local success, mt = pcall(function()
		return getrawmetatable(tbl)
	end)
	if success and mt then
		if not self.State.OriginalMetatables[tbl] then
			self.State.OriginalMetatables[tbl] = mt
		end
		pcall(function()
			if setreadonly then
				setreadonly(mt, false)
			elseif make_writeable then
				make_writeable(mt)
			end
		end)
		if rawget(mt, "__metatable") then
			rawset(mt, "__metatable", nil)
		end
		return true
	end
	return false
end
function Modules.TableUnlocker:_deepUnlock(tbl, maxDepth, currentDepth)
	currentDepth = currentDepth or 0
	maxDepth = maxDepth or 3
	if currentDepth >= maxDepth then
		return
	end
	if type(tbl) ~= "table" then
		return
	end
	if self.State.UnlockedTables[tbl] then
		return
	end
	self:_unlockTable(tbl)
	self:_unlockMetatable(tbl)
	for key, value in pairs(tbl) do
		if type(value) == "table" then
			self:_deepUnlock(value, maxDepth, currentDepth + 1)
		end
	end
end
function Modules.TableUnlocker:UnlockModule(moduleName)
	local targetModule = nil
	local searchLocations = {
		game:GetService("ReplicatedStorage"),
		game:GetService("ReplicatedFirst"),
		LocalPlayer:WaitForChild("PlayerScripts"),
		LocalPlayer:WaitForChild("PlayerGui"),
	}
	for _, location in ipairs(searchLocations) do
		local found = location:FindFirstChild(moduleName, true)
		if found and found:IsA("ModuleScript") then
			targetModule = found
			break
		end
	end
	if not targetModule then
		DoNotif("Module not found: " .. moduleName, 3)
		return
	end
	local success, moduleTable = pcall(function()
		return require(targetModule)
	end)
	if not success then
		DoNotif("Failed to require module", 3)
		return
	end
	if type(moduleTable) ~= "table" then
		DoNotif("Module didn't return a table", 3)
		return
	end
	self:_deepUnlock(moduleTable, 5)
	DoNotif(string.format("Unlocked: %s", moduleName), 2)
end
function Modules.TableUnlocker:UnlockGlobal(globalName)
	local globalTable = _G[globalName]
	if not globalTable then
		DoNotif("Global not found: " .. globalName, 3)
		return
	end
	if type(globalTable) ~= "table" then
		DoNotif("Global is not a table", 3)
		return
	end
	self:_deepUnlock(globalTable, 5)
	DoNotif(string.format("Unlocked global: %s", globalName), 2)
end
function Modules.TableUnlocker:UnlockService(serviceName)
	local success, service = pcall(function()
		return game:GetService(serviceName)
	end)
	if not success or not service then
		DoNotif("Service not found: " .. serviceName, 3)
		return
	end
	self:_unlockTable(service)
	self:_unlockMetatable(service)
	DoNotif(string.format("Unlocked service: %s", serviceName), 2)
end
function Modules.TableUnlocker:ForceWriteable(targetPath)
	local parts = {}
	for part in targetPath:gmatch("[^.]+") do
		table.insert(parts, part)
	end
	if #parts == 0 then
		DoNotif("Invalid path", 3)
		return
	end
	local current = _G[parts[1]] or game
	for i = 2, #parts do
		if not current then
			break
		end
		current = current:FindFirstChild(parts[i])
	end
	if not current then
		DoNotif("Path not found", 3)
		return
	end
	if current:IsA("ModuleScript") then
		local success, moduleTable = pcall(function()
			return require(current)
		end)
		if success and type(moduleTable) == "table" then
			current = moduleTable
		end
	end
	if type(current) == "table" then
		self:_deepUnlock(current, 5)
		DoNotif("Unlocked: " .. targetPath, 2)
	else
		DoNotif("Target is not a table", 3)
	end
end
function Modules.TableUnlocker:StartMonitor()
	if self.State.IsMonitoring then
		DoNotif("Monitor already running", 3)
		return
	end
	self.State.IsMonitoring = true
	self.State.MonitorConnection = game:GetService("RunService").Heartbeat:Connect(function()
		for tbl, _ in pairs(self.State.UnlockedTables) do
			pcall(function()
				if setreadonly then
					setreadonly(tbl, false)
				elseif make_writeable then
					make_writeable(tbl)
				end
			end)
		end
	end)
	DoNotif("Table monitor: ACTIVE", 2)
end
function Modules.TableUnlocker:StopMonitor()
	if not self.State.IsMonitoring then
		return
	end
	self.State.IsMonitoring = false
	if self.State.MonitorConnection then
		self.State.MonitorConnection:Disconnect()
		self.State.MonitorConnection = nil
	end
	DoNotif("Table monitor: STOPPED", 2)
end
function Modules.TableUnlocker:RestoreLocks()
	for tbl, _ in pairs(self.State.UnlockedTables) do
		pcall(function()
			if setreadonly then
				setreadonly(tbl, true)
			end
		end)
	end
	for tbl, originalMt in pairs(self.State.OriginalMetatables) do
		pcall(function()
			setrawmetatable(tbl, originalMt)
		end)
	end
	self.State.UnlockedTables = {}
	self.State.OriginalMetatables = {}
	DoNotif("Restored all locks", 2)
end
