local function make(class, props, parent)
	local obj = Instance.new(class)
	for k, v in pairs(props) do
		pcall(function()
			obj[k] = v
		end)
	end
	if parent then
		obj.Parent = parent
	end
	return obj
end
local function corner(r, p)
	local c = Instance.new("UICorner", p)
	c.CornerRadius = UDim.new(0, r)
end
local function stroke(t, col, p)
	local s = Instance.new("UIStroke", p)
	s.Thickness = t
	s.Color = col
	s.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
end
local function tw(obj, props, t, style)
	pcall(function()
		TweenService
			:Create(obj, TweenInfo.new(t or 0.18, style or Enum.EasingStyle.Quart, Enum.EasingDirection.Out), props)
			:Play()
	end)
end
local function copyToClipboard(text)
	if setclipboard then
		pcall(setclipboard, text)
	elseif toclipboard then
		pcall(toclipboard, text)
	elseif Clipboard and Clipboard.set then
		pcall(Clipboard.set, text)
	end
end
local function accountAge(days)
	days = days or 0
	local y = math.floor(days / 365)
	local m = math.floor((days % 365) / 30)
	local d = days % 30
	local parts = {}
	if y > 0 then
		table.insert(parts, y .. "y")
	end
	if m > 0 then
		table.insert(parts, m .. "mo")
	end
	if d > 0 or #parts == 0 then
		table.insert(parts, d .. "d")
	end
	return table.concat(parts, " ")
end
local function withTimeout(seconds, fn, ...)
	local args = { ... }
	local done = false
	local results = nil
	local thread = task.spawn(function()
		results = table.pack(pcall(fn, table.unpack(args)))
		done = true
	end)
	local elapsed = 0
	local step = 0.05
	while not done and elapsed < seconds do
		task.wait(step)
		elapsed = elapsed + step
	end
	if not done then
		pcall(task.cancel, thread)
		return false, "timeout"
	end
	local ok = table.remove(results, 1)
	return ok, table.unpack(results, 1, results.n - 1)
end
