Modules.Waypoint = {
	State = {
		Waypoints = {},
		Visuals = {},
	},
	Services = {
		Players = game:GetService("Players"),
		Workspace = game:GetService("Workspace"),
		CoreGui = game:GetService("CoreGui"),
	},
}
function Modules.Waypoint:_cleanupVisual(name)
	local visual = self.State.Visuals[name:lower()]
	if visual then
		pcall(function()
			visual:Destroy()
		end)
		self.State.Visuals[name:lower()] = nil
	end
end
function Modules.Waypoint:_createVisual(name, cframe)
	self:_cleanupVisual(name)
	local container = Instance.new("Part")
	container.Name = "WaypointVisual_" .. name
	container.Size = Vector3.new(0.1, 0.1, 0.1)
	container.CFrame = cframe
	container.Anchored = true
	container.CanCollide = false
	container.Transparency = 1
	container.Parent = self.Services.Workspace
	local billboard = Instance.new("BillboardGui", container)
	billboard.AlwaysOnTop = true
	billboard.Size = UDim2.fromOffset(200, 50)
	billboard.StudsOffset = Vector3.new(0, 3, 0)
	local label = Instance.new("TextLabel", billboard)
	label.Size = UDim2.fromScale(1, 1)
	label.BackgroundTransparency = 1
	label.Font = Enum.Font.GothamSemibold
	label.Text = name
	label.TextColor3 = Color3.fromRGB(0, 255, 255)
	label.TextSize = 24
	label.TextStrokeColor3 = Color3.fromRGB(0, 0, 0)
	label.TextStrokeTransparency = 0.5
	local attachment1 = Instance.new("Attachment", container)
	local attachment2 = Instance.new("Attachment", container)
	attachment2.Position = Vector3.new(0, 1000, 0)
	local beam = Instance.new("Beam", container)
	beam.Attachment0 = attachment1
	beam.Attachment1 = attachment2
	beam.Color = ColorSequence.new(Color3.fromRGB(0, 255, 255))
	beam.FaceCamera = true
	beam.LightEmission = 1
	beam.Width0 = 2
	beam.Width1 = 0
	beam.Transparency = NumberSequence.new(0.25)
	self.State.Visuals[name:lower()] = container
end
function Modules.Waypoint:Add(name)
	if not name or name == "" then
		return DoNotif("You must provide a name for the waypoint.", 3)
	end
	local character = self.Services.Players.LocalPlayer.Character
	local hrp = character and character:FindFirstChild("HumanoidRootPart")
	if not hrp then
		return DoNotif("Cannot set waypoint: Character not found.", 3)
	end
	local key = name:lower()
	self.State.Waypoints[key] = hrp.CFrame
	self:_createVisual(name, hrp.CFrame)
	DoNotif("Waypoint '" .. name .. "' created at your position.", 2)
end
function Modules.Waypoint:Remove(name)
	if not name or name == "" then
		return DoNotif("You must provide a name to remove.", 3)
	end
	local key = name:lower()
	if not self.State.Waypoints[key] then
		return DoNotif("Waypoint '" .. name .. "' does not exist.", 3)
	end
	self.State.Waypoints[key] = nil
	self:_cleanupVisual(name)
	DoNotif("Waypoint '" .. name .. "' removed.", 2)
end
function Modules.Waypoint:Teleport(name)
	if not name or name == "" then
		return DoNotif("You must provide a name to teleport to.", 3)
	end
	local key = name:lower()
	local targetCFrame = self.State.Waypoints[key]
	if not targetCFrame then
		return DoNotif("Waypoint '" .. name .. "' does not exist.", 3)
	end
	local character = self.Services.Players.LocalPlayer.Character
	local hrp = character and character:FindFirstChild("HumanoidRootPart")
	if not hrp then
		return DoNotif("Cannot teleport: Character not found.", 3)
	end
	hrp.CFrame = targetCFrame + Vector3.new(0, 3, 0)
	DoNotif("Teleported to '" .. name .. "'.", 2)
end
function Modules.Waypoint:List()
	local waypointNames = {}
	for name in pairs(self.State.Waypoints) do
		table.insert(waypointNames, name)
	end
	if #waypointNames == 0 then
		return DoNotif("No waypoints have been set.", 3)
	end
	local message = "Waypoints: " .. table.concat(waypointNames, ", ")
	DoNotif(message, 5)
end
function Modules.Waypoint:Clear()
	for name in pairs(self.State.Waypoints) do
		self:_cleanupVisual(name)
	end
	self.State.Waypoints = {}
	DoNotif("All waypoints cleared.", 2)
end
RegisterCommand({
	Name = "waypoint",
	Aliases = { "wp" },
	Description = "Manages waypoints.",
}, function(args)
	local subCommand = args[1] and args[1]:lower()
	local name = args[2]
	if subCommand == "add" then
		Modules.Waypoint:Add(name)
	elseif subCommand == "remove" or subCommand == "del" then
		Modules.Waypoint:Remove(name)
	elseif subCommand == "tp" or subCommand == "goto" then
		Modules.Waypoint:Teleport(name)
	elseif subCommand == "list" then
		Modules.Waypoint:List()
	elseif subCommand == "clear" then
		Modules.Waypoint:Clear()
	else
		DoNotif("Usage: ;wp add,remove,tp,list", 4)
	end
end)
Modules.NPCEsp = {
	State = {
		IsEnabled = false,
		TrackedNPCs = {},
		Connections = {},
	},
	Config = {
		MAX_DISTANCE = 500,
		RESCAN_INTERVAL = 1.5,
		BOX_TRANSPARENCY = 0.45,
		COLOR_NEAR = Color3.fromRGB(255, 80, 80),
		COLOR_MID = Color3.fromRGB(255, 200, 50),
		COLOR_FAR = Color3.fromRGB(80, 180, 255),
		COLOR_NEAR_DIST = 50,
		COLOR_FAR_DIST = 300,
	},
}
function Modules.NPCEsp:_isValidNPC(model)
	if not model or not model.Parent then
		return false
	end
	if model == LocalPlayer.Character then
		return false
	end
	for _, plr in ipairs(Players:GetPlayers()) do
		if plr.Character == model then
			return false
		end
	end
	return model:FindFirstChild("HumanoidRootPart") ~= nil
end
function Modules.NPCEsp:_getDistanceColor(dist)
	local t = math.clamp(
		(dist - self.Config.COLOR_NEAR_DIST) / (self.Config.COLOR_FAR_DIST - self.Config.COLOR_NEAR_DIST),
		0,
		1
	)
	if t <= 0.5 then
		return self.Config.COLOR_NEAR:Lerp(self.Config.COLOR_MID, t * 2)
	else
		return self.Config.COLOR_MID:Lerp(self.Config.COLOR_FAR, (t - 0.5) * 2)
	end
end
function Modules.NPCEsp:_createESP(model)
	local hrp = model:FindFirstChild("HumanoidRootPart")
	if not hrp then
		return
	end
	local box = Instance.new("BoxHandleAdornment")
	box.Name = "NPC_ESP_Box"
	box.Adornee = hrp
	box.AlwaysOnTop = true
	box.ZIndex = 5
	box.Size = hrp.Size + Vector3.new(0.4, 0.4, 0.4)
	box.Color3 = self.Config.COLOR_NEAR
	box.Transparency = self.Config.BOX_TRANSPARENCY
	box.Parent = hrp
	local billboard = Instance.new("BillboardGui")
	billboard.Name = "NPC_ESP_Label"
	billboard.Adornee = hrp
	billboard.AlwaysOnTop = true
	billboard.Size = UDim2.new(0, 120, 0, 54)
	billboard.StudsOffset = Vector3.new(0, 3.5, 0)
	billboard.ResetOnSpawn = false
	billboard.Parent = hrp
	local nameLabel = Instance.new("TextLabel", billboard)
	nameLabel.Size = UDim2.new(1, 0, 0, 18)
	nameLabel.BackgroundTransparency = 1
	nameLabel.Font = Enum.Font.Code
	nameLabel.TextSize = 14
	nameLabel.TextStrokeTransparency = 0.4
	nameLabel.Text = model.Name
	local distLabel = Instance.new("TextLabel", billboard)
	distLabel.Size = UDim2.new(1, 0, 0, 16)
	distLabel.Position = UDim2.new(0, 0, 0, 19)
	distLabel.BackgroundTransparency = 1
	distLabel.Font = Enum.Font.Code
	distLabel.TextSize = 13
	distLabel.TextColor3 = Color3.fromRGB(180, 220, 180)
	distLabel.TextStrokeTransparency = 0.4
	distLabel.Text = "? studs"
	local hpLabel = Instance.new("TextLabel", billboard)
	hpLabel.Size = UDim2.new(1, 0, 0, 16)
	hpLabel.Position = UDim2.new(0, 0, 0, 36)
	hpLabel.BackgroundTransparency = 1
	hpLabel.Font = Enum.Font.Code
	hpLabel.TextSize = 13
	hpLabel.TextStrokeTransparency = 0.4
	hpLabel.Text = ""
	local conns = {}
	table.insert(
		conns,
		model.AncestryChanged:Connect(function()
			if not model.Parent then
				pcall(function()
					box:Destroy()
				end)
				pcall(function()
					billboard:Destroy()
				end)
				for _, c in ipairs(conns) do
					c:Disconnect()
				end
				self.State.TrackedNPCs[model] = nil
			end
		end)
	)
	self.State.TrackedNPCs[model] = {
		box = box,
		billboard = billboard,
		nameLabel = nameLabel,
		distLabel = distLabel,
		hpLabel = hpLabel,
		connections = conns,
	}
end
function Modules.NPCEsp:_removeESP(model)
	local data = self.State.TrackedNPCs[model]
	if not data then
		return
	end
	pcall(function()
		data.box:Destroy()
	end)
	pcall(function()
		data.billboard:Destroy()
	end)
	for _, c in ipairs(data.connections or {}) do
		pcall(function()
			c:Disconnect()
		end)
	end
	self.State.TrackedNPCs[model] = nil
end
function Modules.NPCEsp:_clearAll()
	for model in pairs(self.State.TrackedNPCs) do
		self:_removeESP(model)
	end
end
function Modules.NPCEsp:_scan()
	local seen = {}
	for _, desc in ipairs(Workspace:GetDescendants()) do
		if desc:IsA("Model") and self:_isValidNPC(desc) then
			seen[desc] = true
			if not self.State.TrackedNPCs[desc] then
				self:_createESP(desc)
			end
		end
	end
	for model in pairs(self.State.TrackedNPCs) do
		if not seen[model] then
			self:_removeESP(model)
		end
	end
end
function Modules.NPCEsp:Enable()
	if self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = true
	self:_scan()
	self.State.Connections.Render = RunService.RenderStepped:Connect(function()
		local camPos = CurrentCamera.CFrame.Position
		for model, data in pairs(self.State.TrackedNPCs) do
			if not model.Parent or not data.box.Parent then
				self:_removeESP(model)
				continue
			end
			local hrp = model:FindFirstChild("HumanoidRootPart")
			if not hrp then
				self:_removeESP(model)
				continue
			end
			local dist = (camPos - hrp.Position).Magnitude
			local inRange = self.Config.MAX_DISTANCE == 0 or dist <= self.Config.MAX_DISTANCE
			data.box.Visible = inRange
			data.billboard.Enabled = inRange
			if not inRange then
				continue
			end
			data.distLabel.Text = string.format("%.0f studs", dist)
			local col = self:_getDistanceColor(dist)
			data.box.Color3 = col
			data.nameLabel.TextColor3 = col
			local hum = model:FindFirstChildOfClass("Humanoid")
			if hum then
				local ratio = hum.MaxHealth > 0 and (hum.Health / hum.MaxHealth) or 0
				data.hpLabel.Text = string.format("HP: %d/%d", math.floor(hum.Health), math.floor(hum.MaxHealth))
				data.hpLabel.TextColor3 = ratio > 0.4 and Color3.fromRGB(100, 230, 120) or Color3.fromRGB(230, 80, 80)
			else
				data.hpLabel.Text = ""
			end
		end
	end)
	self.State.Connections.Scan = RunService.Heartbeat:Connect(function() end)
	task.spawn(function()
		while self.State.IsEnabled do
			task.wait(self.Config.RESCAN_INTERVAL)
			if self.State.IsEnabled then
				self:_scan()
			end
		end
	end)
	self.State.Connections.Added = Workspace.DescendantAdded:Connect(function(desc)
		if not self.State.IsEnabled then
			return
		end
		task.defer(function()
			if desc:IsA("Model") and self:_isValidNPC(desc) and not self.State.TrackedNPCs[desc] then
				self:_createESP(desc)
			end
		end)
	end)
	self.State.Connections.Removing = Workspace.DescendantRemoving:Connect(function(desc)
		if desc:IsA("Model") and self.State.TrackedNPCs[desc] then
			self:_removeESP(desc)
		end
	end)
	DoNotif("NPC ESP: Enabled", 2)
end
function Modules.NPCEsp:Disable()
	if not self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = false
	for _, conn in pairs(self.State.Connections) do
		pcall(function()
			conn:Disconnect()
		end)
	end
	self.State.Connections = {}
	self:_clearAll()
	DoNotif("NPC ESP: Disabled", 2)
end
function Modules.NPCEsp:Toggle()
	if self.State.IsEnabled then
		self:Disable()
	else
		self:Enable()
	end
end
function Modules.NPCEsp:Initialize()
	local module = self
	RegisterCommand({
		Name = "npcesp",
		Aliases = { "ne", "npcvis" },
		Description = "Toggles ESP highlighting and labels on all humanoid NPCs.",
	}, function()
		module:Toggle()
	end)
end
