		TS:Create(ui.FooterLabelMinimized, tweenInfo, { TextColor3 = Color3.fromRGB(100, 100, 110) }):Play()
		TS:Create(ui.ConfirmFrame, tweenInfo, { BackgroundColor3 = Color3.fromRGB(255, 255, 255) }):Play()
