	Description = "Highlights specific objects in the workspace by name.",
}, function(args)
	local name = table.concat(args, " ")
	if name == "clear" or name == "off" then
		Modules.ObjectESP:Clear()
	else
		Modules.ObjectESP:Toggle(name)
	end
end)
