	local VEL_MAX_STIFFNESS = 10.0
	local PAN_MAX_STIFFNESS = 10.0
	local FOV_MAX_STIFFNESS = 10.0
	local ROLL_MAX_STIFFNESS = 10.0
	local DOUBLE_TAP_TIME_THRESHOLD = 0.25
	local DOUBLE_TAP_DEBOUNCE_TIME = 0.1
	local DoFConstants = {
		FarIntensity = { ADJ = 0.1, MIN = 0.0, MAX = 1.0 },
		NearIntensity = { ADJ = 0.1, MIN = 0.0, MAX = 1.0 },
		FocusDistance = { ADJ = 20.0, MIN = 0.0, MAX = 200.0 },
		FocusRadius = { ADJ = 5.0, MIN = 0.0, MAX = 50.0 },
	}
	local Spring = {}
	Spring.__index = Spring
	function Spring.new(freq, pos)
		return setmetatable({ f = freq, p = pos, v = pos * 0 }, Spring)
	end
	function Spring:Update(dt, goal)
		local f = self.f * 2 * pi
		local offset = goal - self.p
		local decay = exp(-f * dt)
		local p1 = goal + (self.v * dt - offset * (f * dt + 1)) * decay
		local v1 = (f * dt * (offset * f - self.v) + self.v) * decay
		self.p, self.v = p1, v1
		return p1
	end
	function Spring:SetFreq(freq)
		self.f = freq
	end
	function Spring:Reset(pos)
		self.p = pos
		self.v = pos * 0
	end
	local cameraPos = Vector3.new()
	local cameraRot = Vector3.new()
	local cameraFov = 0
	local velSpring = Spring.new(VEL_STIFFNESS, Vector3.new())
	local panSpring = Spring.new(PAN_STIFFNESS, Vector2.new())
	local fovSpring = Spring.new(FOV_STIFFNESS, 0)
	local rollSpring = Spring.new(ROLL_STIFFNESS, 0)
	local FreecamDepthOfField = nil
	local postEffects = {}
	local lastPressTime = {}
	local lastResetTime = 0
	local Input = {}
	do
		local K_CURVATURE = 2.0
		local K_DEADZONE = 0.15
		local function fCurve(x)
			return (exp(K_CURVATURE * x) - 1) / (exp(K_CURVATURE) - 1)
		end
		local function fDeadzone(x)
			return fCurve((x - K_DEADZONE) / (1 - K_DEADZONE))
		end
		local function thumbstickCurve(x)
			return sign(x) * clamp(fDeadzone(abs(x)), 0, 1)
		end
		local gamepad = {
			ButtonX = 0,
			ButtonY = 0,
			DPadDown = 0,
			DPadUp = 0,
			DPadLeft = 0,
			DPadRight = 0,
			ButtonL2 = 0,
			ButtonR2 = 0,
			ButtonL1 = 0,
			ButtonR1 = 0,
			Thumbstick1 = Vector2.new(),
			Thumbstick2 = Vector2.new(),
		}
		local keyboard = {
			W = 0,
			A = 0,
			S = 0,
			D = 0,
			E = 0,
			Q = 0,
			U = 0,
			H = 0,
			J = 0,
			K = 0,
			I = 0,
			Y = 0,
			Up = 0,
			Down = 0,
			Left = 0,
			Right = 0,
			LeftShift = 0,
			RightShift = 0,
			Z = 0,
			C = 0,
			Comma = 0,
			Period = 0,
			LeftBracket = 0,
			RightBracket = 0,
			Semicolon = 0,
			Quote = 0,
			V = 0,
			B = 0,
			N = 0,
			M = 0,
			BackSlash = 0,
			Minus = 0,
			Equals = 0,
		}
		local mouse = { Delta = Vector2.new(), MouseWheel = 0 }
		local DEFAULT_FPS = 60
		local NAV_GAMEPAD_SPEED = Vector3.new(1, 1, 1)
		local NAV_KEYBOARD_SPEED = Vector3.new(1, 1, 1)
		local PAN_MOUSE_SPEED = Vector2.new(1, 1) * (pi / 64)
		local PAN_MOUSE_SPEED_DT = PAN_MOUSE_SPEED / DEFAULT_FPS
		local PAN_GAMEPAD_SPEED = Vector2.new(1, 1) * (pi / 8)
		local FOV_WHEEL_SPEED = 1.0
		local FOV_WHEEL_SPEED_DT = FOV_WHEEL_SPEED / DEFAULT_FPS
		local FOV_GAMEPAD_SPEED = 0.25
		local ROLL_GAMEPAD_SPEED = 1.0
		local ROLL_KEYBOARD_SPEED = 1.0
		local NAV_ADJ_SPEED = 0.75
		local NAV_MIN_SPEED = 0.01
		local NAV_MAX_SPEED = 4.0
		local NAV_SHIFT_MUL = 0.25
		local FOV_ADJ_SPEED = 0.75
		local FOV_MIN_SPEED = 0.01
		local FOV_MAX_SPEED = 4.0
		local ROLL_ADJ_SPEED = 0.75
		local ROLL_MIN_SPEED = 0.01
		local ROLL_MAX_SPEED = 4.0
		local navSpeed = 1
		local fovSpeed = 1
		local rollSpeed = 1
		local function Zero(t)
			for k, v in pairs(t) do
				t[k] = v * 0
			end
		end
		local function resetKeys(keys, tbl)
			for keyEnum in pairs(keys) do
				if tbl[keyEnum.Name] then
					tbl[keyEnum.Name] = 0
				end
			end
		end
		function Input.Vel(dt)
			navSpeed = clamp(
				navSpeed + dt * (keyboard.Up - keyboard.Down + gamepad.DPadUp - gamepad.DPadDown) * NAV_ADJ_SPEED,
				NAV_MIN_SPEED,
				NAV_MAX_SPEED
			)
			local kGamepad = Vector3.new(
				thumbstickCurve(gamepad.Thumbstick1.X),
				thumbstickCurve(gamepad.ButtonR2) - thumbstickCurve(gamepad.ButtonL2),
				thumbstickCurve(-gamepad.Thumbstick1.Y)
			) * NAV_GAMEPAD_SPEED
			local kKeyboard = Vector3.new(
				keyboard.D - keyboard.A + keyboard.K - keyboard.H,
				keyboard.E - keyboard.Q + keyboard.I - keyboard.Y,
				keyboard.S - keyboard.W + keyboard.J - keyboard.U
			) * NAV_KEYBOARD_SPEED
			local shift = UserInputService:IsKeyDown(Enum.KeyCode.LeftShift)
				or UserInputService:IsKeyDown(Enum.KeyCode.RightShift)
			return (kGamepad + kKeyboard) * (navSpeed * (shift and NAV_SHIFT_MUL or 1))
		end
		function Input.Pan(dt)
			local kGamepad = Vector2.new(
				thumbstickCurve(gamepad.Thumbstick2.Y),
				thumbstickCurve(-gamepad.Thumbstick2.X)
			) * PAN_GAMEPAD_SPEED
			local kMouse
			if dt > 0 then
				kMouse = (mouse.Delta / dt) * PAN_MOUSE_SPEED_DT
			else
				kMouse = mouse.Delta * PAN_MOUSE_SPEED
			end
			mouse.Delta = Vector2.new()
			return kGamepad + kMouse
		end
		function Input.Fov(dt)
			fovSpeed = clamp(
				fovSpeed + dt * (keyboard.Right - keyboard.Left + gamepad.DPadRight - gamepad.DPadLeft) * FOV_ADJ_SPEED,
				FOV_MIN_SPEED,
				FOV_MAX_SPEED
			)
			local kGamepad = (gamepad.ButtonX - gamepad.ButtonY) * FOV_GAMEPAD_SPEED
			local kMouse
			if dt > 0 then
				kMouse = (mouse.MouseWheel / dt) * FOV_WHEEL_SPEED_DT
			else
				kMouse = mouse.MouseWheel * FOV_WHEEL_SPEED
			end
			mouse.MouseWheel = 0
			return (kGamepad + kMouse) * fovSpeed
		end
		function Input.Roll(dt)
			rollSpeed = clamp(
				rollSpeed + dt * (keyboard.Period - keyboard.Comma) * ROLL_ADJ_SPEED,
				ROLL_MIN_SPEED,
				ROLL_MAX_SPEED
			)
			local kGamepad = (gamepad.ButtonR1 - gamepad.ButtonL1) * ROLL_GAMEPAD_SPEED
			local kKeyboard = (keyboard.C - keyboard.Z) * ROLL_KEYBOARD_SPEED
			return (kGamepad + kKeyboard) * rollSpeed
		end
		function Input.SpringControl(dt)
			if FreecamDepthOfField and FreecamDepthOfField.Parent then
				local shiftDown = UserInputService:IsKeyDown(Enum.KeyCode.LeftShift)
					or UserInputService:IsKeyDown(Enum.KeyCode.RightShift)
				local ctrlDown = UserInputService:IsKeyDown(Enum.KeyCode.LeftControl)
					or UserInputService:IsKeyDown(Enum.KeyCode.RightControl)
				if shiftDown or ctrlDown then
					return
				end
			end
			VEL_STIFFNESS = clamp(
				VEL_STIFFNESS + dt * (keyboard.RightBracket - keyboard.LeftBracket) * VEL_ADJ_STIFFNESS,
				VEL_MIN_STIFFNESS,
				VEL_MAX_STIFFNESS
			)
			velSpring:SetFreq(VEL_STIFFNESS)
			PAN_STIFFNESS = clamp(
				PAN_STIFFNESS + dt * (keyboard.Quote - keyboard.Semicolon) * PAN_ADJ_STIFFNESS,
				PAN_MIN_STIFFNESS,
				PAN_MAX_STIFFNESS
			)
			panSpring:SetFreq(PAN_STIFFNESS)
			FOV_STIFFNESS = clamp(
				FOV_STIFFNESS + dt * (keyboard.B - keyboard.V) * FOV_ADJ_STIFFNESS,
				FOV_MIN_STIFFNESS,
				FOV_MAX_STIFFNESS
			)
			fovSpring:SetFreq(FOV_STIFFNESS)
			ROLL_STIFFNESS = clamp(
				ROLL_STIFFNESS + dt * (keyboard.M - keyboard.N) * ROLL_ADJ_STIFFNESS,
				ROLL_MIN_STIFFNESS,
				ROLL_MAX_STIFFNESS
			)
			rollSpring:SetFreq(ROLL_STIFFNESS)
		end
		function Input.DoF(dt)
			local shiftDown = UserInputService:IsKeyDown(Enum.KeyCode.LeftShift)
				or UserInputService:IsKeyDown(Enum.KeyCode.RightShift)
			local ctrlDown = UserInputService:IsKeyDown(Enum.KeyCode.LeftControl)
				or UserInputService:IsKeyDown(Enum.KeyCode.RightControl)
			if shiftDown then
				FreecamDepthOfField.FarIntensity = clamp(
					FreecamDepthOfField.FarIntensity
						+ dt * (keyboard.RightBracket - keyboard.LeftBracket) * DoFConstants.FarIntensity.ADJ,
					DoFConstants.FarIntensity.MIN,
					DoFConstants.FarIntensity.MAX
				)
				FreecamDepthOfField.InFocusRadius = clamp(
					FreecamDepthOfField.InFocusRadius
						+ dt * (keyboard.Equals - keyboard.Minus) * DoFConstants.FocusRadius.ADJ,
					DoFConstants.FocusRadius.MIN,
					DoFConstants.FocusRadius.MAX
				)
			elseif ctrlDown then
				FreecamDepthOfField.NearIntensity = clamp(
					FreecamDepthOfField.NearIntensity
						+ dt * (keyboard.RightBracket - keyboard.LeftBracket) * DoFConstants.NearIntensity.ADJ,
					DoFConstants.NearIntensity.MIN,
					DoFConstants.NearIntensity.MAX
				)
			else
				FreecamDepthOfField.FocusDistance = clamp(
					FreecamDepthOfField.FocusDistance
						+ dt * (keyboard.Equals - keyboard.Minus) * DoFConstants.FocusDistance.ADJ,
					DoFConstants.FocusDistance.MIN,
					DoFConstants.FocusDistance.MAX
				)
			end
		end
		do
			local function handleDoubleTapReset(keyCode)
				local now = os.clock()
				local prev = lastPressTime[keyCode]
				local elapsed = prev and (now - prev) or -1
				if prev and elapsed <= DOUBLE_TAP_TIME_THRESHOLD then
					if (now - lastResetTime) >= DOUBLE_TAP_DEBOUNCE_TIME then
						cameraRot = Vector3.new(cameraRot.X, cameraRot.Y, 0)
						rollSpring:Reset(0)
						resetKeys(FREECAM_TILT_RESET_GP, gamepad)
						resetKeys(FREECAM_TILT_RESET_KB, keyboard)
						lastResetTime = now
					end
				end
				lastPressTime[keyCode] = now
			end
			local function Keypress(action, state, input)
				keyboard[input.KeyCode.Name] = state == Enum.UserInputState.Begin and 1 or 0
				if FREECAM_TILT_RESET_KB[input.KeyCode] and input.UserInputState == Enum.UserInputState.Begin then
					handleDoubleTapReset(input.KeyCode)
				end
				if FREECAM_DOF_TOGGLE[input.KeyCode] and input.UserInputState == Enum.UserInputState.Begin then
					if FreecamDepthOfField and FreecamDepthOfField.Parent then
						if not FreecamDepthOfField.Enabled then
							postEffects = {}
							local function disableDoFs(parent)
								for _, effect in ipairs(parent:GetChildren()) do
									if
										effect:IsA("DepthOfFieldEffect")
										and effect ~= FreecamDepthOfField
										and effect.Enabled
									then
										postEffects[#postEffects + 1] = effect
										effect.Enabled = false
									end
								end
							end
							disableDoFs(Camera)
							disableDoFs(Lighting)
						else
							for _, effect in ipairs(postEffects) do
								if effect.Parent then
									effect.Enabled = true
								end
							end
							postEffects = {}
						end
						FreecamDepthOfField.Enabled = not FreecamDepthOfField.Enabled
						resetKeys(FREECAM_DOF_TOGGLE, keyboard)
					end
				end
				return Enum.ContextActionResult.Sink
			end
			local function GpButton(action, state, input)
				gamepad[input.KeyCode.Name] = state == Enum.UserInputState.Begin and 1 or 0
				if FREECAM_TILT_RESET_GP[input.KeyCode] and input.UserInputState == Enum.UserInputState.Begin then
					handleDoubleTapReset(input.KeyCode)
				end
				return Enum.ContextActionResult.Sink
			end
			local function MousePan(action, state, input)
				local delta = input.Delta
				mouse.Delta = Vector2.new(-delta.Y, -delta.X)
				return Enum.ContextActionResult.Sink
			end
			local function Thumb(action, state, input)
				gamepad[input.KeyCode.Name] = input.Position
				return Enum.ContextActionResult.Sink
			end
			local function Trigger(action, state, input)
				gamepad[input.KeyCode.Name] = input.Position.Z
				return Enum.ContextActionResult.Sink
			end
			local function MouseWheel(action, state, input)
				mouse[input.UserInputType.Name] = -input.Position.Z
				return Enum.ContextActionResult.Sink
			end
			function Input.StartCapture()
				ContextActionService:BindActionAtPriority(
					"FreecamKeyboard",
					Keypress,
					false,
					INPUT_PRIORITY,
					Enum.KeyCode.W,
					Enum.KeyCode.U,
					Enum.KeyCode.A,
					Enum.KeyCode.H,
					Enum.KeyCode.S,
					Enum.KeyCode.J,
					Enum.KeyCode.D,
					Enum.KeyCode.K,
					Enum.KeyCode.E,
					Enum.KeyCode.I,
					Enum.KeyCode.Q,
					Enum.KeyCode.Y
				)
				ContextActionService:BindActionAtPriority(
					"FreecamKeyboardControlSpeed",
					Keypress,
					false,
					INPUT_PRIORITY,
					Enum.KeyCode.Up,
					Enum.KeyCode.Down,
					Enum.KeyCode.Left,
					Enum.KeyCode.Right
				)
				ContextActionService:BindActionAtPriority(
					"FreecamGamepadControlSpeed",
					GpButton,
					false,
					INPUT_PRIORITY,
					Enum.KeyCode.DPadUp,
					Enum.KeyCode.DPadDown,
					Enum.KeyCode.DPadLeft,
					Enum.KeyCode.DPadRight
				)
				ContextActionService:BindActionAtPriority(
					"FreecamKeyboardTiltControl",
					Keypress,
					false,
					INPUT_PRIORITY,
					Enum.KeyCode.Z,
					Enum.KeyCode.C
				)
				ContextActionService:BindActionAtPriority(
					"FreecamGamepadTiltControl",
					GpButton,
					false,
					INPUT_PRIORITY,
					Enum.KeyCode.ButtonL1,
					Enum.KeyCode.ButtonR1
				)
				ContextActionService:BindActionAtPriority(
					"FreecamKeyboardTiltControlSpeed",
					Keypress,
					false,
					INPUT_PRIORITY,
					Enum.KeyCode.Comma,
					Enum.KeyCode.Period
				)
				ContextActionService:BindActionAtPriority(
					"FreecamKeyboardSmoothnessControl",
					Keypress,
					false,
					INPUT_PRIORITY,
					Enum.KeyCode.LeftBracket,
					Enum.KeyCode.RightBracket,
					Enum.KeyCode.Semicolon,
					Enum.KeyCode.Quote,
					Enum.KeyCode.V,
					Enum.KeyCode.B,
					Enum.KeyCode.N,
					Enum.KeyCode.M
				)
				ContextActionService:BindActionAtPriority(
					"FreecamKeyboardDoFToggle",
					Keypress,
					false,
					INPUT_PRIORITY,
					Enum.KeyCode.BackSlash
				)
				ContextActionService:BindActionAtPriority(
					"FreecamKeyboardDoFControls",
					Keypress,
					false,
					INPUT_PRIORITY,
					Enum.KeyCode.Minus,
					Enum.KeyCode.Equals
				)
				ContextActionService:BindActionAtPriority(
					"FreecamMousePan",
					MousePan,
					false,
					INPUT_PRIORITY,
					Enum.UserInputType.MouseMovement
				)
				ContextActionService:BindActionAtPriority(
					"FreecamMouseWheel",
					MouseWheel,
					false,
					INPUT_PRIORITY,
					Enum.UserInputType.MouseWheel
				)
				ContextActionService:BindActionAtPriority(
					"FreecamGamepadButton",
					GpButton,
					false,
					INPUT_PRIORITY,
					Enum.KeyCode.ButtonX,
					Enum.KeyCode.ButtonY
				)
				ContextActionService:BindActionAtPriority(
					"FreecamGamepadTrigger",
					Trigger,
					false,
					INPUT_PRIORITY,
					Enum.KeyCode.ButtonR2,
					Enum.KeyCode.ButtonL2
				)
				ContextActionService:BindActionAtPriority(
					"FreecamGamepadThumbstick",
					Thumb,
					false,
					INPUT_PRIORITY,
					Enum.KeyCode.Thumbstick1,
					Enum.KeyCode.Thumbstick2
				)
			end
			function Input.StopCapture()
				navSpeed = 1
				fovSpeed = 1
				rollSpeed = 1
				Zero(gamepad)
				Zero(keyboard)
				Zero(mouse)
				ContextActionService:UnbindAction("FreecamKeyboard")
				ContextActionService:UnbindAction("FreecamKeyboardControlSpeed")
				ContextActionService:UnbindAction("FreecamGamepadControlSpeed")
				ContextActionService:UnbindAction("FreecamKeyboardTiltControl")
				ContextActionService:UnbindAction("FreecamGamepadTiltControl")
				ContextActionService:UnbindAction("FreecamKeyboardTiltControlSpeed")
				ContextActionService:UnbindAction("FreecamKeyboardSmoothnessControl")
				ContextActionService:UnbindAction("FreecamKeyboardDoFToggle")
				ContextActionService:UnbindAction("FreecamKeyboardDoFControls")
				ContextActionService:UnbindAction("FreecamMousePan")
				ContextActionService:UnbindAction("FreecamMouseWheel")
				ContextActionService:UnbindAction("FreecamGamepadButton")
				ContextActionService:UnbindAction("FreecamGamepadTrigger")
				ContextActionService:UnbindAction("FreecamGamepadThumbstick")
			end
		end
	end
	local function StepFreecam(dt)
		Input.SpringControl(dt)
		if FreecamDepthOfField and FreecamDepthOfField.Parent and FreecamDepthOfField.Enabled then
			Input.DoF(dt)
		end
		local vel = velSpring:Update(dt, Input.Vel(dt))
		local pan = panSpring:Update(dt, Input.Pan(dt))
		local fov = fovSpring:Update(dt, Input.Fov(dt))
		local roll = rollSpring:Update(dt, Input.Roll(dt))
		local zoomFactor = sqrt(tan(rad(70 / 2)) / tan(rad(cameraFov / 2)))
		cameraFov = clamp(cameraFov + fov * FOV_GAIN * (dt / zoomFactor), 1, 120)
		local panVec = pan * PAN_GAIN * (dt / zoomFactor)
		cameraRot = Vector3.new(
			cameraRot.X + panVec.X,
			cameraRot.Y + panVec.Y,
			cameraRot.Z + roll * ROLL_GAIN * (dt / zoomFactor)
		)
		cameraRot =
			Vector3.new(clamp(cameraRot.X, -PITCH_LIMIT, PITCH_LIMIT), cameraRot.Y % (2 * pi), cameraRot.Z % (2 * pi))
		local cameraCFrame = CFrame.new(cameraPos)
			* CFrame.fromOrientation(cameraRot.X, cameraRot.Y, cameraRot.Z)
			* CFrame.new(vel * NAV_GAIN * dt)
		cameraPos = cameraCFrame.Position
		Camera.CFrame = cameraCFrame
		Camera.Focus = cameraCFrame * CFrame.new(0, 0, -10)
		Camera.FieldOfView = cameraFov
	end
	local function CheckMouseLockAvailability()
		local devAllowsMouseLock = LocalPlayer.DevEnableMouseLock
		local devMovementScriptable = LocalPlayer.DevComputerMovementMode == Enum.DevComputerMovementMode.Scriptable
		local userMouseLockEnabled = GameSettings.ControlMode == Enum.ControlMode.MouseLockSwitch
		local userClickToMove = GameSettings.ComputerMovementMode == Enum.ComputerMovementMode.ClickToMove
		return devAllowsMouseLock and userMouseLockEnabled and not userClickToMove and not devMovementScriptable
	end
	local PlayerState = {}
	do
		local savedMouseBehavior, savedCameraType, savedCameraFocus
		local savedCameraCFrame, savedCameraFov
		local setCores = {
			BadgesNotificationsActive = true,
			PointsNotificationsActive = true,
		}
		function PlayerState.Push()
			for name in pairs(setCores) do
				local ok, val = pcall(function()
					return StarterGui:GetCore(name)
				end)
				setCores[name] = ok and val or true
				pcall(function()
					StarterGui:SetCore(name, false)
				end)
			end
			savedCameraFov = Camera.FieldOfView
			Camera.FieldOfView = 70
			savedCameraType = Camera.CameraType
			Camera.CameraType = Enum.CameraType.Custom
			savedCameraCFrame = Camera.CFrame
			savedCameraFocus = Camera.Focus
			if CheckMouseLockAvailability() then
				savedMouseBehavior = Enum.MouseBehavior.Default
			else
				savedMouseBehavior = UserInputService.MouseBehavior
			end
			UserInputService.MouseBehavior = Enum.MouseBehavior.Default
		end
		function PlayerState.Pop()
			for name, isEnabled in pairs(setCores) do
				pcall(function()
					StarterGui:SetCore(name, isEnabled)
				end)
			end
			Camera.FieldOfView = savedCameraFov
			Camera.CameraType = savedCameraType
			Camera.CFrame = savedCameraCFrame
			Camera.Focus = savedCameraFocus
			UserInputService.MouseBehavior = savedMouseBehavior
			savedCameraFov, savedCameraType = nil, nil
			savedCameraCFrame, savedCameraFocus = nil, nil
			savedMouseBehavior = nil
		end
	end
	local function StartFreecam()
		local cf = Camera.CFrame
		local ex, ey, ez = cf:ToEulerAnglesYXZ()
		cameraRot = Vector3.new(ex, ey, ez)
		cameraPos = cf.Position
		cameraFov = Camera.FieldOfView
		velSpring:Reset(Vector3.new())
		panSpring:Reset(Vector2.new())
		fovSpring:Reset(0)
		rollSpring:Reset(0)
		VEL_STIFFNESS = 1.5
		PAN_STIFFNESS = 1.0
		FOV_STIFFNESS = 4.0
		ROLL_STIFFNESS = 1.0
		PlayerState.Push()
		if not FreecamDepthOfField or not FreecamDepthOfField.Parent then
			FreecamDepthOfField = Instance.new("DepthOfFieldEffect")
			FreecamDepthOfField.Enabled = false
			FreecamDepthOfField.Name = "FreecamDepthOfField"
			FreecamDepthOfField.Parent = Camera
		end
		RunService:BindToRenderStep("Freecam", Enum.RenderPriority.Camera.Value, StepFreecam)
		Input.StartCapture()
	end
	local function StopFreecam()
		if FreecamDepthOfField and FreecamDepthOfField.Parent then
			if FreecamDepthOfField.Enabled then
				for _, effect in ipairs(postEffects) do
					if effect.Parent then
						effect.Enabled = true
					end
				end
				postEffects = {}
			end
			FreecamDepthOfField.Enabled = false
		end
		Input.StopCapture()
		RunService:UnbindFromRenderStep("Freecam")
		PlayerState.Pop()
	end
	do
		local enabled = false
		local function ToggleFreecam()
			enabled = not enabled
			if enabled then
				StartFreecam()
			else
				StopFreecam()
			end
			setFreecamAttribute(enabled)
		end
		local function CheckMacro(macro)
			for i = 1, #macro - 1 do
				if not UserInputService:IsKeyDown(macro[i]) then
					return
				end
			end
			ToggleFreecam()
		end
		local function HandleActivationInput(action, state, input)
			if state == Enum.UserInputState.Begin then
				if input.KeyCode == FREECAM_MACRO_KB[#FREECAM_MACRO_KB] then
					CheckMacro(FREECAM_MACRO_KB)
				end
			end
			return Enum.ContextActionResult.Pass
		end
		ContextActionService:BindActionAtPriority(
			"FreecamToggle",
			HandleActivationInput,
			false,
			TOGGLE_INPUT_PRIORITY,
			FREECAM_MACRO_KB[#FREECAM_MACRO_KB]
		)
		setFreecamAttribute(enabled)
		attrHolder:GetAttributeChangedSignal(FREECAM_ENABLED_ATTRIBUTE_NAME):Connect(function()
			local val = getFreecamAttribute()
			if typeof(val) ~= "boolean" then
				setFreecamAttribute(enabled)
				return
			end
			if val ~= enabled then
				enabled = val
				if enabled then
					StartFreecam()
				else
					StopFreecam()
				end
			end
		end)
	end
	pcall(function()
		StarterGui:SetCore("SendNotification", {
			Title = "Freecam Enabled",
			Text = "Press Shift+P to toggle",
		})
	end)
end)
Modules.VisualClear = {
	State = {
		IsEnabled = false,
		OriginalStates = {},
	},
}
function Modules.VisualClear:Toggle()
	self.State.IsEnabled = not self.State.IsEnabled
	if self.State.IsEnabled then
		for _, effect in ipairs(Lighting:GetChildren()) do
			if effect:IsA("PostProcessEffect") then
				self.State.OriginalStates[effect] = effect.Enabled
				effect.Enabled = false
			end
		end
		for _, effect in ipairs(Workspace.CurrentCamera:GetChildren()) do
			if effect:IsA("PostProcessEffect") then
				self.State.OriginalStates[effect] = effect.Enabled
				effect.Enabled = false
			end
		end
		DoNotif("Visual Clear: ENABLED (Blur/Bloom Removed)", 2)
	else
		for effect, state in pairs(self.State.OriginalStates) do
			if effect and effect.Parent then
				effect.Enabled = state
			end
		end
		table.clear(self.State.OriginalStates)
		DoNotif("Visual Clear: DISABLED", 2)
	end
end
