				if obj:IsA("ClickDetector") then
					obj.MaxActivationDistance = 1e7
					if fireclickdetector then
						fireclickdetector(obj)
					end
				end
			end
		end)
		DoNotif("Interstellar: Global Interaction ACTIVE", 2)
	else
