		local n = tonumber(v)
		if n and n > 0 and n <= 25 then
			S.AttackCPS = n
		end
		return S.AttackCPS
	end)
	inputRow(ColLeft, "Hover Dist", S.HoverDist, function(v)
		local n = tonumber(v)
		if n and n >= 1 and n <= 25 then
			S.HoverDist = n
		end
		return S.HoverDist
	end)
	inputRow(ColLeft, "Max Dist", S.MaxDistance, function(v)
		local n = tonumber(v)
		if n and n > 0 then
			S.MaxDistance = n
		end
		return S.MaxDistance
	end)
	sectionTitle(ColMid, " EVASION (break their lock)")
	toggleBtn(ColMid, "Evasion", false, function(v)
		S.EvasionEnabled = v
		updateStatus()
	end)
	local modeRow = Instance.new("Frame", ColMid)
	modeRow.Size = UDim2.new(1, 0, 0, 28)
	modeRow.BackgroundTransparency = 1
	local modes = { "Jitter", "Spin", "Vertical", "Combo" }
	local modeIdx = 1
	local modeBtn = btn(modeRow, "Mode: Jitter", UDim2.new(1, 0, 1, 0))
	modeBtn.MouseButton1Click:Connect(function()
		modeIdx = (modeIdx % #modes) + 1
		S.EvasionMode = modes[modeIdx]
		modeBtn.Text = "Mode: " .. S.EvasionMode
		updateStatus()
	end)
	inputRow(ColMid, "Jitter Radius", S.JitterRadius, function(v)
		local n = tonumber(v)
		if n and n > 0 and n <= 20 then
			S.JitterRadius = n
		end
		return S.JitterRadius
	end)
	inputRow(ColMid, "Spin Speed", S.SpinSpeed, function(v)
		local n = tonumber(v)
		if n and n > 0 then
			S.SpinSpeed = n
		end
		return S.SpinSpeed
	end)
	sectionTitle(ColMid, " VOID BAIT")
	toggleBtn(ColMid, "Void Bait", false, function(v)
		S.VoidBait = v
		updateStatus()
	end)
	inputRow(ColMid, "Bait Margin", S.VoidMargin, function(v)
		local n = tonumber(v)
		if n and n > 0 then
			S.VoidMargin = n
		end
		return S.VoidMargin
	end)
	sectionTitle(ColRight, " BOX REACH")
	toggleBtn(ColRight, "BoxReach", false, function(v)
		S.BoxReach = v
		if v then
			applyBoxReach()
		else
			resetReach()
		end
	end)
	inputRow(ColRight, "Size (x,y,z)", "15,15,15", function(t)
		if t then
			local n = {}
			for m in t:gmatch("[^,]+") do
				table.insert(n, tonumber(m))
			end
			if #n == 3 and n[1] and n[2] and n[3] then
				S.BoxSize = Vector3.new(n[1], n[2], n[3])
				if S.BoxReach then
					applyBoxReach()
				end
			end
		end
		return string.format("%.0f,%.0f,%.0f", S.BoxSize.X, S.BoxSize.Y, S.BoxSize.Z)
	end)
	local partsLabel = Instance.new("TextLabel", ColRight)
	partsLabel.Size = UDim2.new(1, 0, 0, 16)
	partsLabel.BackgroundTransparency = 1
	partsLabel.Font = T.Font
	partsLabel.TextSize = 12
	partsLabel.TextColor3 = T.TextDim
	partsLabel.Text = "Tool Parts:"
	partsLabel.TextXAlignment = Enum.TextXAlignment.Left
	local partsScroll = Instance.new("ScrollingFrame", ColRight)
	partsScroll.Size = UDim2.new(1, 0, 0, 100)
	partsScroll.BackgroundColor3 = T.Panel
	partsScroll.BorderSizePixel = 0
	partsScroll.ScrollBarThickness = 4
	partsScroll.CanvasSize = UDim2.new(0, 0, 0, 0)
	corner(partsScroll, 5)
	local partsLayout = Instance.new("UIListLayout", partsScroll)
	partsLayout.Padding = UDim.new(0, 4)
	partsLayout.SortOrder = Enum.SortOrder.LayoutOrder
	partsLayout:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(function()
		partsScroll.CanvasSize = UDim2.new(0, 0, 0, partsLayout.AbsoluteContentSize.Y + 8)
	end)
	do
		local dragging, dragStart, startPos = false, nil, nil
		Bar.InputBegan:Connect(function(i)
			if i.UserInputType == Enum.UserInputType.MouseButton1 then
				dragging = true
				dragStart = i.Position
				startPos = Win.Position
				i.Changed:Connect(function()
					if i.UserInputState == Enum.UserInputState.End then
						dragging = false
					end
				end)
			end
		end)
		track(UIS.InputChanged:Connect(function(i)
			if dragging and i.UserInputType == Enum.UserInputType.MouseMovement then
				local d = i.Position - dragStart
				Win.Position =
					UDim2.new(startPos.X.Scale, startPos.X.Offset + d.X, startPos.Y.Scale, startPos.Y.Offset + d.Y)
			end
		end))
	end
	CloseBtn.MouseButton1Click:Connect(function()
		Screen:Destroy()
		for _, c in ipairs(Connections) do
			pcall(function()
				c:Disconnect()
			end)
		end
	end)
	MinBtn.MouseButton1Click:Connect(function()
		isMinimized = not isMinimized
		Content.Visible = not isMinimized
		StatusBar.Visible = not isMinimized
		Win.Size = isMinimized and UDim2.fromOffset(WIN_W, 32) or UDim2.fromOffset(WIN_W, WIN_H)
		MinBtn.Text = isMinimized and "+" or "−"
	end)
	track(UIS.InputBegan:Connect(function(i, gp)
		if gp then
			return
		end
		if i.KeyCode == Enum.KeyCode.RightAlt then
			S.BotEnabled = not S.BotEnabled
			botToggleSet(S.BotEnabled)
			DoNotif("Rage Bot: " .. (S.BotEnabled and "ON" or "OFF"), 1)
			updateStatus()
		end
		if i.KeyCode == Enum.KeyCode.RightControl then
			S.EvasionEnabled = not S.EvasionEnabled
			DoNotif("Evasion: " .. (S.EvasionEnabled and "ON" or "OFF"), 1)
			updateStatus()
		end
	end))
	function resetReach(tool)
		tool = tool or equippedTool
		if not tool then
			return
		end
		for _, d in ipairs(tool:GetDescendants()) do
			if d:IsA("BasePart") then
				local o = d:FindFirstChild("__OrigSize")
				if o then
					d.Size = o.Value
					o:Destroy()
				end
			end
		end
		if reachBox then
			reachBox:Destroy()
			reachBox = nil
		end
	end
	function applyBoxReach()
		if not S.BoxReach or not S.SelectedPart or not S.SelectedPart.Parent then
			return
		end
		local p = S.SelectedPart
		if not p:FindFirstChild("__OrigSize") then
			local v = Instance.new("Vector3Value", p)
			v.Name = "__OrigSize"
			v.Value = p.Size
		end
		p.Size = S.BoxSize
		if reachBox then
			reachBox:Destroy()
		end
		reachBox = Instance.new("SelectionBox")
		reachBox.Adornee = p
		reachBox.LineThickness = 0.025
		reachBox.Color3 = T.Accent
		reachBox.SurfaceTransparency = 0.85
		reachBox.SurfaceColor3 = T.Accent
		reachBox.Parent = workspace
	end
	local selectedPartBtn = nil
	function populateParts()
		for _, c in ipairs(partsScroll:GetChildren()) do
			if c:IsA("TextButton") then
				c:Destroy()
			end
		end
		S.SelectedPart = nil
		selectedPartBtn = nil
		if not equippedTool then
			return
		end
		for _, p in ipairs(equippedTool:GetDescendants()) do
			if p:IsA("BasePart") then
				local b = Instance.new("TextButton", partsScroll)
				b.Size = UDim2.new(1, -6, 0, 22)
				b.BackgroundColor3 = T.Btn
				b.Font = T.Font
				b.TextSize = 12
				b.TextColor3 = T.Text
				b.Text = p.Name
				corner(b, 4)
				b.MouseButton1Click:Connect(function()
					resetReach(equippedTool)
					S.SelectedPart = p
					if S.BoxReach then
						applyBoxReach()
					end
					if selectedPartBtn then
						selectedPartBtn.BackgroundColor3 = T.Btn
					end
					b.BackgroundColor3 = T.AccentDim
					selectedPartBtn = b
				end)
			end
		end
	end
	local function cleanCharConns()
		for _, c in ipairs(charConns) do
			pcall(function()
				c:Disconnect()
			end)
		end
		charConns = {}
	end
	local function trackTool(char)
		cleanCharConns()
		resetReach(equippedTool)
		equippedTool = char:FindFirstChildOfClass("Tool")
		populateParts()
		table.insert(
			charConns,
			char.ChildAdded:Connect(function(c)
				if c:IsA("Tool") then
					resetReach(equippedTool)
					equippedTool = c
					populateParts()
				end
			end)
		)
		table.insert(
			charConns,
			char.ChildRemoved:Connect(function(c)
				if c == equippedTool then
					resetReach(equippedTool)
					equippedTool = nil
					populateParts()
				end
			end)
		)
	end
	if LocalPlayer.Character then
		trackTool(LocalPlayer.Character)
	end
	track(LocalPlayer.CharacterAdded:Connect(trackTool))
	local function getChar(p)
		return p and p.Character
	end
	local function getHRP(p)
		local c = getChar(p)
		return c and c:FindFirstChild("HumanoidRootPart")
	end
	local function getHum(p)
		local c = getChar(p)
		return c and c:FindFirstChildOfClass("Humanoid")
	end
	local function isAlive(p)
		local h = getHum(p)
		return h and h.Health > 0
	end
	local function sameTeam(p)
		if not S.TeamFilter then
			return false
		end
		return p.Team == LocalPlayer.Team
	end
	local function distTo(p)
		local myHRP = getHRP(LocalPlayer)
		local tHRP = getHRP(p)
		if not (myHRP and tHRP) then
			return math.huge
		end
		return (myHRP.Position - tHRP.Position).Magnitude
	end
	local function refreshPlayers()
		playerList = {}
		for _, p in ipairs(Players:GetPlayers()) do
			if p ~= LocalPlayer and not sameTeam(p) then
				table.insert(playerList, p)
			end
		end
		table.sort(playerList, function(a, b)
			return distTo(a) < distTo(b)
		end)
		if S.Target and (not isAlive(S.Target) or sameTeam(S.Target)) then
			S.Target = nil
		end
		if not S.Target and #playerList > 0 then
			targetIndex = 1
			S.Target = playerList[1]
		end
		targetBtn.Text = S.Target and S.Target.Name or "No Target"
		updateStatus()
	end
	targetBtn.MouseButton1Click:Connect(function()
		refreshPlayers()
		if #playerList == 0 then
			return
		end
		targetIndex = (targetIndex % #playerList) + 1
		S.Target = playerList[targetIndex]
		targetBtn.Text = S.Target.Name
		updateStatus()
	end)
	local cycleOn = false
	cycleBtn.Text = "Cycle: OFF"
	cycleBtn.MouseButton1Click:Connect(function()
		cycleOn = not cycleOn
		S.AutoCycle = cycleOn
		cycleBtn.Text = "Cycle: " .. (cycleOn and "ON" or "OFF")
		cycleBtn.BackgroundColor3 = cycleOn and T.AccentDim or T.Btn
	end)
	track(Players.PlayerAdded:Connect(refreshPlayers))
	track(Players.PlayerRemoving:Connect(function(p)
		if S.Target == p then
			S.Target = nil
		end
		refreshPlayers()
	end))
	refreshPlayers()
	local lastTargetPos = nil
	local function predictedPos(tHRP, dt)
		local pos = tHRP.Position
		if lastTargetPos then
			local vel = (pos - lastTargetPos) / dt
			table.insert(velHistory, vel)
			if #velHistory > 6 then
				table.remove(velHistory, 1)
			end
			local avgVel = Vector3.new(0, 0, 0)
			for _, v in ipairs(velHistory) do
				avgVel = avgVel + v
			end
			avgVel = avgVel / #velHistory
			lastTargetPos = pos
			return pos + avgVel * (dt * S.PredictSteps)
		end
		lastTargetPos = pos
		return pos
	end
	local evasionTime = 0
	local function applyEvasion(myHRP, dt)
		if not S.EvasionEnabled then
			return
		end
		evasionTime = evasionTime + dt
		local mode = S.EvasionMode
		if mode == "Jitter" or mode == "Combo" then
			local r = S.JitterRadius
			local jx = (math.random() * 2 - 1) * r
			local jz = (math.random() * 2 - 1) * r
			if math.random(1, 3) == 1 then
				myHRP.CFrame = myHRP.CFrame * CFrame.new(jx * dt * 20, 0, jz * dt * 20)
			end
		end
		if mode == "Spin" or mode == "Combo" then
			local spinAngle = evasionTime * S.SpinSpeed
			local pos = myHRP.Position
			myHRP.CFrame = CFrame.new(pos) * CFrame.Angles(0, spinAngle, 0)
		end
		if mode == "Vertical" then
			if math.random(1, 30) == 1 then
				local spike = 8
				myHRP.CFrame = myHRP.CFrame + Vector3.new(0, spike, 0)
				task.delay(0.08, function()
					if myHRP and myHRP.Parent then
						myHRP.CFrame = myHRP.CFrame - Vector3.new(0, spike, 0)
					end
				end)
			end
		end
	end
	local voidFloor = workspace.FallenPartsDestroyHeight or -500
	local baitPhase = "idle"
	local safeReturnPos = nil
	local function findVoidEdge(myPos)
		local dirs = {
			Vector3.new(1, 0, 0),
			Vector3.new(-1, 0, 0),
			Vector3.new(0, 0, 1),
			Vector3.new(0, 0, -1),
			Vector3.new(1, 0, 1).Unit,
			Vector3.new(-1, 0, 1).Unit,
			Vector3.new(1, 0, -1).Unit,
			Vector3.new(-1, 0, -1).Unit,
		}
		local params = RaycastParams.new()
		params.FilterDescendantsInstances = { LocalPlayer.Character }
		params.FilterType = Enum.RaycastFilterType.Exclude
		for _, dir in ipairs(dirs) do
			local probePos = myPos + dir * S.VoidMargin
			local result = workspace:Raycast(probePos, Vector3.new(0, -300, 0), params)
			if not result then
				return probePos, dir
			end
		end
		return nil, nil
	end
	local function applyVoidBait(myHRP, tHRP, dt)
		if not S.VoidBait or not tHRP then
			return
		end
		local myPos = myHRP.Position
		if baitPhase == "idle" then
			local edgePos, edgeDir = findVoidEdge(myPos)
			if edgePos then
				safeReturnPos = myPos
				baitPhase = "approaching"
			end
		elseif baitPhase == "approaching" then
			local edgePos, edgeDir = findVoidEdge(myPos)
			if edgePos then
				local target = edgePos
				local newPos = myPos + (target - myPos).Unit * 20 * dt
				myHRP.CFrame = CFrame.new(newPos, newPos + (target - myPos).Unit)
				if (myPos - edgePos).Magnitude < S.VoidReturnDist then
					baitPhase = "returning"
				end
			else
				baitPhase = "idle"
			end
		elseif baitPhase == "returning" then
			if safeReturnPos then
				myHRP.CFrame = CFrame.new(safeReturnPos)
			end
			baitPhase = "idle"
			safeReturnPos = nil
		end
	end
	task.spawn(function()
		while true do
			task.wait(3)
			if S.AutoCycle and S.BotEnabled then
				refreshPlayers()
				if #playerList > 1 then
					targetIndex = (targetIndex % #playerList) + 1
					S.Target = playerList[targetIndex]
					targetBtn.Text = S.Target.Name
					updateStatus()
				end
			end
		end
	end)
	local lastFrame = tick()
	track(RunService.RenderStepped:Connect(function()
		local now = tick()
		local dt = now - lastFrame
		lastFrame = now
		if S.Target then
			if not isAlive(S.Target) or distTo(S.Target) > S.MaxDistance then
				refreshPlayers()
			end
		end
		local myChar = LocalPlayer.Character
		local myHRP = myChar and myChar:FindFirstChild("HumanoidRootPart")
		local myHum = myChar and myChar:FindFirstChildOfClass("Humanoid")
		if not (myHRP and myHum and myHum.Health > 0) then
			return
		end
		applyEvasion(myHRP, dt)
		if not S.BotEnabled or not S.Target then
			return
		end
		local tChar = S.Target.Character
		local tHRP = tChar and tChar:FindFirstChild("HumanoidRootPart")
		if not tHRP then
			return
		end
		applyVoidBait(myHRP, tHRP, dt)
		local predPos = predictedPos(tHRP, dt)
		local behindVec = -tHRP.CFrame.LookVector
		local goalPos = predPos + behindVec * S.HoverDist
		local goalCF = CFrame.lookAt(goalPos, predPos)
		myHRP.CFrame = myHRP.CFrame:Lerp(goalCF, S.LerpSpeed)
		if S.AutoAttack and equippedTool then
			local interval = 1 / S.AttackCPS
			local jitteredInterval = interval * (0.85 + math.random() * 0.3)
			if now - lastAttack >= jitteredInterval then
				lastAttack = now
				pcall(function()
					equippedTool:Activate()
				end)
			end
		end
	end))
	DoNotif("Rage Bot V2 loaded — RightAlt = toggle bot, RightCtrl = toggle evasion", 4)
	updateStatus()
end)

RegisterCommand({
	Name = "partbring",
	Aliases = { "pb", "sendpart" },
	Description = "WIP Sends unanchored parts to a target",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	local TweenService = game:GetService("TweenService")
	local Players = game:GetService("Players")
	local RunService = game:GetService("RunService")
	local UserInputService = game:GetService("UserInputService")
	local Workspace = game:GetService("Workspace")
	local Camera = Workspace.CurrentCamera
	local LocalPlayer = Players.LocalPlayer
	LocalPlayer.ReplicationFocus = Workspace

	pcall(function()
		game:GetService("CoreGui").RobloxGui["CoreScripts/NetworkPause"]:Destroy()
	end)

	--  Ownership assertion 
	if not getgenv().Network then
		getgenv().Network = { BaseParts = {} }
		RunService.Heartbeat:Connect(function()
			sethiddenproperty(LocalPlayer, "SimulationRadius", math.huge)
			LocalPlayer.ReplicationFocus = Workspace
		end)
		RunService.RenderStepped:Connect(function()
			sethiddenproperty(LocalPlayer, "SimulationRadius", math.huge)
		end)
	end

	local CONFIG = {
		UPDATE_INTERVAL = 0.01,
		MAX_PARTS = 800,
	}

	local TARGET_PARTS = {}
	local CONNECTIONS = {}
	local sendTarget = nil
	local blackHoleActive = false
	local spectateActive = false
	local targetMode = "Players"
	local cycleIndex = 1
	local cycleConnection = nil
	local spectateMonitorConnection = nil
	local DescendantAddedConnection = nil
	local originalCameraType = nil
	local originalCameraSubject = nil
	local lastUpdate = 0

	local Folder = Instance.new("Folder", Workspace)
	local AnchorPart = Instance.new("Part", Folder)
	local Attachment1 = Instance.new("Attachment", AnchorPart)
	AnchorPart.Anchored = false
	AnchorPart.CanCollide = true
	AnchorPart.Transparency = 1

	local overlapParams = OverlapParams.new()
	overlapParams.FilterType = Enum.RaycastFilterType.Exclude
	overlapParams.MaxParts = 500

	local function getPartsInRadius(centerPos, radius)
		local char = LocalPlayer.Character
		overlapParams.FilterDescendantsInstances = char and { char } or {}
		local parts = Workspace:GetPartBoundsInRadius(centerPos, radius, overlapParams)
		if sendTarget then
			local targetChar = sendTarget.Character
			local targetRoot = targetChar and targetChar:FindFirstChild("HumanoidRootPart")
			if targetRoot then
				local targetParts = Workspace:GetPartBoundsInRadius(targetRoot.Position, CONFIG.RADIUS, overlapParams)
				for _, p in ipairs(targetParts) do
					table.insert(parts, p)
				end
			end
		end
		return parts
	end

	local function releasePart(part)
		local data = TARGET_PARTS[part]
		if not data then
			return
		end
		if data.conn then
			data.conn:Disconnect()
		end
		pcall(function()
			local bv = part:FindFirstChildOfClass("BodyVelocity")
			if bv then
				bv:Destroy()
			end
			if data.alignPos and data.alignPos.Parent then
				data.alignPos:Destroy()
			end
			if data.attachment and data.attachment.Parent then
				data.attachment:Destroy()
			end
			if data.torque and data.torque.Parent then
				data.torque:Destroy()
			end
		end)
		TARGET_PARTS[part] = nil
	end

	local function claimOwnership(part)
		-- direct network ownership claim — multiple methods for executor compatibility
		pcall(function()
			part:SetNetworkOwner(LocalPlayer)
		end)
		pcall(function()
			sethiddenproperty(part, "NetworkOwnershipRule", 0)
		end)
	end

	local function forcePart(part)
		if not part:IsA("BasePart") then
			return
		end
		if TARGET_PARTS[part] then
			return
		end
		if part.Anchored then
			return
		end
		if part.Parent and part.Parent:FindFirstChildOfClass("Humanoid") then
			return
		end
		if part.Parent and part.Parent:FindFirstChild("Head") then
			return
		end
		if part.Name == "Handle" then
			return
		end
		local count = 0
		for _ in pairs(TARGET_PARTS) do
			count += 1
		end
		if count >= CONFIG.MAX_PARTS then
			return
		end

		pcall(function()
			for _, c in ipairs(part:GetChildren()) do
				if
					c:IsA("BodyMover")
					or c:IsA("RocketPropulsion")
					or c:IsA("LinearVelocity")
					or c:IsA("VectorForce")
					or c:IsA("BodyVelocity")
					or c:IsA("BodyForce")
				then
					c:Destroy()
				end
			end
		end)

		part.CanCollide = true
		part.Massless = false
		claimOwnership(part)

		local function launchAtTarget()
			if not sendTarget then
				return
			end
			local targetChar = sendTarget.Character
			local targetRoot = targetChar and targetChar:FindFirstChild("HumanoidRootPart")
			if not targetRoot then
				return
			end
			pcall(function()
				local old = part:FindFirstChildOfClass("BodyVelocity")
				if old then
					old:Destroy()
				end
				local bv = Instance.new("BodyVelocity")
				bv.MaxForce = Vector3.new(1e9, 1e9, 1e9)
				bv.Velocity = (targetRoot.Position - part.Position).Unit * 500
				bv.Parent = part
			end)
		end

		launchAtTarget()

		local conn
		conn = RunService.Heartbeat:Connect(function()
			if not part.Parent then
				releasePart(part)
				return
			end
			if not blackHoleActive then
				releasePart(part)
				return
			end
			claimOwnership(part)
			if sendTarget then
				local targetChar = sendTarget.Character
				local targetRoot = targetChar and targetChar:FindFirstChild("HumanoidRootPart")
				if targetRoot then
					local bv = part:FindFirstChildOfClass("BodyVelocity")
					if bv then
						bv.Velocity = (targetRoot.Position - part.Position).Unit * 500
					else
						launchAtTarget()
					end
				end
			end
		end)
		TARGET_PARTS[part] = { conn = conn }
	end

	local function cleanupStaleParts()
		for part in pairs(TARGET_PARTS) do
			if not part.Parent then
				releasePart(part)
			end
		end
	end

	local function blackholeLoop()
		local now = tick()
		if now - lastUpdate < CONFIG.UPDATE_INTERVAL then
			return
		end
		lastUpdate = now
		if not blackHoleActive then
			return
		end
		cleanupStaleParts()
	end
	table.insert(CONNECTIONS, RunService.Heartbeat:Connect(blackholeLoop))

	local function getPlayer(name)
		local query = name:lower()
		for _, p in ipairs(Players:GetPlayers()) do
			if p ~= LocalPlayer then
				if p.Name:lower():find(query, 1, true) or p.DisplayName:lower():find(query, 1, true) then
					return p
				end
			end
		end
	end

	local function getValidPlayers()
		local valid = {}
		for _, p in ipairs(Players:GetPlayers()) do
			if p ~= LocalPlayer and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then
				table.insert(valid, p)
			end
		end
		return valid
	end

	local function isTargetValid(target)
		return target
			and target.Character
			and target.Character:FindFirstChildOfClass("Humanoid")
			and target.Character.Humanoid.Health > 0
	end

	local function startSpectating()
		if not isTargetValid(sendTarget) then
			return
		end
		local humanoid = sendTarget.Character:FindFirstChildOfClass("Humanoid")
		if not humanoid then
			return
		end
		if not originalCameraType then
			originalCameraType = Camera.CameraType
			originalCameraSubject = Camera.CameraSubject
		end
		Camera.CameraType = Enum.CameraType.Custom
		Camera.CameraSubject = humanoid
	end

	local function stopSpectating()
		if originalCameraType and originalCameraSubject then
			Camera.CameraType = originalCameraType
			Camera.CameraSubject = originalCameraSubject
		else
			Camera.CameraType = Enum.CameraType.Custom
			Camera.CameraSubject = LocalPlayer.Character and LocalPlayer.Character:FindFirstChildOfClass("Humanoid")
		end
		originalCameraType = nil
		originalCameraSubject = nil
	end
	local screenGui = Instance.new("ScreenGui")
	screenGui.Name = "BH_Gui"
	screenGui.ResetOnSpawn = false
	screenGui.IgnoreGuiInset = true
	screenGui.Parent = (pcall(function()
		return gethui()
	end) and gethui()) or LocalPlayer.PlayerGui

	local Main = Instance.new("Frame")
	Main.Size = UDim2.new(0, 240, 0, 160)
	Main.Position = UDim2.new(0, 16, 0, 16)
	Main.BackgroundColor3 = Color3.fromRGB(14, 14, 14)
	Main.BackgroundTransparency = 0.2
	Main.BorderSizePixel = 0
	Main.Active = true
	Main.Draggable = true
	Main.Parent = screenGui

	local function corner(parent, radius)
		local c = Instance.new("UICorner", parent)
		c.CornerRadius = UDim.new(0, radius or 8)
		return c
	end
	local function stroke(parent, color, thickness)
		local s = Instance.new("UIStroke", parent)
		s.Color = color or Color3.fromRGB(50, 50, 50)
		s.Thickness = thickness or 1
		return s
	end

	corner(Main, 10)
	stroke(Main)

	local titleLabel = Instance.new("TextLabel")
	titleLabel.Size = UDim2.new(1, 0, 0, 28)
	titleLabel.BackgroundColor3 = Color3.fromRGB(22, 22, 22)
	titleLabel.BackgroundTransparency = 0.1
	titleLabel.BorderSizePixel = 0
	titleLabel.Font = Enum.Font.Code
	titleLabel.Text = "Part Flinger"
	titleLabel.TextColor3 = Color3.fromRGB(200, 200, 200)
	titleLabel.TextSize = 12
	titleLabel.Parent = Main
	corner(titleLabel)

	local inputBox = Instance.new("TextBox")
	inputBox.Size = UDim2.new(0, 148, 0, 30)
	inputBox.Position = UDim2.new(0, 8, 0, 34)
	inputBox.BackgroundColor3 = Color3.fromRGB(24, 24, 24)
	inputBox.BorderSizePixel = 0
	inputBox.PlaceholderText = "player name..."
	inputBox.PlaceholderColor3 = Color3.fromRGB(65, 65, 65)
	inputBox.Text = ""
	inputBox.TextColor3 = Color3.fromRGB(210, 210, 210)
	inputBox.TextSize = 13
	inputBox.Font = Enum.Font.Code
	inputBox.ClearTextOnFocus = false
	inputBox.Parent = Main
	corner(inputBox, 6)
	stroke(inputBox, Color3.fromRGB(45, 45, 45))

	local modeBtn = Instance.new("TextButton")
	modeBtn.Size = UDim2.new(0, 72, 0, 30)
	modeBtn.Position = UDim2.new(0, 162, 0, 34)
	modeBtn.BackgroundColor3 = Color3.fromRGB(45, 45, 45)
	modeBtn.BorderSizePixel = 0
	modeBtn.Font = Enum.Font.Code
	modeBtn.Text = "Players"
	modeBtn.TextColor3 = Color3.fromRGB(200, 200, 200)
	modeBtn.TextSize = 12
	modeBtn.Parent = Main
	corner(modeBtn, 6)

	local bringBtn = Instance.new("TextButton")
	bringBtn.Size = UDim2.new(0, 108, 0, 28)
	bringBtn.Position = UDim2.new(0, 8, 0, 72)
	bringBtn.BackgroundColor3 = Color3.fromRGB(45, 45, 45)
	bringBtn.BorderSizePixel = 0
	bringBtn.Font = Enum.Font.Code
	bringBtn.Text = "Bring: Off"
	bringBtn.TextColor3 = Color3.fromRGB(200, 200, 200)
	bringBtn.TextSize = 12
	bringBtn.Parent = Main
	corner(bringBtn, 6)

	local spectateBtn = Instance.new("TextButton")
	spectateBtn.Size = UDim2.new(0, 108, 0, 28)
	spectateBtn.Position = UDim2.new(0, 124, 0, 72)
	spectateBtn.BackgroundColor3 = Color3.fromRGB(45, 45, 45)
	spectateBtn.BorderSizePixel = 0
	spectateBtn.Font = Enum.Font.Code
	spectateBtn.Text = "Spectate: Off"
	spectateBtn.TextColor3 = Color3.fromRGB(200, 200, 200)
	spectateBtn.TextSize = 12
	spectateBtn.Parent = Main
	corner(spectateBtn, 6)

	local statusLabel = Instance.new("TextLabel")
	statusLabel.Size = UDim2.new(1, -16, 0, 24)
	statusLabel.Position = UDim2.new(0, 8, 0, 108)
	statusLabel.BackgroundColor3 = Color3.fromRGB(20, 20, 20)
	statusLabel.BackgroundTransparency = 0.1
	statusLabel.BorderSizePixel = 0
	statusLabel.Font = Enum.Font.Code
	statusLabel.Text = "idle"
	statusLabel.TextColor3 = Color3.fromRGB(80, 80, 80)
	statusLabel.TextSize = 11
	statusLabel.TextXAlignment = Enum.TextXAlignment.Left
	statusLabel.Parent = Main
	corner(statusLabel, 6)
	local statusPadding = Instance.new("UIPadding", statusLabel)
	statusPadding.PaddingLeft = UDim.new(0, 6)
	local countLabel = Instance.new("TextLabel")
	countLabel.Size = UDim2.new(1, -16, 0, 16)
	countLabel.Position = UDim2.new(0, 8, 0, 136)
	countLabel.BackgroundTransparency = 1
	countLabel.Font = Enum.Font.Code
	countLabel.Text = ""
	countLabel.TextColor3 = Color3.fromRGB(60, 60, 60)
	countLabel.TextSize = 10
	countLabel.TextXAlignment = Enum.TextXAlignment.Left
	countLabel.Parent = Main
	local function setStatus(msg, color)
		statusLabel.Text = msg
		statusLabel.TextColor3 = color or Color3.fromRGB(80, 80, 80)
	end

	local function setTarget(player)
		sendTarget = player
		if player then
			setStatus("→ " .. player.Name .. " (" .. player.DisplayName .. ")", Color3.fromRGB(200, 80, 80))
		else
			setStatus("idle")
		end
	end

	local function stopBlackhole()
		blackHoleActive = false
		bringBtn.Text = "Bring: Off"
		bringBtn.BackgroundColor3 = Color3.fromRGB(45, 45, 45)
		if DescendantAddedConnection then
			DescendantAddedConnection:Disconnect()
			DescendantAddedConnection = nil
		end
		if cycleConnection then
			cycleConnection:Disconnect()
			cycleConnection = nil
		end
		for part in pairs(TARGET_PARTS) do
			releasePart(part)
		end
	end

	local function startBlackhole()
		if not sendTarget then
			return
		end
		blackHoleActive = true
		bringBtn.Text = "Bring: On"
		bringBtn.BackgroundColor3 = Color3.fromRGB(160, 35, 35)
		local targetChar = sendTarget.Character
		local targetRoot = targetChar and targetChar:FindFirstChild("HumanoidRootPart")
		if targetRoot then
			Attachment1.WorldCFrame = targetRoot.CFrame
		end
		task.spawn(function()
			for _, v in ipairs(Workspace:GetDescendants()) do
				forcePart(v)
			end
		end)
		DescendantAddedConnection = Workspace.DescendantAdded:Connect(function(v)
			if blackHoleActive then
				task.spawn(function()
					forcePart(v)
				end)
			end
		end)
		if targetMode == "All" then
			cycleConnection = RunService.Heartbeat:Connect(function()
				if tick() % 3 < 0.05 then
					local players = getValidPlayers()
					if #players > 0 then
						cycleIndex = (cycleIndex % #players) + 1
						setTarget(players[cycleIndex])
					end
				end
			end)
		end
	end

	local function toggleSpectate()
		if not sendTarget then
			return
		end
		spectateActive = not spectateActive
		spectateBtn.Text = spectateActive and "Spectate: On" or "Spectate: Off"
		spectateBtn.BackgroundColor3 = spectateActive and Color3.fromRGB(40, 80, 140) or Color3.fromRGB(45, 45, 45)
		if spectateActive then
			startSpectating()
			if spectateMonitorConnection then
				spectateMonitorConnection:Disconnect()
			end
			spectateMonitorConnection = RunService.Heartbeat:Connect(function()
				if not spectateActive then
					spectateMonitorConnection:Disconnect()
					return
				end
				if not isTargetValid(sendTarget) then
					stopSpectating()
					spectateActive = false
					spectateBtn.Text = "Spectate: Off"
					spectateBtn.BackgroundColor3 = Color3.fromRGB(45, 45, 45)
				elseif Camera.CameraSubject ~= sendTarget.Character:FindFirstChildOfClass("Humanoid") then
					startSpectating()
				end
			end)
		else
			stopSpectating()
			if spectateMonitorConnection then
				spectateMonitorConnection:Disconnect()
				spectateMonitorConnection = nil
			end
		end
	end

	table.insert(
		CONNECTIONS,
		RunService.Heartbeat:Connect(function()
			if blackHoleActive then
				local count = 0
				for _ in pairs(TARGET_PARTS) do
					count += 1
				end
				countLabel.Text = "parts claimed: " .. count
			else
				countLabel.Text = ""
			end
		end)
	)

	bringBtn.MouseButton1Click:Connect(function()
		if blackHoleActive then
			stopBlackhole()
		else
			if targetMode == "Players" then
				local p = getPlayer(inputBox.Text)
				if not p then
					setStatus("not found: " .. inputBox.Text, Color3.fromRGB(200, 80, 80))
					return
				end
				setTarget(p)
			else
				local players = getValidPlayers()
				if #players == 0 then
					setStatus("no valid players", Color3.fromRGB(200, 80, 80))
					return
				end
				setTarget(players[1])
			end
			startBlackhole()
		end
	end)

	spectateBtn.MouseButton1Click:Connect(toggleSpectate)

	modeBtn.MouseButton1Click:Connect(function()
		targetMode = targetMode == "Players" and "All" or "Players"
		modeBtn.Text = targetMode
		inputBox.Visible = targetMode == "Players"
		if blackHoleActive then
			stopBlackhole()
			if targetMode == "All" then
				local players = getValidPlayers()
				if #players > 0 then
					setTarget(players[1])
					startBlackhole()
				end
			end
		end
	end)

	inputBox.FocusLost:Connect(function(enterPressed)
		if not enterPressed then
			return
		end
		local p = getPlayer(inputBox.Text)
		if p then
			inputBox.Text = p.Name
			if not blackHoleActive then
				setTarget(p)
			end
		else
			setStatus("not found: " .. inputBox.Text, Color3.fromRGB(200, 80, 80))
		end
	end)

	Players.PlayerRemoving:Connect(function(p)
		if p == sendTarget then
			if spectateActive then
				stopSpectating()
				spectateActive = false
				spectateBtn.Text = "Spectate: Off"
				spectateBtn.BackgroundColor3 = Color3.fromRGB(45, 45, 45)
			end
			if blackHoleActive and targetMode == "All" then
				local players = getValidPlayers()
				if #players > 0 then
					setTarget(players[1])
				else
					stopBlackhole()
					setStatus("no players left")
				end
			elseif blackHoleActive then
				stopBlackhole()
				setStatus("target left")
			else
				setTarget(nil)
			end
		end
	end)

	local guiVisible = true
	UserInputService.InputBegan:Connect(function(input, gpe)
		if gpe then
			return
		end
		if input.KeyCode == Enum.KeyCode.RightControl then
			guiVisible = not guiVisible
			local t = guiVisible and 0.05 or 1
			TweenService:Create(Main, TweenInfo.new(0.25), { BackgroundTransparency = t }):Play()
			for _, child in ipairs(Main:GetDescendants()) do
				if child:IsA("TextLabel") or child:IsA("TextButton") or child:IsA("TextBox") then
					TweenService:Create(child, TweenInfo.new(0.25), {
						TextTransparency = guiVisible and 0 or 1,
						BackgroundTransparency = guiVisible and 0.05 or 1,
					}):Play()
				end
			end
			Main.Active = guiVisible
			Main.Draggable = guiVisible
		end
	end)
	setStatus("idle")
end)

RegisterCommand({
	Name = "gamepassforfree",
	Aliases = { "gpff" },
	Description = "spoofs the pompt for gamepasses",
}, function(args)
	local CoreGui = game:GetService("CoreGui")
	local MarketplaceService = game:GetService("MarketplaceService")
	local TweenService = game:GetService("TweenService")
	local Players = game:GetService("Players")
	local GuiService = game:GetService("GuiService")
	local UIS = game:GetService("UserInputService")
	local LocalPlayer = Players.LocalPlayer
	while not LocalPlayer do
		task.wait()
		LocalPlayer = Players.LocalPlayer
	end
	local COLORS = {
		IDLE = Color3.fromRGB(34, 214, 78),
		HOVER = Color3.fromRGB(42, 232, 90),
	}
	local COPY_COLORS = {
		IDLE = Color3.fromRGB(255, 154, 46),
		HOVER = Color3.fromRGB(255, 176, 84),
	}
	local AUTO_COLORS = {
		IDLE = Color3.fromRGB(210, 72, 72),
		HOVER = Color3.fromRGB(232, 98, 98),
	}
	local TWEEN_SPEED = TweenInfo.new(0.045, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
	local SECONDARY_BUTTON_DELAY = 0.03
	local NEW_OVERLAY_BUTTON_INJECT_DELAY = 0
	local INSTANT_STATE_WATCH_INTERVAL = 0.03
	local OVERLAY_RESCAN_INTERVAL = 0.03
	local LastPrompt = { Id = nil, Type = nil, Nonce = 0 }
	local LastInstant = { PromptNonce = -1 }
	local SETTINGS_DEFAULTS = {
		CopyButton = false,
		AutoButton = false,
		AutoInterval = 0.3,
		InstantPurchase = false,
		AutoMassPurchase = false,
		Debug = false,
	}
	local function getSettings()
		local resolved = table.clone(SETTINGS_DEFAULTS)
		local ok, envSettings = pcall(function()
			if type(getgenv) ~= "function" then
				return false
			end
			local env = getgenv()
			if type(env) ~= "table" then
				return false
			end
			local settings = env.Settings
			if type(settings) ~= "table" then
				return false
			end
			return settings
		end)
		if not ok or envSettings == false then
			return resolved
		end
		for key, defaultValue in pairs(SETTINGS_DEFAULTS) do
			local expectedType = type(defaultValue)
			if type(envSettings[key]) == expectedType then
				resolved[key] = envSettings[key]
			else
				resolved[key] = defaultValue
			end
		end
		return resolved
	end
	local function isSettingEnabled(name)
		return getSettings()[name] == true
	end
	local RuntimeState = nil
	pcall(function()
		local env = type(getgenv) == "function" and getgenv() or nil
		if type(env) == "table" then
			env.__FreeGamepassRuntime = env.__FreeGamepassRuntime or { runId = 0 }
			if type(env.__FreeGamepassRuntime.connections) == "table" then
				for _, conn in ipairs(env.__FreeGamepassRuntime.connections) do
					pcall(function()
						if conn and conn.Disconnect then
							conn:Disconnect()
						end
					end)
				end
			end
			env.__FreeGamepassRuntime.connections = {}
			env.__FreeGamepassRuntime.runId = env.__FreeGamepassRuntime.runId + 1
			RuntimeState = env.__FreeGamepassRuntime
		end
	end)
	local CURRENT_RUN_ID = RuntimeState and RuntimeState.runId or os.clock()
	local AutoLoopState = { Running = false, ThreadId = 0, StopGui = nil }
	local ParentButtonState = setmetatable({}, { __mode = "k" })
	local ScriptConnections = RuntimeState and RuntimeState.connections or {}
	local HiddenOverlays = setmetatable({}, { __mode = "k" })
	local function isCurrentRun()
		return not RuntimeState or RuntimeState.runId == CURRENT_RUN_ID
	end
	local function trackConnection(conn)
		if conn then
			table.insert(ScriptConnections, conn)
		end
		return conn
	end
	local function toggleRobloxMenu()
		pcall(function()
			local foundOverlay = false
			for _, child in ipairs(CoreGui:GetChildren()) do
				if child:IsA("ScreenGui") and child.Name == "FoundationOverlay" and child.Enabled then
					local saf = child:FindFirstChild("SafeAreaFrame")
					local portal = saf and saf:FindFirstChild("OverlayPortal")
					local backdrop = portal and portal:FindFirstChild("Backdrop")
					local sheet = portal and portal:FindFirstChild("SheetContainer")
					if backdrop and sheet then
						foundOverlay = true
						local info = TweenInfo.new(0.1, Enum.EasingStyle.Cubic, Enum.EasingDirection.In)
						TweenService:Create(backdrop, info, { BackgroundTransparency = 1 }):Play()
						local t = TweenService:Create(sheet, info, { Position = UDim2.new(0.5, 0, 0.5, 32) })
						t:Play()
						t.Completed:Connect(function()
							GuiService:SetMenuIsOpen(true)
							GuiService:SetMenuIsOpen(false)
						end)
						break
					end
				end
			end
			if not foundOverlay then
				GuiService:SetMenuIsOpen(true)
				GuiService:SetMenuIsOpen(false)
			end
		end)
	end
	pcall(function()
		local oldStopGui = CoreGui:FindFirstChild("AutoStopButton")
		if oldStopGui then
			oldStopGui:Destroy()
		end
	end)
	local function trySet(obj, prop, value)
		pcall(function()
			obj[prop] = value
		end)
	end
	local function tweenColor(target, color)
		if not target or not target.Parent then
			return
		end
		local props = {}
		if target:IsA("GuiObject") then
			props.BackgroundColor3 = color
		end
		if target:IsA("ImageButton") or target:IsA("ImageLabel") then
			props.ImageColor3 = color
		end
		if next(props) then
			TweenService:Create(target, TWEEN_SPEED, props):Play()
		end
	end
	local function applyVisualState(root, color)
		tweenColor(root, color)
		for _, desc in ipairs(root:GetDescendants()) do
			if desc:IsA("ImageLabel") or desc:IsA("ImageButton") or desc:IsA("Frame") then
				tweenColor(desc, color)
			end
		end
	end
	local function fireEventFallback(event, ...)
		if type(firesignal) == "function" then
			pcall(firesignal, event, ...)
		end
	end
	local function finishPurchase(id)
		if LastPrompt.Type == "GamePass" then
			local success = pcall(function()
				MarketplaceService:SignalPromptGamePassPurchaseFinished(LocalPlayer.UserId, id, true)
			end)
			if not success then
				fireEventFallback(MarketplaceService.PromptGamePassPurchaseFinished, LocalPlayer, id, true)
			end
		elseif LastPrompt.Type == "Product" then
			local success = pcall(function()
				MarketplaceService:SignalPromptProductPurchaseFinished(LocalPlayer.UserId, id, true)
			end)
			if not success then
				fireEventFallback(MarketplaceService.PromptProductPurchaseFinished, LocalPlayer.UserId, id, true)
			end
		elseif LastPrompt.Type == "Asset" then
			local success = pcall(function()
				MarketplaceService:SignalPromptPurchaseFinished(LocalPlayer.UserId, id, true)
			end)
			if not success then
				fireEventFallback(MarketplaceService.PromptPurchaseFinished, LocalPlayer, id, true)
			end
		elseif LastPrompt.Type == "Bundle" then
			local success = pcall(function()
				MarketplaceService:SignalPromptBundlePurchaseFinished(LocalPlayer.UserId, id, true)
			end)
			if not success then
				fireEventFallback(MarketplaceService.PromptBundlePurchaseFinished, LocalPlayer, id, true)
			end
		elseif LastPrompt.Type == "Premium" then
			local success = pcall(function()
				MarketplaceService:SignalPromptPremiumPurchaseFinished(true)
			end)
			if not success then
				fireEventFallback(MarketplaceService.PromptPremiumPurchaseFinished, true)
			end
		end
	end
	local function restoreHiddenOverlays()
		for overlay in pairs(HiddenOverlays) do
			pcall(function()
				if overlay and overlay.Parent and overlay:IsA("ScreenGui") then
					overlay.Enabled = true
				end
			end)
			HiddenOverlays[overlay] = nil
		end
	end
	local function restoreFoundationOverlayVisibility()
		for _, child in ipairs(CoreGui:GetDescendants()) do
			if child:IsA("ScreenGui") and child.Name == "FoundationOverlay" then
				pcall(function()
					child.Enabled = true
				end)
			end
		end
	end
	local function runInstantPurchase(id, options)
		if not isCurrentRun() or not isSettingEnabled("InstantPurchase") then
			return
		end
		local opts = options or {}
		if opts.hideOverlay and opts.overlay then
			pcall(function()
				if opts.overlay:IsA("ScreenGui") then
					opts.overlay.Enabled = false
					HiddenOverlays[opts.overlay] = true
				end
			end)
		end
		if opts.forceMenuToggle then
			toggleRobloxMenu()
		end
		if not id then
			return
		end
		if id ~= LastPrompt.Id then
			return
		end
		local promptNonce = LastPrompt.Nonce or 0
		if LastInstant.PromptNonce == promptNonce then
			return
		end
		LastInstant.PromptNonce = promptNonce
		finishPurchase(id)
		if not opts.forceMenuToggle then
			return
		end
	end
	local function capturePrompt(player, id, promptType)
		if not isCurrentRun() then
			return
		end
		if player == LocalPlayer then
			LastPrompt.Nonce = (LastPrompt.Nonce or 0) + 1
			LastPrompt.Id = id
			LastPrompt.Type = promptType
			if isSettingEnabled("Debug") then
				task.spawn(function()
					local infoType
					if promptType == "GamePass" then
						infoType = Enum.InfoType.GamePass
					elseif promptType == "Product" then
						infoType = Enum.InfoType.Product
					elseif promptType == "Asset" then
						infoType = Enum.InfoType.Asset
					elseif promptType == "Bundle" then
						infoType = Enum.InfoType.Bundle
					end
					if infoType then
						local success, info = pcall(function()
							return MarketplaceService:GetProductInfo(id, infoType)
						end)
						if success and info then
							print(
								string.format(
									"%s | %s | %s",
									tostring(info.Name),
									tostring(id),
									tostring(info.PriceInRobux or 0)
								)
							)
						else
							print(string.format("Unknown | %s | 0", tostring(id)))
						end
					else
						print(string.format("Unknown | %s | 0", tostring(id)))
					end
				end)
			end
			if isSettingEnabled("InstantPurchase") then
				task.spawn(function()
					runInstantPurchase(id, { forceMenuToggle = false })
				end)
			end
		end
	end
	trackConnection(MarketplaceService.PromptGamePassPurchaseRequested:Connect(function(player, id)
		capturePrompt(player, id, "GamePass")
	end))
	trackConnection(MarketplaceService.PromptProductPurchaseRequested:Connect(function(player, id)
		capturePrompt(player, id, "Product")
	end))
	trackConnection(MarketplaceService.PromptPurchaseRequested:Connect(function(player, id)
		capturePrompt(player, id, "Asset")
	end))
	trackConnection(MarketplaceService.PromptBundlePurchaseRequested:Connect(function(player, id)
		capturePrompt(player, id, "Bundle")
	end))
	trackConnection(MarketplaceService.PromptPremiumPurchaseRequested:Connect(function(player)
		capturePrompt(player, 0, "Premium")
	end))
	local function buildPurchaseOperation(id)
		local code = 'local MarketplaceService = game:GetService("MarketplaceService")\n\n'
		if LastPrompt.Type == "GamePass" then
			return code
				.. string.format(
					"MarketplaceService:SignalPromptGamePassPurchaseFinished(%d, %d, true)",
					LocalPlayer.UserId,
					id
				)
		elseif LastPrompt.Type == "Product" then
			return code
				.. string.format(
					"MarketplaceService:SignalPromptProductPurchaseFinished(%d, %d, true)",
					LocalPlayer.UserId,
					id
				)
		elseif LastPrompt.Type == "Asset" then
			return code
				.. string.format(
					"MarketplaceService:SignalPromptPurchaseFinished(%d, %d, true)",
					LocalPlayer.UserId,
					id
				)
		elseif LastPrompt.Type == "Bundle" then
			return code
				.. string.format(
					"MarketplaceService:SignalPromptBundlePurchaseFinished(%d, %d, true)",
					LocalPlayer.UserId,
					id
				)
		elseif LastPrompt.Type == "Premium" then
			return code .. "MarketplaceService:SignalPromptPremiumPurchaseFinished(true)"
		end
		return ""
	end
	local function settleButtonPosition(anchorBtn, btn, parent, offsetY)
		if not anchorBtn or not btn or not parent then
			return
		end
		local hasListLayout = parent:FindFirstChildOfClass("UIListLayout") ~= nil
		if hasListLayout then
			btn.LayoutOrder = (anchorBtn.LayoutOrder or 0) + 1
			return
		end
		btn.Position = anchorBtn.Position + UDim2.fromOffset(0, offsetY or 0)
		task.defer(function()
			if btn.Parent ~= parent or anchorBtn.Parent ~= parent then
				return
			end
			btn.Position = anchorBtn.Position + UDim2.fromOffset(0, offsetY or 0)
			task.defer(function()
				if btn.Parent ~= parent or anchorBtn.Parent ~= parent then
					return
				end
				btn.Position = anchorBtn.Position + UDim2.fromOffset(0, offsetY or 0)
			end)
		end)
	end
	local function settleFreeButtonPosition(originalBtn, freeBtn, parent)
		if not originalBtn or not freeBtn or not parent then
			return
		end
		local hasListLayout = parent:FindFirstChildOfClass("UIListLayout") ~= nil
		if hasListLayout then
			freeBtn.LayoutOrder = (originalBtn.LayoutOrder or 0) + 1
			return
		end
		freeBtn.Position = originalBtn.Position
		task.defer(function()
			if freeBtn.Parent ~= parent or originalBtn.Parent ~= parent then
				return
			end
			freeBtn.Position = originalBtn.Position
			task.defer(function()
				if freeBtn.Parent ~= parent or originalBtn.Parent ~= parent then
					return
				end
				freeBtn.Position = originalBtn.Position
			end)
		end)
	end
	local function getInjectedButtonsBaseOrder(parent)
		local maxOrder = 0
		for _, child in ipairs(parent:GetChildren()) do
			if
				child:IsA("GuiObject")
				and child.Name ~= "FreeButton"
				and child.Name ~= "CopyButton"
				and child.Name ~= "AutoButton"
			then
				local order = child.LayoutOrder or 0
				if order > maxOrder then
					maxOrder = order
				end
			end
		end
		return maxOrder
	end
	local function getParentState(parent)
		local state = ParentButtonState[parent]
		if not state then
			state = {}
			ParentButtonState[parent] = state
		end
		return state
	end
	local function layoutInjectedButtons(parent)
		if not parent then
			return
		end
		local state = getParentState(parent)
		local template = state.TemplateButton
		if not (template and template.Parent == parent) then
			template = nil
			for _, child in ipairs(parent:GetChildren()) do
				if
					child:IsA("ImageButton")
					and child.Name ~= "FreeButton"
					and child.Name ~= "CopyButton"
					and child.Name ~= "AutoButton"
				then
					template = child
					break
				end
			end
			state.TemplateButton = template
		end
		local freeBtn = parent:FindFirstChild("FreeButton")
		local copyBtn = parent:FindFirstChild("CopyButton")
		local autoBtn = parent:FindFirstChild("AutoButton")
		local hasListLayout = parent:FindFirstChildOfClass("UIListLayout") ~= nil
		if hasListLayout then
			local baseOrder = getInjectedButtonsBaseOrder(parent)
			if freeBtn then
				freeBtn.LayoutOrder = baseOrder + 1
			end
			if copyBtn then
				copyBtn.LayoutOrder = baseOrder + 2
			end
			if autoBtn then
				autoBtn.LayoutOrder = baseOrder + 3
			end
			return
		end
		if freeBtn and template then
			settleFreeButtonPosition(template, freeBtn, parent)
		end
		if copyBtn and freeBtn then
			settleButtonPosition(freeBtn, copyBtn, parent, 42)
		end
		if autoBtn then
			local anchorBtn = copyBtn or freeBtn
			if anchorBtn then
				settleButtonPosition(anchorBtn, autoBtn, parent, 42)
			end
		end
	end
	local function stopAutoLoop()
		AutoLoopState.Running = false
		AutoLoopState.ThreadId = AutoLoopState.ThreadId + 1
	end
	local function destroyAutoStopButton()
		if AutoLoopState.StopGui and AutoLoopState.StopGui.Parent then
			AutoLoopState.StopGui:Destroy()
		end
		AutoLoopState.StopGui = nil
	end
	local function startAutoLoop()
		if AutoLoopState.Running then
			return
		end
		AutoLoopState.Running = true
		AutoLoopState.ThreadId = AutoLoopState.ThreadId + 1
		local myThreadId = AutoLoopState.ThreadId
		task.spawn(function()
			while AutoLoopState.Running and AutoLoopState.ThreadId == myThreadId do
				local id = LastPrompt.Id
				if id then
					finishPurchase(id)
					toggleRobloxMenu()
				end
				local interval = getSettings().AutoInterval
				if type(interval) ~= "number" or interval <= 0 then
					interval = 0.3
				end
				task.wait(interval)
			end
		end)
	end
	local function makeDraggable(frame)
		local dragging = false
		local dragInput = nil
		local dragStart = nil
		local startPos = nil
		local didDrag = false
		local DRAG_THRESHOLD = 6
		local function update(input)
			local delta = input.Position - dragStart
			if math.abs(delta.X) > DRAG_THRESHOLD or math.abs(delta.Y) > DRAG_THRESHOLD then
				didDrag = true
			end
			frame.Position =
				UDim2.new(startPos.X.Scale, startPos.X.Offset + delta.X, startPos.Y.Scale, startPos.Y.Offset + delta.Y)
		end
		frame.InputBegan:Connect(function(input)
			if
				input.UserInputType == Enum.UserInputType.MouseButton1
				or input.UserInputType == Enum.UserInputType.Touch
			then
				dragging = true
				didDrag = false
				dragStart = input.Position
				startPos = frame.Position
				input.Changed:Connect(function()
					if input.UserInputState == Enum.UserInputState.End then
						dragging = false
					end
				end)
			end
		end)
		frame.InputChanged:Connect(function(input)
			if
				input.UserInputType == Enum.UserInputType.MouseMovement
				or input.UserInputType == Enum.UserInputType.Touch
			then
				dragInput = input
			end
		end)
		UIS.InputChanged:Connect(function(input)
			if dragging and input == dragInput then
				update(input)
			end
		end)
		return function()
			local wasDragged = didDrag
			didDrag = false
			return wasDragged
		end
	end
	local function createAutoStopButton()
		destroyAutoStopButton()
		local gui = Instance.new("ScreenGui")
		local button = Instance.new("TextButton")
		local corner = Instance.new("UICorner")
		local icon = Instance.new("ImageLabel")
		local aspect = Instance.new("UIAspectRatioConstraint")
		gui.Name = "AutoStopButton"
		gui.IgnoreGuiInset = true
		gui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
		gui.Parent = CoreGui
		button.Name = "Button"
		button.Parent = gui
		button.AnchorPoint = Vector2.new(0.5, 0.5)
		button.Position = UDim2.new(0.5, 0, 0, 34)
		button.Size = UDim2.new(0.039, 0, 0.069, 0)
		button.BackgroundColor3 = Color3.fromRGB(0, 0, 0)
		button.BackgroundTransparency = 0.4
		button.BorderSizePixel = 0
		button.AutoButtonColor = false
		button.ZIndex = 99999999
		button.Text = ""
		corner.CornerRadius = UDim.new(0, 99999)
		corner.Parent = button
		icon.Parent = button
		icon.BackgroundTransparency = 1
		icon.Position = UDim2.new(0.1, 0, 0.1, 0)
		icon.Size = UDim2.new(0.8, 0, 0.8, 0)
		icon.Image = "rbxassetid://98003862321782"
		icon.ImageColor3 = Color3.fromRGB(255, 90, 90)
		aspect.Parent = button
		aspect.AspectRatio = 1
		local wasDragged = makeDraggable(button)
		button.Activated:Connect(function()
			if wasDragged() then
				return
			end
			stopAutoLoop()
			destroyAutoStopButton()
		end)
		AutoLoopState.StopGui = gui
	end
	local function decorateButton(btn, text, zIndex, palette)
		local colors = palette or COLORS
		btn.Visible = true
		btn.Active = true
		btn.Selectable = true
		btn.AutoButtonColor = false
		btn.ZIndex = zIndex
		btn.BackgroundColor3 = colors.IDLE
		btn.BackgroundTransparency = 0.1
		trySet(btn, "Interactable", true)
		if btn:IsA("ImageButton") then
			btn.ImageColor3 = colors.IDLE
		end
		for _, desc in ipairs(btn:GetDescendants()) do
			if desc:IsA("LocalScript") or desc:IsA("Script") or desc:IsA("ModuleScript") then
				desc:Destroy()
			elseif desc:IsA("GuiObject") then
				desc.ZIndex = math.max(desc.ZIndex, btn.ZIndex)
				desc.Active = true
				trySet(desc, "Interactable", true)
				if desc:IsA("TextLabel") or desc:IsA("TextButton") then
					desc.Text = text
					desc.TextTransparency = 0
				end
			end
		end
	end
	local function wireHover(btn, palette)
		local colors = palette or COLORS
		btn.MouseEnter:Connect(function()
			applyVisualState(btn, colors.HOVER)
		end)
		btn.MouseLeave:Connect(function()
			applyVisualState(btn, colors.IDLE)
		end)
	end
	local function processParentButtons(parent)
		if not parent then
			return
		end
		local state = getParentState(parent)
		if state.Injecting then
			state.Dirty = true
			return
		end
		state.Injecting = true
		task.spawn(function()
			repeat
				state.Dirty = false
				local template = state.TemplateButton
				if not (template and template.Parent == parent) then
					state.Injecting = false
					return
				end
				if not parent:FindFirstChild("FreeButton") then
					local freeBtn = template:Clone()
					freeBtn.Name = "FreeButton"
					freeBtn.Parent = parent
					decorateButton(freeBtn, "Free", (template.ZIndex or 1) + 10)
					settleFreeButtonPosition(template, freeBtn, parent)
					wireHover(freeBtn, COLORS)
					freeBtn.Activated:Connect(function()
						local id = LastPrompt.Id
						if not id then
							return
						end
						applyVisualState(freeBtn, COLORS.HOVER)
						finishPurchase(id)
						applyVisualState(freeBtn, COLORS.IDLE)
						toggleRobloxMenu()
					end)
				end
				task.defer(function()
					task.wait(SECONDARY_BUTTON_DELAY)
					if not isSettingEnabled("CopyButton") then
						local existingCopy = parent:FindFirstChild("CopyButton")
						if existingCopy then
							existingCopy:Destroy()
						end
						return
					end
					if parent:FindFirstChild("CopyButton") then
						return
					end
					local templateBtn = state.TemplateButton
					if not (templateBtn and templateBtn.Parent == parent) then
						return
					end
					local copyBtn = templateBtn:Clone()
					copyBtn.Name = "CopyButton"
					copyBtn.Parent = parent
					local freeBtn = parent:FindFirstChild("FreeButton")
					decorateButton(
						copyBtn,
						"Copy",
						freeBtn and freeBtn.ZIndex or ((templateBtn.ZIndex or 1) + 10),
						COPY_COLORS
					)
					wireHover(copyBtn, COPY_COLORS)
					settleButtonPosition(freeBtn, copyBtn, parent, 42)
					copyBtn.Activated:Connect(function()
						local id = LastPrompt.Id
						if not id then
							return
						end
						local operationText = buildPurchaseOperation(id)
						local copied = pcall(function()
							setclipboard(operationText)
						end)
						if copied then
							applyVisualState(copyBtn, COPY_COLORS.HOVER)
							task.wait(0.05)
						end
						applyVisualState(copyBtn, COPY_COLORS.IDLE)
					end)
				end)
				task.defer(function()
					task.wait(SECONDARY_BUTTON_DELAY)
					if not isSettingEnabled("AutoButton") then
						local existingAuto = parent:FindFirstChild("AutoButton")
						if existingAuto then
							existingAuto:Destroy()
						end
						stopAutoLoop()
						destroyAutoStopButton()
						return
					end
					if parent:FindFirstChild("AutoButton") then
						return
					end
					local templateBtn = state.TemplateButton
					if not (templateBtn and templateBtn.Parent == parent) then
						return
					end
					local autoBtn = templateBtn:Clone()
					autoBtn.Name = "AutoButton"
					autoBtn.Parent = parent
					local anchorBtn = parent:FindFirstChild("CopyButton") or parent:FindFirstChild("FreeButton")
					decorateButton(
						autoBtn,
						"Auto",
						(anchorBtn and anchorBtn.ZIndex) or ((templateBtn.ZIndex or 1) + 10),
						AUTO_COLORS
					)
					wireHover(autoBtn, AUTO_COLORS)
					settleButtonPosition(anchorBtn, autoBtn, parent, 42)
					autoBtn.Activated:Connect(function()
						toggleRobloxMenu()
						if AutoLoopState.Running then
							stopAutoLoop()
							destroyAutoStopButton()
							return
						end
						startAutoLoop()
						createAutoStopButton()
						applyVisualState(autoBtn, AUTO_COLORS.HOVER)
					end)
				end)
				task.wait()
				layoutInjectedButtons(parent)
			until not state.Dirty
			state.Injecting = false
		end)
	end
	local function injectButtons(originalBtn)
		if
			not originalBtn
			or originalBtn.Name == "FreeButton"
			or originalBtn.Name == "CopyButton"
			or originalBtn.Name == "AutoButton"
		then
			return
		end
		local parent = originalBtn.Parent
		if not parent then
			return
		end
		local state = getParentState(parent)
		if not (state.TemplateButton and state.TemplateButton.Parent == parent) then
			state.TemplateButton = originalBtn
		end
		processParentButtons(parent)
	end
	local function getActions(foundation)
		local actions = foundation:FindFirstChild("SafeAreaFrame")
		actions = actions and actions:FindFirstChild("OverlayPortal")
		actions = actions and actions:FindFirstChild("SheetContainer")
		actions = actions and actions:FindFirstChild("Frame")
		actions = actions and actions:FindFirstChild("Sheet")
		actions = actions and actions:FindFirstChild("Content")
		actions = actions and actions:FindFirstChild("Actions")
		return actions or foundation:FindFirstChild("Actions", true)
	end
	local function scanActions(actionsFolder)
		for _, child in ipairs(actionsFolder:GetChildren()) do
			if tonumber(child.Name) then
				for _, inner in ipairs(child:GetDescendants()) do
					if inner:IsA("ImageButton") then
						injectButtons(inner)
					end
				end
			end
		end
	end
	local function scanAllFoundationOverlays()
		for _, child in ipairs(CoreGui:GetDescendants()) do
			if child:IsA("ScreenGui") and child.Name == "FoundationOverlay" then
				local actions = getActions(child)
				if actions then
					scanActions(actions)
				end
			end
		end
	end
	local ProcessedOverlays = setmetatable({}, { __mode = "k" })
	local handleOverlay
	local function startInstantStateWatcher()
		task.spawn(function()
			local wasEnabled = isSettingEnabled("InstantPurchase")
			if not wasEnabled then
				restoreHiddenOverlays()
				restoreFoundationOverlayVisibility()
				scanAllFoundationOverlays()
			end
			while isCurrentRun() do
				local isEnabled = isSettingEnabled("InstantPurchase")
				if isEnabled ~= wasEnabled then
					if not isEnabled then
						LastInstant.PromptNonce = -1
						restoreHiddenOverlays()
						restoreFoundationOverlayVisibility()
						scanAllFoundationOverlays()
					end
					for _, child in ipairs(CoreGui:GetDescendants()) do
						if child:IsA("ScreenGui") and child.Name == "FoundationOverlay" then
							task.spawn(handleOverlay, child, true)
						end
					end
					wasEnabled = isEnabled
				end
				task.wait(INSTANT_STATE_WATCH_INTERVAL)
			end
		end)
	end
	local function startOverlayRescanLoop()
		task.spawn(function()
			while isCurrentRun() do
				if not isSettingEnabled("InstantPurchase") then
					for _, child in ipairs(CoreGui:GetDescendants()) do
						if child:IsA("ScreenGui") and child.Name == "FoundationOverlay" then
							local actions = getActions(child)
							if actions then
								scanActions(actions)
							end
						end
					end
				end
				task.wait(OVERLAY_RESCAN_INTERVAL)
			end
		end)
	end
	function handleOverlay(child, force)
		if child.Name ~= "FoundationOverlay" then
			return
		end
		local modeKey = isSettingEnabled("InstantPurchase") and "instant" or "buttons"
		if not force and ProcessedOverlays[child] == modeKey then
			return
		end
		ProcessedOverlays[child] = modeKey
		if isSettingEnabled("InstantPurchase") then
			local function executeInstant()
				local id = LastPrompt.Id
				runInstantPurchase(id, { hideOverlay = true, overlay = child, forceMenuToggle = true })
			end
			task.spawn(function()
				local function check()
					if not (child and child.Parent and isSettingEnabled("InstantPurchase")) then
						return true
					end
					local safeArea = child:FindFirstChild("SafeAreaFrame")
					local portal = safeArea and safeArea:FindFirstChild("OverlayPortal")
					if portal then
						executeInstant()
						return true
					end
					return false
				end
				if not check() then
					local conn
					conn = trackConnection(child.DescendantAdded:Connect(function()
						if check() then
							if conn then
								conn:Disconnect()
							end
						end
					end))
				end
			end)
			return
		end
		local function scanButtonsWithDelay()
			if not (child and child.Parent and isCurrentRun() and not isSettingEnabled("InstantPurchase")) then
				return false
			end
			if not force then
				task.wait(NEW_OVERLAY_BUTTON_INJECT_DELAY)
			end
			if not (child and child.Parent and isCurrentRun() and not isSettingEnabled("InstantPurchase")) then
				return false
			end
			local actions = getActions(child)
			if not actions then
				return false
			end
			scanActions(actions)
			return true
		end
		if scanButtonsWithDelay() then
			return
		end
		local conn
		conn = trackConnection(child.DescendantAdded:Connect(function()
			if scanButtonsWithDelay() then
				if conn then
					conn:Disconnect()
				end
			end
		end))
		task.delay(10, function()
			if conn then
				conn:Disconnect()
			end
		end)
	end
	trackConnection(CoreGui.DescendantAdded:Connect(handleOverlay))
	for _, child in ipairs(CoreGui:GetDescendants()) do
		task.spawn(handleOverlay, child)
	end
	startInstantStateWatcher()
	startOverlayRescanLoop()
	local function performAutoMassPurchase()
		if not isSettingEnabled("AutoMassPurchase") then
			return
		end
		task.spawn(function()
			local success, productsPage = pcall(function()
				return MarketplaceService:GetDeveloperProductsAsync()
			end)
			if success and productsPage then
				while true do
					local products = productsPage:GetCurrentPage()
					for _, info in ipairs(products) do
						local id = info.ProductId
						local name = info.Name or "Unknown"
						local price = info.PriceInRobux or 0
						if isSettingEnabled("Debug") then
							print(string.format("Product: %s | %s | %s", tostring(name), tostring(id), tostring(price)))
						end
						local successSig = pcall(function()
							MarketplaceService:SignalPromptProductPurchaseFinished(LocalPlayer.UserId, id, true)
						end)
						if not successSig then
							fireEventFallback(
								MarketplaceService.PromptProductPurchaseFinished,
								LocalPlayer.UserId,
								id,
								true
							)
						end
						task.wait(0.1)
					end
					if productsPage.IsFinished then
						break
					end
					pcall(function()
						productsPage:AdvanceToNextPageAsync()
					end)
				end
			end
			local HttpService = game:GetService("HttpService")
			local universeId = game.GameId
			if universeId == 0 then
				pcall(function()
					local res = game:HttpGet(
						"https://apis.roblox.com/universes/v1/places/" .. tostring(game.PlaceId) .. "/universe"
					)
					local data = HttpService:JSONDecode(res)
					if data and data.universeId then
						universeId = data.universeId
					end
				end)
			end
			if universeId and universeId > 0 then
				pcall(function()
					local cursor = ""
					while cursor do
						local url = "https://games.roblox.com/v1/games/"
							.. tostring(universeId)
							.. "/game-passes?limit=100"
						if cursor ~= "" then
							url = url .. "&cursor=" .. cursor
						end
						local res = game:HttpGet(url)
						local data = HttpService:JSONDecode(res)
						if data and data.data then
							for _, gp in ipairs(data.data) do
								local id = gp.id
								local name = gp.name or "Unknown"
								local price = gp.price or 0
								if isSettingEnabled("Debug") then
									print(
										string.format(
											"GamePass: %s | %s | %s",
											tostring(name),
											tostring(id),
											tostring(price)
										)
									)
								end
								local successSig = pcall(function()
									MarketplaceService:SignalPromptGamePassPurchaseFinished(
										LocalPlayer.UserId,
										id,
										true
									)
								end)
								if not successSig then
									fireEventFallback(
										MarketplaceService.PromptGamePassPurchaseFinished,
										LocalPlayer,
										id,
										true
									)
								end
								task.wait(0.1)
							end
							cursor = data.nextPageCursor
						else
							cursor = nil
						end
					end
				end)
			end
		end)
	end
	performAutoMassPurchase()
end)
Modules.Aggressor = {
	State = {
		IsEnabled = false,
		TargetPlayer = nil,
		LoopThread = nil,
		Index = 0,
	},
	Config = {
		Frequency = 0.35,
		OffsetDistance = 1.5,
		VerticalAdjustment = 1,
	},
	Dependencies = { "Players", "RunService" },
	Services = {},
}
function Modules.Aggressor:Stop()
	self.State.IsEnabled = false
	if self.State.LoopThread then
		task.cancel(self.State.LoopThread)
		self.State.LoopThread = nil
	end
	local char = game:GetService("Players").LocalPlayer.Character
	local hum = char and char:FindFirstChildOfClass("Humanoid")
	if hum then
		hum:SetStateEnabled(Enum.HumanoidStateType.Seated, true)
	end
	self.State.TargetPlayer = nil
	DoNotif("sex sequence stopped.", 2)
end
function Modules.Aggressor:Start(targetPlayer)
	if self.State.IsEnabled then
		self:Stop()
	end
	local lp = game:GetService("Players").LocalPlayer
	local char = lp.Character
	local hum = char and char:FindFirstChildOfClass("Humanoid")
	local root = char and char:FindFirstChild("HumanoidRootPart")
	if not (hum and root) then
		return DoNotif("Character not found.", 3)
	end
	self.State.IsEnabled = true
	self.State.TargetPlayer = targetPlayer
	self.State.Index = 0
	hum:SetStateEnabled(Enum.HumanoidStateType.Seated, false)
	hum.Sit = false
	self.State.LoopThread = task.spawn(function()
		while self.State.IsEnabled do
			local tChar = targetPlayer.Character
			local tHum = tChar and tChar:FindFirstChildOfClass("Humanoid")
			local tRoot = tChar and tChar:FindFirstChild("HumanoidRootPart")
			if not (tChar and tHum and tRoot and char.Parent and hum.Health > 0) then
				self:Stop()
				break
			end
			self.State.Index += self.Config.Frequency
			if tHum.FloorMaterial == Enum.Material.Air and hum.FloorMaterial ~= Enum.Material.Air and not tHum.Sit then
				hum:ChangeState(Enum.HumanoidStateType.Jumping)
			end
			local sinValue = math.sin(self.State.Index) * self.Config.OffsetDistance
			local offset
			if tHum.Sit then
				offset = CFrame.new(0, 0, -self.Config.OffsetDistance + sinValue)
			else
				offset = CFrame.new(0, 0, self.Config.OffsetDistance + sinValue)
			end
			local targetGoal = tRoot.CFrame * offset
			root.CFrame =
				CFrame.new(targetGoal.Position, Vector3.new(tRoot.Position.X, root.Position.Y, tRoot.Position.Z))
			task.wait()
		end
	end)
	DoNotif("sex sequence started on " .. targetPlayer.Name, 2)
end
