function Modules.ScriptSearcher:Initialize()
	for _, s in ipairs(self.Dependencies) do
		self.Services[s] = game:GetService(s)
	end
	RegisterCommand({
		Name = "Hub",
		Aliases = { "search", "scripts" },
		Description = "Opens the ScriptBlox database searcher.",
	}, function()
		self:CreateUI()
	end)
end
Modules.GoToPart = {
	State = {
		LastSearchResults = {},
		IsSearching = false,
	},
	Services = {
		Players = game:GetService("Players"),
		Workspace = game:GetService("Workspace"),
	},
}
function Modules.GoToPart:_findParts(searchTerm)
	if not searchTerm or searchTerm == "" then
		return {}
	end
	local results = {}
	local lowerSearch = searchTerm:lower()
	for _, descendant in ipairs(self.Services.Workspace:GetDescendants()) do
		local isValidTarget = descendant:IsA("BasePart") or descendant:IsA("Model")
		if isValidTarget and descendant.Name:lower():find(lowerSearch, 1, true) then
			table.insert(results, descendant)
			if #results >= 50 then
				break
			end
		end
	end
	return results
end
function Modules.GoToPart:_getPrimaryPosition(instance)
	if instance:IsA("Model") then
		if instance.PrimaryPart then
			return instance.PrimaryPart.Position
		end
		for _, child in ipairs(instance:GetDescendants()) do
			if child:IsA("BasePart") then
				return child.Position
			end
		end
		return instance:GetPivot().Position
	elseif instance:IsA("BasePart") then
		return instance.Position
	end
	return nil
end
function Modules.GoToPart:TeleportToInstance(instance)
	local character = self.Services.Players.LocalPlayer.Character
	local hrp = character and character:FindFirstChild("HumanoidRootPart")
	if not hrp then
		return DoNotif("HumanoidRootPart not found.", 3)
	end
	local targetPos = self:_getPrimaryPosition(instance)
	if not targetPos then
		return DoNotif("Could not determine position for: " .. instance.Name, 3)
	end
	hrp.CFrame = CFrame.new(targetPos + Vector3.new(0, 5, 0))
	DoNotif("Teleported to: " .. instance.Name, 2)
end
function Modules.GoToPart:SearchAndTeleport(searchTerm)
	if self.State.IsSearching then
		return DoNotif("Already searching...", 2)
	end
	self.State.IsSearching = true
	DoNotif("Searching for: " .. searchTerm, 1.5)
	task.spawn(function()
		local results = self:_findParts(searchTerm)
		self.State.IsSearching = false
		if #results == 0 then
			DoNotif("No parts/models found matching: " .. searchTerm, 3)
			return
		end
		if #results == 1 then
			self:TeleportToInstance(results[1])
		else
			self.State.LastSearchResults = results
			DoNotif("Found " .. #results .. " matches. Use ;gotopart # to select.", 4)
			print("=== GoToPart Results ===")
			for i, result in ipairs(results) do
				local path = result:GetFullName()
				print(string.format("[%d] %s (%s)", i, result.Name, result.ClassName))
			end
			print("========================")
			print("Use: ;gotopart " .. math.min(#results, 5) .. " (for example)")
		end
	end)
end
function Modules.GoToPart:TeleportToIndex(index)
	if #self.State.LastSearchResults == 0 then
		return DoNotif("No search results. Use ;gotopart <name> first.", 3)
	end
	local idx = tonumber(index)
	if not idx or idx < 1 or idx > #self.State.LastSearchResults then
		return DoNotif("Invalid index. Choose 1-" .. #self.State.LastSearchResults, 3)
	end
	local targetInstance = self.State.LastSearchResults[idx]
	if targetInstance and targetInstance.Parent then
		self:TeleportToInstance(targetInstance)
	else
		DoNotif("Selected part no longer exists.", 3)
	end
end
function Modules.GoToPart:Initialize()
	local module = self
	RegisterCommand({
		Name = "gotopart",
		Aliases = { "gtp", "tppart", "topart" },
		Description = "Teleports to a part or model by name. Use number to select from results.",
	}, function(args)
		if not args[1] then
			return DoNotif("Usage: ;gotopart <part name> OR ;gotopart <#>", 3)
		end
		local firstArg = args[1]
		local asNumber = tonumber(firstArg)
		if asNumber then
			module:TeleportToIndex(asNumber)
		else
			local searchTerm = table.concat(args, " ")
			module:SearchAndTeleport(searchTerm)
		end
	end)
end
RegisterCommand({
	Name = "combatai",
	Aliases = { "bot1" },
	Description = "sword fighting bot, im still better fr",
}, function(args)
	local State = {
		target = nil,
		active = false,
		autoTarget = false,
		sideMultiplier = 3,
		closeRange = false,
		jogCounter = 0,
		dodgeDir = 1,
		dodgeCounter = 0,
		inDodge = false,
	}
	local Config = {
		trackingDistance = 20,
		meleeDistance = 10,
		hitboxDistance = 5,
		dodgeExitDistance = 7,
		autoTargetRange = 40,
		bgP = 30000,
		bgD = 1,
	}
	local function notify(text, color)
		StarterGui:SetCore("ChatMakeSystemMessage", {
			Text = text,
			Color = color or Color3.fromRGB(255, 255, 0),
			Font = Enum.Font.SourceSansBold,
			TextSize = 18,
		})
	end
	local jitterValue = Instance.new("NumberValue", workspace)
	jitterValue.Value = -40
	task.spawn(function()
		while true do
			task.wait(0.14)
			jitterValue.Value = math.random(-90, -35)
			TweenService:Create(
				jitterValue,
				TweenInfo.new(0.07, Enum.EasingStyle.Linear, Enum.EasingDirection.InOut, 1, true, 0),
				{ Value = math.random(35, 90) }
			):Play()
		end
	end)
	local bg = Instance.new("BodyGyro")
	bg.D = Config.bgD
	bg.P = Config.bgP
	bg.MaxTorque = Vector3.new(4e8, 4e8, 4e8)
	bg.CFrame = CFrame.new(Vector3.new())
	local function getAimCFrame(from, to)
		local flatFrom = Vector3.new(from.x, 0, from.z)
		local flatTo = Vector3.new(to.x, 0, to.z)
		return CFrame.new(flatFrom, flatTo)
	end
	local function getPredictedTargetPos(hrp)
		if State.closeRange then
			return hrp.Position + player.Character.HumanoidRootPart.CFrame.RightVector * (jitterValue.Value / 25)
		end
		return hrp.Position + hrp.Velocity / 10
	end
	local function getDesiredPosition(targetHRP, myHRP)
		local targetPos = targetHRP.Position
		local targetVel = targetHRP.Velocity
		local targetLook = targetHRP.CFrame.LookVector
		local targetRight = targetHRP.CFrame.RightVector
		local myRight = myHRP.CFrame.RightVector
		local myLook = myHRP.CFrame.LookVector
		local dist = (targetPos - myHRP.Position).Magnitude
		local basePos = targetPos + targetRight * -1 + targetLook * 0 + myRight * 6
		local targetMoving = targetVel.Magnitude > 1
		if dist <= Config.meleeDistance then
			State.jogCounter += 1
			if State.jogCounter >= 3 then
				State.jogCounter = 0
				State.sideMultiplier *= -1
			end
			return targetPos
				+ targetRight * -1
				+ targetLook * -1
				+ (myRight + myLook * -1)
				+ (targetMoving and (-targetVel / 5) or (targetVel / 10))
				+ myRight * State.sideMultiplier
		elseif targetMoving then
			return targetPos + targetRight * -1 + targetLook * -1 + myRight * 6 - targetVel / 2
		else
			return basePos + targetVel / 10
		end
	end
	task.spawn(function()
		task.wait(5)
		RunService.RenderStepped:Connect(function()
			local char = player.Character
			if not char then
				return
			end
			local myHRP = char:FindFirstChild("HumanoidRootPart")
			local myHuman = char:FindFirstChild("Humanoid")
			if not myHRP or not myHuman or myHuman.Health <= 0 then
				return
			end
			local target = State.target
			if not State.active or not target or not target:FindFirstChild("HumanoidRootPart") then
				bg.Parent = game.ReplicatedStorage
				return
			end
			local targetHRP = target.HumanoidRootPart
			local dist = (targetHRP.Position - myHRP.Position).Magnitude
			bg.Parent = myHRP
			State.closeRange = dist <= Config.meleeDistance
			local predictedPos = getPredictedTargetPos(targetHRP)
			local myFlatOrigin = myHRP.CFrame.p + myHRP.CFrame.LookVector + myHRP.CFrame.RightVector
			bg.CFrame = getAimCFrame(myFlatOrigin, predictedPos)
			if targetHRP.Position.Y - 0.5 > myHRP.Position.Y then
				task.spawn(function()
					myHuman.Jump = true
				end)
			end
			local destination = getDesiredPosition(targetHRP, myHRP)
			_G.pos = destination
			if dist <= Config.trackingDistance then
				local myRightArm = char:FindFirstChild("Right Arm")
				local armDist = myRightArm and (targetHRP.Position - myRightArm.Position).Magnitude or math.huge
				if armDist <= Config.hitboxDistance or State.inDodge then
					State.inDodge = true
					if armDist >= Config.dodgeExitDistance then
						State.inDodge = false
					end
					State.dodgeCounter += 1
					if State.dodgeCounter >= math.random(2, 4) then
						State.dodgeCounter = 0
						State.dodgeDir = State.dodgeDir == 0 and -2 or 0
					end
					destination = myHRP.CFrame.LookVector * 5 * State.dodgeDir + targetHRP.Velocity / 20
					_G.pos = destination
					myHuman:Move(destination)
				end
				local tool = char:FindFirstChildOfClass("Tool")
				if tool then
					tool:Activate()
				end
			end
			myHuman:MoveTo(_G.pos)
		end)
	end)
	local function findCharacterFromPart(part)
		if not part then
			return nil
		end
		local model = part.Parent
		for _ = 1, 3 do
			if model and model:FindFirstChild("HumanoidRootPart") then
				return model
			end
			model = model and model.Parent
		end
		return nil
	end
	UserInputService.InputBegan:Connect(function(key, gameProcessed)
		if gameProcessed then
			return
		end
		if key.KeyCode == Enum.KeyCode.E then
			local target = findCharacterFromPart(mouse.Target)
			if target then
				State.target = target
				_G.x = target
				local info = ("%s > %s > %s"):format(
					target.Name,
					target.Parent and target.Parent.Name or "?",
					target.Parent and target.Parent.Parent and target.Parent.Parent.Name or "?"
				)
				notify(info, Color3.fromRGB(0, 255, 255))
			end
		elseif key.KeyCode == Enum.KeyCode.R then
			State.active = not State.active
			_G.y = State.active and 1 or 0
			notify("Bot: " .. (State.active and "ON" or "OFF"))
		elseif key.KeyCode == Enum.KeyCode.T then
			State.autoTarget = not State.autoTarget
			_G.rage = State.autoTarget and 1 or 0
			notify("Auto-target: " .. (State.autoTarget and "ON" or "OFF"))
		end
	end)
	task.spawn(function()
		while true do
			task.wait(0.1)
			if not State.autoTarget then
				continue
			end
			local char = player.Character
			if not char then
				continue
			end
			local myHRP = char:FindFirstChild("HumanoidRootPart")
			if not myHRP then
				continue
			end
			local closest, closestDist = nil, Config.autoTargetRange
			for _, otherPlayer in ipairs(Players:GetPlayers()) do
				if otherPlayer == player then
					continue
				end
				local otherChar = otherPlayer.Character
				if not otherChar then
					continue
				end
				local otherHRP = otherChar:FindFirstChild("HumanoidRootPart")
				local otherHuman = otherChar:FindFirstChild("Humanoid")
				if not otherHRP or not otherHuman or otherHuman.Health <= 0 then
					continue
				end
				local d = (otherHRP.Position - myHRP.Position).Magnitude
				if d < closestDist then
					closestDist = d
					closest = otherChar
				end
			end
			if closest then
				State.target = closest
				_G.x = closest
			end
		end
	end)
	print("Combat script loaded — E: target | R: toggle | T: auto-target")
end)
