	local _j4 = {}
	for _i = 1, _j3 do
		_j4[_i] = _j2:sub(_i, _i)
	end
	local lp = game:GetService("Players").LocalPlayer
	local mt = getrawmetatable(lp)
	setreadonly(mt, false)
	local orig = rawget(mt, "__index")
