end)
RegisterCommand({
	Name = "newreach",
	Aliases = { "newr" },
	Description = "hitbox expander",
}, function(args)
	if getgenv().HitboxSettings and getgenv().HitboxSettings.Enabled then
		print("Hitbox expander already running.")
		return
	end
	local TargetSize = Vector3.new(20, 20, 20)
	getgenv().HitboxSettings = {
		Enabled = true,
		Transparency = 1.0,
		Color = Color3.fromRGB(255, 0, 0),
		ExcludedTeam = nil,
	}
	local expandedParts = {}
	local function expandHitbox(model)
		if model == LocalPlayer.Character then
			return
		end
		local hrp = model:FindFirstChild("HumanoidRootPart")
		local humanoid = model:FindFirstChildWhichIsA("Humanoid")
		if not (hrp and hrp:IsA("BasePart") and humanoid) then
			return
		end
		if expandedParts[hrp] then
			return
		end
		local ghost = Instance.new("Part")
		ghost.Name = "ExpandedHitbox"
		ghost.Size = TargetSize
		ghost.Transparency = getgenv().HitboxSettings.Transparency
		ghost.Color = getgenv().HitboxSettings.Color
		ghost.CanCollide = false
		ghost.Massless = true
		ghost.Material = Enum.Material.Neon
		ghost.CFrame = hrp.CFrame
		ghost.Parent = hrp
		local weld = Instance.new("WeldConstraint")
		weld.Part0 = hrp
		weld.Part1 = ghost
		weld.Parent = ghost
		expandedParts[hrp] = ghost
	end
	local function fullScan()
		for _, desc in ipairs(Workspace:GetDescendants()) do
			if desc:IsA("Model") and desc ~= LocalPlayer.Character then
				local h = desc:FindFirstChildWhichIsA("Humanoid")
				if h then
					expandHitbox(desc)
				end
			end
		end
	end
	for _, player in ipairs(Players:GetPlayers()) do
		if player ~= LocalPlayer then
			player.CharacterAdded:Connect(function(character)
				if getgenv().HitboxSettings.Enabled then
					task.wait(0.5)
					expandHitbox(character)
				end
			end)
		end
	end
	Players.PlayerAdded:Connect(function(player)
		player.CharacterAdded:Connect(function(character)
			if getgenv().HitboxSettings.Enabled then
				task.wait(0.5)
				expandHitbox(character)
			end
		end)
	end)
	Workspace.DescendantAdded:Connect(function(descendant)
		if not getgenv().HitboxSettings.Enabled then
			return
		end
		if descendant:IsA("Model") and descendant:FindFirstChildWhichIsA("Humanoid") then
			task.wait(0.1)
			expandHitbox(descendant)
		end
	end)
	task.spawn(function()
		print("Hitbox expander active.")
		fullScan()
	end)
	task.spawn(function()
		while task.wait(10) do
			if getgenv().HitboxSettings.Enabled then
				fullScan()
			else
				break
			end
		end
	end)
end)
RegisterCommand({
	Name = "newantia",
	Aliases = { "naa" },
	Description = "anti aimbot",
}, function(args)
	local Config = {
		PoisonVector = Vector3.new(0, -20000, 0),
		PoisonJitter = 120,
		MaxSpoofsPerSecond = 60,
		DisableRagdoll = true,
		DisableFallingDown = true,
		StripConstraints = true,
	}
	local State = {
		VelocitySpooferEnabled = false,
		RootPart = nil,
		Connections = {},
		Applying = false,
		SpoofCount = 0,
		LastSecond = os.clock(),
	}
	local function getPoisonVector()
		local base = Config.PoisonVector
		local j = Config.PoisonJitter
		return Vector3.new(base.X + math.random(-j, j), base.Y + math.random(-j, j), base.Z + math.random(-j, j))
	end
	local function stripAttachedConstraints()
		local hrp = State.RootPart
		if not hrp then
			return
		end
		pcall(function()
			for _, child in ipairs(hrp:GetChildren()) do
				if
					child:IsA("LinearVelocity")
					or child:IsA("VectorForce")
					or child:IsA("BodyVelocity")
					or child:IsA("BodyForce")
					or child:IsA("AlignPosition")
					or child:IsA("RocketPropulsion")
				then
					child:Destroy()
				end
			end
			for _, child in ipairs(hrp:GetChildren()) do
				if child:IsA("Attachment") then
					for _, constraint in ipairs(child:GetChildren()) do
						if constraint:IsA("AlignPosition") or constraint:IsA("LinearVelocity") then
							constraint:Destroy()
						end
					end
				end
			end
		end)
	end
	local function updateRootPart()
		local character = LocalPlayer.Character
		if character then
			State.RootPart = character:FindFirstChild("HumanoidRootPart")
		end
	end
	local function disableRagdollStates()
		local character = LocalPlayer.Character
		if not character then
			return
		end
		local humanoid = character:FindFirstChildOfClass("Humanoid")
		if not humanoid then
			return
		end
		if Config.DisableFallingDown then
			humanoid:SetStateEnabled(Enum.HumanoidStateType.FallingDown, false)
		end
		if Config.DisableRagdoll then
			humanoid:SetStateEnabled(Enum.HumanoidStateType.Ragdoll, false)
		end
	end
	local function enableRagdollStates()
		local character = LocalPlayer.Character
		if not character then
			return
		end
		local humanoid = character:FindFirstChildOfClass("Humanoid")
		if not humanoid then
			return
		end
		if Config.DisableFallingDown then
			humanoid:SetStateEnabled(Enum.HumanoidStateType.FallingDown, true)
		end
		if Config.DisableRagdoll then
			humanoid:SetStateEnabled(Enum.HumanoidStateType.Ragdoll, true)
		end
	end
	local function applyVelocitySpoof()
		if State.Applying then
			return
		end
		local hrp = State.RootPart
		if not hrp or not State.VelocitySpooferEnabled then
			return
		end
		local now = os.clock()
		if now - State.LastSecond >= 1 then
			State.SpoofCount = 0
			State.LastSecond = now
		end
		if State.SpoofCount >= Config.MaxSpoofsPerSecond then
			return
		end
		State.Applying = true
		State.SpoofCount = State.SpoofCount + 1
		pcall(function()
			if Config.StripConstraints then
				stripAttachedConstraints()
			end
			local realVelocity = hrp.AssemblyLinearVelocity
			hrp.AssemblyLinearVelocity = getPoisonVector()
			RunService.RenderStepped:Wait()
			if hrp and hrp.Parent then
				hrp.AssemblyLinearVelocity = realVelocity
			end
		end)
		State.Applying = false
	end
	local VelocitySpoofer = {}
	function VelocitySpoofer:Enable()
		if State.VelocitySpooferEnabled then
			return
		end
		State.VelocitySpooferEnabled = true
		State.Applying = false
		updateRootPart()
		State.Connections.Heartbeat = RunService.Heartbeat:Connect(function()
			if not State.RootPart and LocalPlayer.Character then
				updateRootPart()
			end
			if State.RootPart and State.VelocitySpooferEnabled then
				applyVelocitySpoof()
			end
		end)
		State.Connections.CharacterAdded = LocalPlayer.CharacterAdded:Connect(function()
			task.wait(0.1)
			updateRootPart()
			disableRagdollStates()
		end)
		State.Connections.RagdollGuard = RunService.Heartbeat:Connect(function()
			if not State.VelocitySpooferEnabled then
				State.Connections.RagdollGuard:Disconnect()
				return
			end
			disableRagdollStates()
		end)
	end
	function VelocitySpoofer:Disable()
		if not State.VelocitySpooferEnabled then
			return
		end
		State.VelocitySpooferEnabled = false
		State.Applying = false
		for name, conn in pairs(State.Connections) do
			if conn then
				conn:Disconnect()
			end
		end
		State.Connections = {}
		enableRagdollStates()
		State.RootPart = nil
	end
	function VelocitySpoofer:IsEnabled()
		return State.VelocitySpooferEnabled
	end
	function VelocitySpoofer:Toggle()
		if State.VelocitySpooferEnabled then
			self:Disable()
		else
			self:Enable()
		end
	end
end)
RegisterCommand({
	Name = "noadminabuse",
	Aliases = { "naab" },
	Description = "tries to protect against ss admins",
}, function(args)
	local SETTINGS = {
		KICK_IMMUNITY = true,
		BLOCK_SERVER_TP = true,
		ANTI_CFRAME_TP = false,
		ANTI_FLING = true,
		ANTI_ANCHOR = true,
		NOTIFY = true,
		DEBUG = false,
	}
	local LastValidCFrame = {}
	local AllowedMovement = false
	local function notify(msg)
		if not SETTINGS.NOTIFY then
			return
		end
		game:GetService("StarterGui"):SetCore("SendNotification", {
			Title = "Shield Active",
			Text = msg,
			Duration = 3,
		})
	end
	local Meta = getrawmetatable(game)
	local OldNamecall = Meta.__namecall
	setreadonly(Meta, false)
	Meta.__namecall = newcclosure(function(self, ...)
		local method = getnamecallmethod()
		local args = { ... }
		if SETTINGS.KICK_IMMUNITY and self == LocalPlayer and (method == "Kick" or method == "kick") then
			notify("Blocked Kick: " .. (args[1] or "No reason"))
			return nil
		end
		if SETTINGS.BLOCK_SERVER_TP and self == TeleportService and string.find(method:lower(), "teleport") then
			notify("Blocked Server-Hop attempt.")
			return nil
		end
		return OldNamecall(self, unpack(args))
	end)
	local tpMethods = { "Teleport", "TeleportToPlaceInstance", "TeleportAsync", "TeleportToPrivateServer" }
	for _, m in ipairs(tpMethods) do
		if TeleportService[m] then
			hookfunction(
				TeleportService[m],
				newcclosure(function(self, ...)
					if SETTINGS.BLOCK_SERVER_TP and self == TeleportService then
						notify("Blocked Direct Teleport Call.")
						return nil
					end
					return TeleportService[m](self, ...)
				end)
			)
		end
	end
	setreadonly(Meta, true)
	local function monitorPart(part)
		if not part:IsA("BasePart") then
			return
		end
		LastValidCFrame[part] = part.CFrame
		part:GetPropertyChangedSignal("CFrame"):Connect(function()
			if not SETTINGS.ANTI_CFRAME_TP or AllowedMovement then
				return
			end
			local last = LastValidCFrame[part]
			if last and (part.Position - last.Position).Magnitude > 5 then
				AllowedMovement = true
				part.CFrame = last
				task.wait()
				AllowedMovement = false
				if SETTINGS.DEBUG then
					print("[Shield] Snap-back triggered for " .. part.Name)
				end
			end
		end)
	end
	local function setupCharacter(char)
		LastValidCFrame = {}
		for _, part in ipairs(char:GetDescendants()) do
			monitorPart(part)
		end
		char.DescendantAdded:Connect(monitorPart)
		task.spawn(function()
			while char and char.Parent do
				if not AllowedMovement then
					for _, part in ipairs(char:GetChildren()) do
						if part:IsA("BasePart") then
							LastValidCFrame[part] = part.CFrame
						end
					end
				end
				task.wait(0.2)
			end
		end)
	end
	RunService.Heartbeat:Connect(function()
		local char = LocalPlayer.Character
		if not char then
			return
		end
		local hrp = char:FindFirstChild("HumanoidRootPart")
		if not hrp then
			return
		end
		if SETTINGS.ANTI_FLING and hrp.AssemblyLinearVelocity.Magnitude > 150 then
			hrp.AssemblyLinearVelocity = Vector3.new(0, 0, 0)
			hrp.AssemblyAngularVelocity = Vector3.new(0, 0, 0)
		end
		if SETTINGS.ANTI_ANCHOR then
			for _, part in ipairs(char:GetChildren()) do
				if part:IsA("BasePart") and part.Anchored then
					part.Anchored = false
				end
			end
		end
	end)
	workspace.DescendantAdded:Connect(function(obj)
		if obj:IsA("Explosion") then
			local char = LocalPlayer.Character
			if char and char:FindFirstChild("HumanoidRootPart") then
				if (obj.Position - char.HumanoidRootPart.Position).Magnitude < 15 then
					obj.BlastPressure = 0
					obj.BlastRadius = 0
				end
			end
		end
	end)
	LocalPlayer.CharacterAdded:Connect(setupCharacter)
	if LocalPlayer.Character then
		setupCharacter(LocalPlayer.Character)
	end
end)
RegisterCommand({
    Name        = "mathsolver",
    Aliases     = {"math", "automath"},
    Description = "for +1 sp a second",
}, function(args)

    local ReplicatedStorage = game:GetService("ReplicatedStorage")
    local TextChatService = game:GetService("TextChatService")
    local MathQuizQuestion = ReplicatedStorage:WaitForChild("MathQuizQuestion")
    local MathQuizWinner = ReplicatedStorage:WaitForChild("MathQuizWinner")


    local ANSWER_DELAY = 1.7
    local quizActive = false


    local function solveEquation(question)
    	local q = question
    	q = q:gsub("\195\151", "*")
    	q = q:gsub("\195\183", "/")
    	q = q:gsub("[xX]", "*")
    	q = q:gsub("[%(%)%[%]]", "")
    	q = q:gsub("%s+", " "):match("^%s*(.-)%s*$")
    	local tokens = {}
    	for tok in q:gmatch("[%+%-%*/]?%s*%-?%d+%.?%d*") do
    		local op, num = tok:match("^([%+%-%*/])%s*(%-?%d+%.?%d*)$")
    		if op and num then
    			table.insert(tokens, op)
    			table.insert(tokens, tonumber(num))
    		else
    			local n = tonumber(tok:match("%-?%d+%.?%d*"))
    			if n then
    				table.insert(tokens, n)
    			end
    		end
    	end
    	if #tokens == 0 then return nil end
    	if type(tokens[1]) ~= "number" then return nil end
    	local i = 2
    	while i <= #tokens do
    		local op = tokens[i]
    		if op == "*" or op == "/" then
    			local lhs = tokens[i - 1]
    			local rhs = tokens[i + 1]
    			if type(lhs) ~= "number" or type(rhs) ~= "number" then break end
    			if op == "/" and rhs == 0 then return nil end
    			local val = op == "*" and lhs * rhs or lhs / rhs
    			table.remove(tokens, i + 1)
    			table.remove(tokens, i)
    			tokens[i - 1] = val
    		else
    			i = i + 2
    		end
    	end
    	local result = tokens[1]
    	i = 2
    	while i <= #tokens do
    		local op = tokens[i]
    		local rhs = tokens[i + 1]
    		if type(op) ~= "string" or type(rhs) ~= "number" then break end
    		if op == "+" then
    			result = result + rhs
    		elseif op == "-" then
    			result = result - rhs
    		end
    		i = i + 2
    	end
    	local rounded = math.round(result)
    	return (math.abs(result - rounded) < 0.0001) and rounded or result
    end
    MathQuizQuestion.OnClientEvent:Connect(function(question, isInsane)
    	if not question or question == "" then
    		return
    	end
    	quizActive = true
    	local answer = solveEquation(question)
    	if not answer then
    		return
    	end
    	task.delay(ANSWER_DELAY, function()
    		if not quizActive then
    			return
    		end
    		TextChatService.TextChannels.RBXGeneral:SendAsync(tostring(answer))
    	end)
    end)
    MathQuizWinner.OnClientEvent:Connect(function()
    	quizActive = false
    end)
    print(" made by zuka math is hard on god ")
end)
