print("Weighted Score:", envInfo.level)
print("Rating       :", envInfo.rating)
print(
	"Functions Found:",
	(function()
		local count = 0
		for _ in pairs(envInfo.functions) do
			count = count + 1
		end
		return count
	end)()
)


